-- Schema for Domain: livestock | Business: Agriculture | Version: v1_mvm
-- Generated on: 2026-05-01 18:45:52

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `agriculture_ecm`.`livestock` COMMENT 'Manages all animal husbandry and breeding operations including herd and flock records, animal identification (RFID/ear tag), breeding programs, health and veterinary treatment logs, feed ration and nutrition planning, vaccination schedules, growth performance, and animal welfare compliance. Serves as the SSOT for animal lifecycle data from birth through harvest, supporting APHIS regulatory requirements, FSIS compliance, and antibiotic/withdrawal period tracking.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `agriculture_ecm`.`livestock`.`animal` (
    `animal_id` BIGINT COMMENT 'Unique system-generated surrogate identifier for each individual animal record. Serves as the primary key and universal reference across all livestock management systems.',
    `breed_id` BIGINT COMMENT 'Reference identifier linking to the breed master record for this animals registered or recognized breed (e.g., Angus, Hereford, Duroc, Merino). Supports genetic performance benchmarking, EPD (Expected Progeny Difference) analysis, and breed association reporting.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Individual animal acquisition costs and capitalized breeding animal depreciation require cost center assignment for livestock enterprise budgeting and USDA farm financial reporting. A livestock accoun',
    `facility_id` BIGINT COMMENT 'USDA-assigned Premises Identification Number (PIN) for the physical location where the animal currently resides. 10-character alphanumeric code (3-letter state abbreviation + 7 digits). Required for USDA NAIS/ADT interstate movement documentation and disease traceability.',
    `herd_id` BIGINT COMMENT 'Reference identifier for the herd or flock to which this animal is currently assigned. Drives management group decisions, vaccination scheduling, and regulatory reporting at the herd level. Sourced from Granular Farm Management herd master.',
    `inspection_id` BIGINT COMMENT 'Foreign key linking to quality.inspection. Business justification: Individual animals undergo USDA ante-mortem, state veterinary, and welfare inspections tracked per animal for regulatory compliance (FSIS, APHIS). A domain expert expects each animal record to referen',
    `organic_certification_id` BIGINT COMMENT 'Foreign key linking to product.organic_certification. Business justification: animal.organic_certified is a boolean denormalization of an organic certification record. USDA NOP requires traceability from individual animals to the specific organic certification under which they ',
    `pen_location_id` BIGINT COMMENT 'Reference identifier for the current physical pen, pasture, or paddock where the animal is housed or grazing. Supports daily management, feeding operations, and biosecurity zone tracking. Linked to the facility location master.',
    `primary_dam_animal_id` BIGINT COMMENT 'Self-referencing identifier pointing to the mother (dam) animal record within this same table. Enables maternal lineage tracing for genetic performance analysis, EPD calculations, and pedigree documentation. Null for purchased animals with unknown dam.',
    `purchase_order_id` BIGINT COMMENT 'Foreign key linking to procurement.purchase_order. Business justification: Each purchased animal must reference the procurement PO for cost basis establishment, financial reconciliation, and COOL (Country of Origin Labeling) documentation. animal.source_vendor_id already lin',
    `vendor_id` BIGINT COMMENT 'Reference identifier for the external vendor, auction house, or producer from whom the animal was purchased. Null for born-on-farm animals. Supports supplier traceability, biosecurity source tracking, and procurement analytics in SAP S/4HANA MM module.',
    `acquisition_cost` DECIMAL(18,2) COMMENT 'Purchase price or capitalized cost basis of the animal at time of acquisition, expressed in USD. For born-on-farm animals, represents the capitalized cost of raising to weaning. Used for inventory valuation, COGS (Cost of Goods Sold) calculation, and financial reporting under GAAP/IFRS.',
    `acquisition_date` DATE COMMENT 'Date the animal was acquired by the operation — either the birth date for born-on-farm animals or the purchase/transfer-in date for externally sourced animals. Used for inventory aging, cost basis calculation, and COOL documentation.',
    `antibiotic_free` BOOLEAN COMMENT 'Indicates whether the animal has never received antibiotic treatments and qualifies for Never Ever 3 (NE3) or antibiotic-free marketing programs. Drives premium market channel eligibility and label claim compliance.',
    `birth_date` DATE COMMENT 'Actual or estimated calendar date the animal was born. Used to calculate age, determine production class eligibility, schedule vaccinations, and compute days-on-feed (DOF). Required for USDA age verification programs and COOL documentation.',
    `birth_weight_kg` DECIMAL(18,2) COMMENT 'Body weight of the animal recorded at or shortly after birth, expressed in kilograms. Baseline measurement for growth performance tracking, EPD (Expected Progeny Difference) calculations, and dam/sire genetic evaluation.',
    `brand_description` STRING COMMENT 'Description of the hot iron or freeze brand applied to the animal for permanent ownership identification. Includes brand symbol, location on body, and registration state. Required for cattle ownership verification in brand-law states and theft prevention.',
    `breed_composition_pct` DECIMAL(18,2) COMMENT 'Percentage of the animals genetics attributable to the primary breed identified in breed_id. Expressed as a decimal percentage (e.g., 75.00 for 75% Angus). Used for crossbreeding program management, breed association registration eligibility, and genetic improvement analytics.',
    `country_of_origin` STRING COMMENT 'ISO 3166-1 alpha-3 country code representing the country where the animal was born, raised, or slaughtered as required by USDA COOL (Country of Origin Labeling) regulations. Mandatory for retail muscle cut labeling compliance.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'ISO 8601 timestamp when the animal record was first created in the system. Supports data lineage, audit trail requirements, and FSMA traceability documentation. Populated automatically at record creation and never updated.',
    `current_weight_kg` DECIMAL(18,2) COMMENT 'Most recently recorded live body weight of the animal in kilograms. Updated at each weigh event. Used for feed ration calculation, marketing weight assessment, and growth performance monitoring. Distinct from birth weight and harvest weight.',
    `disposition_date` DATE COMMENT 'Date the animal was removed from active inventory through harvest, sale, death, condemnation, or transfer out. Used for inventory reconciliation, mortality reporting, and lifecycle cost analysis. Null while animal is in ACTIVE disposition status.',
    `disposition_status` STRING COMMENT 'Current disposition status representing the animals standing in the operation. ACTIVE=currently on inventory; HARVESTED=sent to harvest/slaughter; SOLD=sold to external party; DIED=natural or accidental death; CONDEMNED=condemned at ante/post-mortem inspection; TRANSFERRED_OUT=moved to another facility. Core lifecycle status field for inventory reconciliation and FSIS compliance.. Valid values are `ACTIVE|HARVESTED|SOLD|DIED|CONDEMNED|TRANSFERRED_OUT`',
    `ear_tag_number` STRING COMMENT 'Visual alphanumeric identifier printed on the physical ear tag applied to the animal. Used for visual identification in the field and pen. May be a farm-assigned number or official USDA 840 tag number. Supports COOL country-of-origin labeling traceability.',
    `eid` STRING COMMENT 'Electronic Identification number as printed on the visual ear tag and encoded in the RFID transponder. May differ from the raw RFID tag number in formatted display. Used in John Deere Operations Center and Granular Farm Management for animal-level record linkage.',
    `gmo_status` STRING COMMENT 'Indicates whether the animal is derived from genetically modified genetics (GMO), confirmed non-GMO, or status is unknown. Required for non-GMO certification programs, organic certification under USDA NOP, and export documentation to GMO-sensitive markets.. Valid values are `GMO|NON_GMO|UNKNOWN`',
    `health_status` STRING COMMENT 'Current veterinary health status of the animal. HEALTHY=no active health concerns; SICK=active illness under observation; QUARANTINE=isolated for biosecurity or regulatory reasons; TREATED=currently under veterinary treatment with active withdrawal period; RECOVERED=returned to healthy status post-treatment; CONDEMNED=condemned by veterinary inspection.. Valid values are `HEALTHY|SICK|QUARANTINE|TREATED|RECOVERED|CONDEMNED`',
    `last_weigh_date` DATE COMMENT 'Calendar date of the most recent live weight measurement. Used to assess recency of weight data, calculate average daily gain (ADG) since last weigh, and trigger re-weigh alerts when interval exceeds operational thresholds.',
    `lifecycle_stage` STRING COMMENT 'Current biological and production lifecycle stage of the animal. Drives nutritional requirements, veterinary protocols, and management interventions. [ENUM-REF-CANDIDATE: NEONATAL|WEANED|GROWING|FINISHING|MATURE|GESTATING|LACTATING|DRY — promote to reference product]',
    `official_usda_tag` STRING COMMENT 'Official USDA 840-prefix 15-digit national uniform ear tag number assigned under the USDA Animal Disease Traceability (ADT) framework. Required for interstate movement of cattle, bison, and other covered species. Begins with country code 840 (USA).. Valid values are `^840[0-9]{12}$`',
    `origin_type` STRING COMMENT 'Indicates whether the animal was born on the operation, purchased from an external source, or transferred in from another company-owned facility. Critical for COOL country-of-origin labeling, FSMA traceability, and biosecurity risk classification.. Valid values are `BORN_ON_FARM|PURCHASED|TRANSFERRED_IN`',
    `parity_number` STRING COMMENT 'Number of times a female animal has given birth (parturitions). Parity 0 = never calved/farrowed/lambed; Parity 1 = first calf/litter; etc. Used for reproductive performance analysis, culling decisions, and production benchmarking for dairy and cow-calf operations.',
    `production_class` STRING COMMENT 'Operational production class that defines the animals role in the production system. Determines applicable management protocols, feed rations, performance benchmarks, and marketing channels. [ENUM-REF-CANDIDATE: COW_CALF|STOCKER|FEEDLOT|DAIRY|BREEDING|SHOW|SEEDSTOCK|REPLACEMENT_HEIFER — promote to reference product]',
    `registration_number` STRING COMMENT 'Official registration number issued by a recognized breed association (e.g., American Angus Association, National Swine Registry) for purebred or registered animals. Required for seedstock marketing, EPD publication, and breed association reporting.',
    `rfid_tag_number` STRING COMMENT '15-digit ISO 11784/11785 compliant RFID electronic tag number embedded in the animals ear tag or bolus. Primary electronic identifier used for automated reading at chutes, scales, and gates. Required for USDA NAIS traceability and APHIS interstate movement compliance.. Valid values are `^[0-9]{15}$`',
    `sex_code` STRING COMMENT 'Biological sex and reproductive status of the animal. M=Male (intact bull/boar/ram), F=Female (cow/sow/ewe), C=Castrated male (steer/barrow/wether), S=Spayed female, B=Barrow. Drives production class assignment, feed ration, and harvest yield expectations.. Valid values are `M|F|C|S|B`',
    `species_code` STRING COMMENT 'Standardized species classification of the animal. Drives applicable regulatory frameworks (FSIS, APHIS), withdrawal period rules, and feed ration formulations. [ENUM-REF-CANDIDATE: BOVINE|SWINE|OVINE|CAPRINE|EQUINE|POULTRY|CERVID|BISON|OTHER — promote to reference product]',
    `tattoo_number` STRING COMMENT 'Permanent alphanumeric tattoo applied inside the ear or on the body for permanent identification, particularly for swine, sheep, and registered cattle. Used as a backup identifier when ear tags are lost and for breed association registration.',
    `updated_timestamp` TIMESTAMP COMMENT 'ISO 8601 timestamp of the most recent modification to the animal record. Used for change data capture (CDC), data synchronization between SAP S/4HANA and Granular Farm Management, and audit trail compliance under SOX and FSMA.',
    CONSTRAINT pk_animal PRIMARY KEY(`animal_id`)
) COMMENT 'Core master record for every individual animal in the herd or flock. Serves as the SSOT for animal identity across the full lifecycle from birth through harvest, sale, or disposal. Captures RFID tag, ear tag, electronic ID (EID), species, breed reference, sex, birth date, birth weight, dam/sire references (self-referencing lineage), origin (born on farm vs. purchased), current herd assignment, current location (pen/pasture), production class, production group assignment, GMO status, current lifecycle stage, and disposition status. Supports APHIS traceability requirements, USDA NAIS/RFID compliance, and COOL country-of-origin documentation.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`livestock`.`herd` (
    `herd_id` BIGINT COMMENT 'Unique system-generated surrogate key identifying a managed herd or flock grouping within the livestock management system. Primary key for all animal-level record associations.',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: In contract growing and custom feeding (common in swine, poultry, and fed cattle), the integrator or packer is a customer who owns or has a forward contract on the herd. Linking herd to customer.accou',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: Each herd produces a specific commodity output (beef, pork, fluid milk, broilers). Linking to product.commodity enables commodity-level cost-of-production reporting, organic premium tracking against N',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: In multi-entity livestock operations, herds belong to specific legal entities (company codes) for consolidated financial reporting, intercompany transfers, and entity-level P&L. This link is required ',
    `contract_id` BIGINT COMMENT 'Foreign key linking to sales.contract. Business justification: Herds are routinely sold under forward sales contracts specifying volume, delivery window, and price. Linking herd to contract enables contract fulfillment tracking, production planning against commit',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Herd-level cost center assignment is fundamental to livestock P&L reporting — feed, labor, and veterinary costs are accumulated per herd cost center for budget variance analysis and closeout profitabi',
    `farm_unit_id` BIGINT COMMENT 'Foreign key linking to land.farm_unit. Business justification: Livestock herds are operationally assigned to farm units for FSA compliance reporting, stocking density calculations, and cost center allocation. A livestock manager expects to know which farm unit ea',
    `field_id` BIGINT COMMENT 'Foreign key linking to land.field. Business justification: Pasture-based livestock operations assign herds to specific fields for rotational grazing management, stocking density compliance (head/ha), and NRCS conservation practice reporting. Agronomists and l',
    `employee_id` BIGINT COMMENT 'Reference to the employee or contractor designated as the responsible herd manager. Used for accountability tracking, SAP SuccessFactors workforce assignment, and regulatory contact identification for APHIS inspections.',
    `facility_id` BIGINT COMMENT 'Reference to the farm, ranch, or production facility where this herd is domiciled. Links to the land/facility master record for location-based reporting, GIS mapping via Esri ArcGIS, and USDA premises registration.',
    `herd_premises_facility_id` BIGINT COMMENT 'USDA APHIS-assigned Premises Identification Number (PIN) for the physical location where the herd resides. Required for Animal Disease Traceability (ADT) compliance and interstate movement documentation. Format: 3-letter state code + 7-digit number.',
    `herd_veterinarian_employee_id` BIGINT COMMENT 'Reference to the licensed veterinarian of record (VOR) responsible for health oversight of this herd. Required for VCPR (Veterinarian-Client-Patient Relationship) compliance, antibiotic prescription authorization, and FSIS residue avoidance programs.',
    `inspection_id` BIGINT COMMENT 'Foreign key linking to quality.inspection. Business justification: Herds undergo PAACO welfare audits, GAP biosecurity inspections, and state veterinary herd inspections as distinct events from quality audits. A domain expert expects herd to reference its current gov',
    `organic_certification_id` BIGINT COMMENT 'Foreign key linking to product.organic_certification. Business justification: USDA NOP regulations require organic livestock operations to maintain herd-level certification records tied to an NOP certificate. Linking herd to organic_certification enables certification renewal t',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Herds are the primary profit center unit in livestock enterprise accounting — each herd generates revenue (sales, milk) and incurs costs tracked against a profit center for enterprise P&L. Livestock m',
    `vendor_contract_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor_contract. Business justification: Custom feeding and livestock supply agreements are herd-level contracts in commercial agriculture. Linking herd to vendor_contract enables contract compliance tracking, spend allocation by herd, and a',
    `avg_body_weight_kg` DECIMAL(18,2) COMMENT 'Average live body weight in kilograms of animals in the herd at the most recent weigh event. Used for feed conversion ratio (FCR) calculations, drug dosage determination, and market readiness assessment. Supports YPM (Yield Per Acre Metric) and performance benchmarking.',
    `avg_daily_gain_kg` DECIMAL(18,2) COMMENT 'Average daily weight gain in kilograms per animal, calculated from the most recent performance measurement period. Key production KPI for finishing herds; benchmarked against breed standards and used in feed efficiency analysis.',
    `biosecurity_level` STRING COMMENT 'Assigned biosecurity risk classification for the herd facility, determining visitor access controls, quarantine protocols, and disease surveillance intensity. Enhanced level is triggered by proximity to foreign animal disease outbreaks or APHIS disease alerts.. Valid values are `low|medium|high|enhanced`',
    `breed` STRING COMMENT 'Primary breed or genetic line of the herd (e.g., Angus, Holstein, Duroc, Cornish Cross, Merino). Influences production performance benchmarks, feed ration planning, and genetic improvement programs tracked in breeding records.',
    `certification_expiry_date` DATE COMMENT 'Earliest expiration date across all active certifications (organic, GAP, GLOBALG.A.P.) held by this herd. Used to trigger recertification workflows and prevent lapsed-certification sales into premium market channels.',
    `classification` STRING COMMENT 'Operational classification of the herds production stage or management purpose (e.g., breeding, finishing, nursery, cow-calf, stocker, replacement). Drives feed ration formulation, housing allocation, and performance KPI benchmarks. [ENUM-REF-CANDIDATE: breeding|finishing|nursery|grow-out|cow-calf|stocker|replacement|farrowing|lactating|dry|other — promote to reference product]',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp recording when this herd master record was first created in the FMIS or ERP system. Supports data lineage, FSMA traceability audit trails, and SOX financial reporting controls for livestock asset records.',
    `current_head_count` STRING COMMENT 'Actual number of live animals currently in the herd as of the last inventory reconciliation. Drives feed ration calculations, housing capacity utilization, and USDA NASS livestock inventory reporting. Updated upon births, deaths, purchases, and transfers.',
    `disease_status` STRING COMMENT 'Current disease surveillance status of the herd as determined by USDA APHIS or state veterinarian. confirmed status triggers mandatory reporting, movement restrictions, and potential depopulation under the National Animal Health Emergency Management System (NAHEMS).. Valid values are `disease-free|under-surveillance|suspect|confirmed|cleared`',
    `dispersal_date` DATE COMMENT 'Calendar date on which the herd was fully dispersed through sale, harvest, or depopulation. Null for active herds. Used to close the herd lifecycle record and trigger final regulatory reporting to USDA APHIS.',
    `expected_market_date` DATE COMMENT 'Projected date when the herd or a cohort of animals is expected to reach market weight and be ready for sale or harvest. Used for sales order planning, slaughter scheduling, and logistics coordination with TMS and WMS systems.',
    `formation_date` DATE COMMENT 'Calendar date on which this herd grouping was formally established or first registered in the FMIS. Used for herd age tracking, performance period calculations, and audit trail compliance under FSMA traceability requirements.',
    `herd_code` STRING COMMENT 'Externally-known alphanumeric business identifier for the herd, used in operational systems such as SAP S/4HANA livestock modules, FMIS records, and regulatory submissions to USDA APHIS. Serves as the cross-system reference key.. Valid values are `^[A-Z0-9-]{3,20}$`',
    `herd_name` STRING COMMENT 'Human-readable descriptive name assigned to the herd or flock grouping (e.g., North Pasture Angus Cow-Calf Herd, Broiler House 4 Flock). Used in operational reports, Granular Farm Management, and John Deere Operations Center displays.',
    `herd_status` STRING COMMENT 'Current lifecycle status of the herd record. active indicates operational management; quarantined triggers APHIS disease containment protocols; dispersed indicates the herd has been sold or depopulated; pending indicates formation in progress.. Valid values are `active|inactive|quarantined|dispersed|pending`',
    `housing_type` STRING COMMENT 'Primary housing or production system type for the herd (e.g., pasture, confinement, feedlot, free-range). Determines applicable animal welfare standards, GAP certification requirements, and environmental compliance obligations under EPA regulations. [ENUM-REF-CANDIDATE: pasture|confinement|semi-confinement|feedlot|free-range|barn|other — 7 candidates stripped; promote to reference product]',
    `is_antibiotic_free` BOOLEAN COMMENT 'Indicates whether this herd is managed under a no-antibiotics-ever (NAE) or raised-without-antibiotics (RWA) program. Drives treatment protocol restrictions, veterinary prescription controls, and premium market channel eligibility.',
    `is_gap_certified` BOOLEAN COMMENT 'Indicates whether this herd operation holds a current Good Agricultural Practices (GAP) certification. Enables premium market access and satisfies retailer food safety audit requirements under GFSI-recognized schemes.',
    `is_globalg_ap_certified` BOOLEAN COMMENT 'Indicates whether this herd holds a current GLOBALG.A.P. Integrated Farm Assurance (IFA) certification for livestock. Required for export market access to EU and other international buyers demanding GFSI-recognized certification.',
    `is_gmo_free` BOOLEAN COMMENT 'Indicates whether this herd is managed under a non-GMO feed program, qualifying for Non-GMO Project Verified or equivalent labeling claims on derived products. Affects feed procurement specifications and supply chain segregation.',
    `is_organic_certified` BOOLEAN COMMENT 'Indicates whether this herd is certified under the USDA National Organic Program (NOP). When True, enforces organic feed sourcing, prohibits synthetic antibiotic use, and triggers organic premium pricing in sales contracts.',
    `last_health_check_date` DATE COMMENT 'Date of the most recent veterinary health inspection or herd health assessment. Used to ensure compliance with VCPR requirements, schedule next health review, and support APHIS accredited veterinarian documentation.',
    `morbidity_rate_pct` DECIMAL(18,2) COMMENT 'Rolling percentage of animals in the herd that have been treated for illness during the current production period. Tracks herd health status, antibiotic use patterns, and biosecurity effectiveness. Supports FSIS residue avoidance program reporting.',
    `mortality_rate_pct` DECIMAL(18,2) COMMENT 'Rolling mortality rate expressed as a percentage of the herd, calculated over the current production period. Key animal welfare and production efficiency KPI; triggers veterinary investigation when thresholds are exceeded. Reported to USDA NASS.',
    `movement_restriction_flag` BOOLEAN COMMENT 'Indicates whether this herd is currently subject to a USDA APHIS or state-imposed movement restriction order (e.g., due to disease quarantine, regulatory hold, or embargo). When True, blocks interstate movement documentation and sale order processing.',
    `pasture_area_ha` DECIMAL(18,2) COMMENT 'Total pasture or grazing area allocated to this herd in hectares. Used for stocking density calculations, EPA CAFO nutrient management planning, and USDA NRCS conservation program compliance. Integrated with Esri ArcGIS land parcel data.',
    `production_type` STRING COMMENT 'Primary agricultural production purpose of the herd (e.g., beef, dairy, swine, poultry, sheep). Determines applicable FSIS inspection requirements, HACCP plans, and market channel routing. [ENUM-REF-CANDIDATE: beef|dairy|swine|broiler|layer|turkey|sheep|goat|mixed|other — promote to reference product]',
    `species` STRING COMMENT 'Biological species classification of the animals in the herd (e.g., bovine for cattle, swine for pigs, poultry for chickens/turkeys). Drives regulatory reporting pathways under USDA APHIS and FSIS, and determines applicable withdrawal period and MRL rules. [ENUM-REF-CANDIDATE: bovine|swine|poultry|ovine|caprine|equine|aquaculture|other — promote to reference product]',
    `stocking_density_head_per_ha` DECIMAL(18,2) COMMENT 'Current stocking density expressed as number of animal head per hectare of allocated pasture or housing area. Monitored against regulatory thresholds for EPA CAFO permits, organic certification land requirements, and animal welfare standards.',
    `target_head_count` STRING COMMENT 'Planned or budgeted number of animal head for this herd grouping, used for capacity planning, feed procurement forecasting, and financial budgeting in Granular Farm Management. Compared against current_head_count for variance analysis.',
    `updated_timestamp` TIMESTAMP COMMENT 'System timestamp of the most recent modification to this herd master record. Used for change data capture (CDC) in the Databricks Silver Layer pipeline, audit trail compliance, and detecting stale records requiring review.',
    `welfare_audit_date` DATE COMMENT 'Date of the most recent animal welfare audit for this herd. Used to determine audit currency, schedule next audit, and satisfy retailer supply chain assurance requirements.',
    `welfare_audit_score` DECIMAL(18,2) COMMENT 'Numeric score from the most recent animal welfare audit conducted against an approved standard (e.g., Animal Welfare Approved, Certified Humane, GLOBALG.A.P.). Expressed as a percentage (0.00–100.00). Required by major retail customers and GFSI-aligned buyers.',
    CONSTRAINT pk_herd PRIMARY KEY(`herd_id`)
) COMMENT 'Master record defining a managed herd or flock grouping — the primary operational unit for livestock management. Captures herd name, species, production type (beef, dairy, swine, poultry, sheep, etc.), home location (farm/facility), responsible manager, target head count, current head count, herd classification (breeding, finishing, nursery, etc.), and certification status (organic, GAP, GLOBALG.A.P.). Acts as the organizational anchor for all animal-level records.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`livestock`.`pen_location` (
    `pen_location_id` BIGINT COMMENT 'Unique system-generated identifier for each pen, paddock, pasture, barn, feedlot, farrowing room, milking parlor, or processing facility unit within the livestock operation. Serves as the primary key and SSOT reference for all animal movement, feed delivery, welfare audit, and biosecurity zone records.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Pen locations are physical infrastructure units with depreciation, maintenance, and utility costs allocated to cost centers. Facility cost allocation by pen is standard in feedlot and confinement live',
    `facility_id` BIGINT COMMENT 'Reference to the parent facility or premises in the land domain that physically contains this pen or housing unit. Enables cross-domain linkage between livestock-operational pen records and land-parcel or premises-level records managed in the land domain.',
    `farm_unit_id` BIGINT COMMENT 'Foreign key linking to land.farm_unit. Business justification: Farm unit capacity planning, pen inventory reporting, and biosecurity zone management require direct pen-to-farm-unit association. Farm managers need all pens under their farm unit without joining thr',
    `field_id` BIGINT COMMENT 'Foreign key linking to land.field. Business justification: Outdoor pens and pasture pen locations are physically situated within fields. This link supports manure nutrient management planning (EPA/state regulations require knowing which field receives manure ',
    `inspection_id` BIGINT COMMENT 'Foreign key linking to quality.inspection. Business justification: Pen locations undergo biosecurity, sanitation, and welfare inspections (PAACO, state vet, GAP field sanitation modules). A domain expert expects pen_location to reference its most recent governing ins',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Each pen in a feedlot or dairy is assigned a responsible pen rider or pen manager for daily welfare monitoring, morbidity detection, and regulatory compliance. This accountability link is required for',
    `aisle_row_number` STRING COMMENT 'Aisle or row designation within a building where this pen is located (e.g., Aisle 3, Row B). Supports precise pen location navigation for feed delivery crews, veterinary staff, and welfare auditors within large confinement facilities.',
    `area_acres` DECIMAL(18,2) COMMENT 'Physical area of the pen, paddock, or pasture measured in acres. Used to calculate stocking density (head per acre), grazing rotation schedules, and welfare compliance metrics. Sourced from Esri ArcGIS geospatial measurements or Granular Farm Management land records.',
    `area_sqft` DECIMAL(18,2) COMMENT 'Physical area of the pen or indoor housing unit measured in square feet. Used for indoor confinement facilities (barns, farrowing rooms, milking parlors) where square footage per animal head is the applicable welfare compliance metric.',
    `biosecurity_zone` STRING COMMENT 'Biosecurity zone designation assigned to the pen per the operations biosecurity plan. Governs personnel access controls, equipment movement restrictions, and disease containment protocols. Critical for APHIS foreign animal disease response planning and GLOBALG.A.P. biosecurity compliance.. Valid values are `clean|dirty|buffer|restricted|quarantine`',
    `building_number` STRING COMMENT 'Identifier for the building or structure within the parent facility that contains this pen. Used for facility layout navigation, maintenance work order routing in SAP S/4HANA PM module, and emergency response planning.',
    `capacity_head` STRING COMMENT 'Maximum number of animal head this pen or housing unit is designed to hold at one time, based on species-specific stocking density standards and welfare regulations. Used for occupancy management, welfare compliance audits, and feed ration planning.',
    `commissioned_date` DATE COMMENT 'Date the pen or housing unit was first placed into operational service. Used for asset lifecycle tracking, maintenance scheduling, depreciation calculations (CAPEX), and historical occupancy trend analysis.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this pen location record was first created in the system. Supports data lineage, audit trail requirements, and Silver Layer lakehouse record management. Populated automatically at record insertion.',
    `current_occupancy` STRING COMMENT 'Current number of animal head present in the pen at the time of last update. Enables real-time occupancy monitoring, stocking density compliance checks, and feed delivery quantity calculations. Updated upon each animal movement event.',
    `decommissioned_date` DATE COMMENT 'Date the pen or housing unit was permanently taken out of service. Nullable for active pens. Supports asset lifecycle management, historical capacity reporting, and regulatory premises deregistration with USDA APHIS.',
    `feed_delivery_method` STRING COMMENT 'Method by which feed rations are delivered to animals within this pen. Drives feed delivery scheduling, TMR (Total Mixed Ration) batch targeting, and feed management system integration with Granular Farm Management and SAP S/4HANA PP module.. Valid values are `bunk|trough|automated_feeder|pasture_grazing|total_mixed_ration|hand_fed`',
    `flooring_type` STRING COMMENT 'Type of flooring surface within the pen or housing unit. Impacts animal welfare assessments (lameness, injury risk), manure management practices, and compliance with GLOBALG.A.P. and GFSI welfare audit criteria. [ENUM-REF-CANDIDATE: concrete|slatted|dirt|rubber_mat|bedded_pack|pasture|grated — promote to reference product]',
    `gis_polygon_reference` STRING COMMENT 'Reference identifier for the pen boundary polygon stored in the Esri ArcGIS geospatial system or John Deere Operations Center field mapping layer. Enables spatial analysis, boundary-based animal tracking, and integration with precision agriculture platforms.',
    `housing_type` STRING COMMENT 'Classification of the physical housing or containment structure type. Drives welfare audit requirements, ventilation standards, biosecurity protocols, and regulatory reporting under USDA APHIS and GFSI frameworks. [ENUM-REF-CANDIDATE: pen|paddock|pasture|barn|feedlot|farrowing_room|milking_parlor|processing_facility — promote to reference product]',
    `is_biosecurity_restricted` BOOLEAN COMMENT 'Indicates whether this pen requires restricted personnel access under the operations biosecurity plan. When true, access logs, PPE requirements, and visitor protocols are enforced per APHIS biosecurity guidelines and GLOBALG.A.P. standards.',
    `is_climate_controlled` BOOLEAN COMMENT 'Indicates whether the pen or housing unit has active climate control systems (heating, cooling, or humidity regulation). Relevant to welfare compliance for sensitive species/life stages (farrowing, nursery), energy cost tracking, and IoT sensor deployment planning.',
    `is_covered` BOOLEAN COMMENT 'Indicates whether the pen or housing unit has a roof or overhead shelter structure. Affects weather protection assessments, welfare audit scoring, and heat/cold stress risk classification for animal health management.',
    `last_cleaned_date` DATE COMMENT 'Date the pen was most recently cleaned and sanitized. Supports biosecurity compliance tracking, disease prevention scheduling, and welfare audit documentation. Required for GLOBALG.A.P. and GFSI audit trails.',
    `last_disinfected_date` DATE COMMENT 'Date the pen was most recently disinfected with an approved disinfectant product. Distinct from cleaning — disinfection is a separate biosecurity step required between animal groups and after disease events. Tracked for APHIS and FSIS compliance.',
    `last_inspection_date` DATE COMMENT 'Date of the most recent animal welfare or facility inspection conducted at this pen location. Supports audit scheduling, compliance gap identification, and regulatory reporting to USDA APHIS and GFSI certification bodies.',
    `latitude` DECIMAL(18,2) COMMENT 'GPS latitude coordinate of the pen centroid or primary access point in decimal degrees (WGS84 datum). Enables spatial tracking of animal locations, feed delivery routing, and GIS-based biosecurity zone mapping in Esri ArcGIS and John Deere Operations Center.',
    `lighting_type` STRING COMMENT 'Type of lighting available within the pen or housing unit. Relevant to animal welfare assessments, photoperiod management for reproductive performance, and energy efficiency reporting under CAPEX/OPEX tracking.. Valid values are `natural|artificial|mixed|none`',
    `longitude` DECIMAL(18,2) COMMENT 'GPS longitude coordinate of the pen centroid or primary access point in decimal degrees (WGS84 datum). Enables spatial tracking of animal locations, feed delivery routing, and GIS-based biosecurity zone mapping in Esri ArcGIS and John Deere Operations Center.',
    `manure_management_type` STRING COMMENT 'Method used to collect, store, or manage manure generated within this pen. Required for EPA nutrient management plan compliance, USDA NRCS BMP (Best Management Practices) reporting, and environmental permit documentation.. Valid values are `lagoon|pit|composting|solid_stack|pasture|biodigester`',
    `notes` STRING COMMENT 'Free-text field for operational notes, special instructions, or contextual information about this pen location that does not fit structured fields. Examples include temporary capacity restrictions, ongoing construction notes, or special biosecurity instructions for staff.',
    `operational_status` STRING COMMENT 'Current lifecycle state of the pen or housing unit. Controls whether the pen is available for animal placement, feed delivery scheduling, or welfare inspections. quarantined status triggers biosecurity protocols per APHIS and FSIS requirements.. Valid values are `active|inactive|under_maintenance|quarantined|decommissioned|standby`',
    `pen_code` STRING COMMENT 'Externally-known alphanumeric code or label assigned to the pen or housing unit, used in operational signage, feed delivery manifests, animal movement records, and FMIS integrations (e.g., Granular Farm Management, SAP S/4HANA PP module). Must be unique within the parent facility.. Valid values are `^[A-Z0-9-]{2,20}$`',
    `pen_name` STRING COMMENT 'Human-readable descriptive name for the pen or housing unit (e.g., North Farrowing Room 3, Pasture B-12, Feedlot Pen 7A). Used in operational reports, welfare audit documentation, and staff communications.',
    `production_stage` STRING COMMENT 'Livestock production stage for which this pen is designated. Determines applicable feed ration programs, health protocols, withdrawal period tracking, and welfare audit criteria. Aligns with SAP S/4HANA PP production order classification and Granular Farm Management livestock records. [ENUM-REF-CANDIDATE: nursery|grower|finisher|breeding|gestation|farrowing|lactation|dry_lot|backgrounding — promote to reference product]',
    `species_type` STRING COMMENT 'Primary livestock species for which this pen or housing unit is designed and designated. Determines applicable welfare standards, ventilation requirements, stocking density limits, and regulatory reporting frameworks (APHIS, FSIS, USDA). [ENUM-REF-CANDIDATE: cattle|swine|poultry|sheep|goat|equine|mixed — 7 candidates stripped; promote to reference product]',
    `stocking_density_limit` DECIMAL(18,2) COMMENT 'Maximum allowable stocking density for this pen expressed as head per acre (outdoor) or square feet per head (indoor), per applicable welfare and regulatory standards. Used to enforce compliance thresholds and trigger alerts when current occupancy approaches or exceeds limits.',
    `stocking_density_uom` STRING COMMENT 'Unit of measure for the stocking density limit field. Distinguishes between outdoor (head per acre) and indoor (square feet per head) density metrics to ensure correct welfare compliance calculations.. Valid values are `head_per_acre|sqft_per_head|head_per_sqft`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this pen location record was most recently modified. Supports change tracking, data quality monitoring, and incremental data pipeline processing in the Databricks Lakehouse Silver Layer.',
    `ventilation_type` STRING COMMENT 'Type of ventilation system installed in or applicable to the pen or housing unit. Affects air quality management, heat stress mitigation, disease transmission risk, and welfare compliance under USDA APHIS and GLOBALG.A.P. standards.. Valid values are `natural|mechanical|tunnel|hybrid|open_air|none`',
    `water_source_type` STRING COMMENT 'Type of water delivery system or source available within the pen. Critical for animal welfare compliance, daily water consumption monitoring, and drought contingency planning. Supports GLOBALG.A.P. and USDA APHIS welfare audit requirements.. Valid values are `automatic_waterer|trough|nipple_drinker|pond|well|municipal`',
    `welfare_certification_status` STRING COMMENT 'Current animal welfare certification status for this pen location under applicable certification programs (e.g., GLOBALG.A.P., Certified Humane, Animal Welfare Approved). Drives audit scheduling, corrective action tracking, and customer-facing welfare claims.. Valid values are `certified|pending|non_compliant|not_applicable`',
    CONSTRAINT pk_pen_location PRIMARY KEY(`pen_location_id`)
) COMMENT 'Master record for physical housing and containment units within the livestock operation — pens, paddocks, pastures, barns, feedlots, farrowing rooms, milking parlors, and processing facilities. Captures location name, facility reference (FK to land domain for parent facility/premises), GPS coordinates, area (acres/sq ft), capacity (head count), housing type, ventilation type, flooring type, biosecurity zone designation, current occupancy, and operational status. Enables spatial tracking of animal movements, feed delivery targeting, welfare audit location references, and biosecurity zone management. Owned by the livestock domain because pen-level granularity is livestock-operational — pen attributes (capacity, biosecurity zone, housing type, ventilation) are livestock-specific and not managed at the land-parcel level. Cross-references the land domain for parent premises/facility identification.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`livestock`.`breeding_event` (
    `breeding_event_id` BIGINT COMMENT 'Unique system-generated identifier for each breeding event or semen/embryo inventory record. Serves as the primary key for the breeding_event data product.',
    `asset_id` BIGINT COMMENT 'Identifier of the liquid nitrogen (LN2) cryogenic storage tank in which the semen straws or embryos are stored. Used for physical inventory location management and tank maintenance scheduling.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: AI and embryo transfer breeding programs are budgeted cost line items in livestock enterprise accounting. Cost center assignment on breeding_event enables reproductive program ROI analysis and budget ',
    `crew_id` BIGINT COMMENT 'Foreign key linking to workforce.crew. Business justification: AI synchronization and mass breeding programs use dedicated breeding crews. Crew-level tracking enables piece-rate payroll for AI technicians, labor cost allocation per breeding event, and H2A complia',
    `employee_id` BIGINT COMMENT 'Reference to the employee or contractor who performed the breeding procedure (AI technician, embryo transfer specialist, or natural service supervisor). Supports labor accountability and technician performance KPIs.',
    `facility_id` BIGINT COMMENT 'Foreign key linking to supply.facility. Business justification: Breeding events occur at specific facilities (AI labs, breeding barns). Facility-level biosecurity zone compliance, USDA premises registration, and breeding program audits all require knowing which fa',
    `herd_id` BIGINT COMMENT 'Reference to the herd or flock to which the female animal belongs at the time of the breeding event. Supports herd-level reproductive performance reporting and APHIS premises identification.',
    `lab_sample_id` BIGINT COMMENT 'Foreign key linking to quality.lab_sample. Business justification: Semen quality analysis, embryo viability testing, and post-thaw motility verification require lab samples. Breeding programs track lab results to validate genetic material quality before use. A domain',
    `lot_trace_id` BIGINT COMMENT 'Foreign key linking to supply.lot_trace. Business justification: Semen and embryo lots require FSMA-compliant lot traceability for genetic material recalls and regulatory audits. breeding_event.lot_number is a denormalized lot reference; a proper FK to lot_trace en',
    `material_master_id` BIGINT COMMENT 'Foreign key linking to inventory.material_master. Business justification: Semen and embryo inventory management is a core livestock genetics operation. Linking breeding_event to material_master enables lot traceability, storage temperature compliance, expiry tracking, and i',
    `animal_id` BIGINT COMMENT 'Reference to the dam (female animal) involved in the breeding activity. Links to the animal master record for the cow, heifer, sow, ewe, or other female subject of the breeding event.',
    `purchase_order_id` BIGINT COMMENT 'Foreign key linking to procurement.purchase_order. Business justification: Semen and embryo lots are procured via purchase orders. Linking breeding_event to purchase_order enables traceability from genetic material PO through breeding outcomes, supports lot-level cost alloca',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor. Business justification: breeding_event.semen_supplier is a plain-text denormalized vendor name. Normalizing to semen_vendor_id → procurement.vendor supports vendor scorecarding, APHIS permit verification for imported genetic',
    `vendor_contract_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor_contract. Business justification: Semen and embryo suppliers operate under vendor supply contracts in commercial livestock breeding. Linking breeding_event to vendor_contract enables contract spend tracking, volume commitment monitori',
    `actual_parturition_date` DATE COMMENT 'Actual recorded date on which the dam gave birth (calved, farrowed, lambed, etc.). Used to calculate gestation length, compare against expected date, and update reproductive performance records. Formatted as yyyy-MM-dd.',
    `breeding_date` DATE COMMENT 'Calendar date on which the breeding activity (natural service, artificial insemination, or embryo transfer) was performed. Principal real-world event date for the breeding transaction. Formatted as yyyy-MM-dd.',
    `breeding_method` STRING COMMENT 'Method used to achieve conception. natural_service indicates direct mating; artificial_insemination (AI) uses processed semen; embryo_transfer (ET) implants a flushed embryo; in_vitro_fertilization (IVF) uses laboratory-produced embryos.. Valid values are `natural_service|artificial_insemination|embryo_transfer|in_vitro_fertilization`',
    `breeding_notes` STRING COMMENT 'Free-text field for recording additional observations, complications, or contextual information about the breeding event or inventory record (e.g., synchronization protocol used, heat detection method, embryo quality grade, technician observations).',
    `collection_date` DATE COMMENT 'Date on which the semen or embryo was collected from the donor animal. Used for lot age tracking, quality assessment, and regulatory compliance with USDA semen import/export requirements. Formatted as yyyy-MM-dd.',
    `conception_check_date` DATE COMMENT 'Date on which pregnancy diagnosis (rectal palpation, ultrasound, or blood test) was performed to confirm or deny conception following the breeding event. Formatted as yyyy-MM-dd.',
    `conception_rate_history_pct` DECIMAL(18,2) COMMENT 'Recorded historical conception rate (as a percentage) for this sire or semen lot based on prior breeding events. Derived from field performance data and used in sire selection and AI program planning. Distinct from the result of any single breeding event.',
    `conception_result` STRING COMMENT 'Outcome of the pregnancy diagnosis check. confirmed_pregnant indicates successful conception; open indicates the animal did not conceive; recheck_required indicates inconclusive result requiring follow-up; not_checked indicates no pregnancy check has been performed.. Valid values are `confirmed_pregnant|open|recheck_required|not_checked`',
    `cost_per_unit` DECIMAL(18,2) COMMENT 'Purchase cost per semen straw or embryo unit in USD. Used for breeding cost accounting, COGS (Cost of Goods Sold) allocation to offspring, and ROI analysis of genetic improvement programs.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this breeding event or inventory record was first created in the system. Formatted as yyyy-MM-ddTHH:mm:ss.SSSXXX. Supports audit trail and data lineage requirements.',
    `epd_birth_weight` DECIMAL(18,2) COMMENT 'Expected Progeny Difference (EPD) value for birth weight for the sire, expressed in pounds. Positive values indicate heavier-than-average offspring. Used in sire selection to manage calving difficulty and neonatal survival.',
    `epd_calving_ease` DECIMAL(18,2) COMMENT 'Expected Progeny Difference (EPD) value for calving ease for the sire. Expressed as a percentage advantage in unassisted births compared to breed average. Used in sire selection to minimize dystocia risk.',
    `epd_marbling` DECIMAL(18,2) COMMENT 'Expected Progeny Difference (EPD) value for marbling (intramuscular fat) for the sire. Expressed as a USDA marbling score unit advantage. Used in beef quality grade prediction and premium market targeting.',
    `epd_milk` DECIMAL(18,2) COMMENT 'Expected Progeny Difference (EPD) value for milk production for the sire, expressed in pounds. Reflects the milking ability transmitted through daughters. Used in maternal breed selection for calf nutrition and growth.',
    `epd_rea` DECIMAL(18,2) COMMENT 'Expected Progeny Difference (EPD) value for Ribeye Area (REA) for the sire, expressed in square inches. Indicates genetic merit for muscle expression and cutability. Used in carcass merit prediction and sire selection for yield grade improvement.',
    `epd_weaning_weight` DECIMAL(18,2) COMMENT 'Expected Progeny Difference (EPD) value for weaning weight for the sire, expressed in pounds. Indicates the sires genetic merit for pre-weaning growth. Key metric in beef and sheep genetic improvement programs.',
    `epd_yearling_weight` DECIMAL(18,2) COMMENT 'Expected Progeny Difference (EPD) value for yearling weight for the sire, expressed in pounds. Indicates the sires genetic merit for post-weaning growth rate. Used in feedlot performance prediction and sire selection.',
    `event_status` STRING COMMENT 'Current lifecycle status of the breeding event or inventory record. planned indicates a scheduled breeding activity; completed indicates the event occurred; cancelled indicates the event was voided; pending_confirmation indicates awaiting conception check result.. Valid values are `planned|completed|cancelled|pending_confirmation`',
    `expected_parturition_date` DATE COMMENT 'Calculated expected date of birth (calving, farrowing, lambing, etc.) based on breeding date and species-specific gestation length. Used for calving/farrowing schedule planning, nutritional management, and labor allocation. Formatted as yyyy-MM-dd.',
    `genetic_registration_number` STRING COMMENT 'Official breed association registration number for the sire. Serves as the externally-known unique identifier for the sire in breed registry databases, enabling EPD lookup and genetic verification.',
    `genomic_enhanced_epd` BOOLEAN COMMENT 'Indicates whether the EPD values for this sire are genomic-enhanced (GE-EPD), meaning they incorporate DNA marker information in addition to traditional pedigree and performance data. Genomic-enhanced EPDs have higher accuracy, especially for young sires.',
    `offspring_count` STRING COMMENT 'Number of live offspring born from this breeding event (e.g., 1 for singleton calf, 2 for twins). Recorded at parturition. Used for litter size tracking, multiple birth analysis, and reproductive performance KPIs.',
    `post_thaw_motility_pct` DECIMAL(18,2) COMMENT 'Quality grade expressed as the percentage of progressively motile sperm cells observed after thawing a representative straw from the lot. Minimum acceptable threshold is typically 30-35% per USDA AMS standards. Used to assess semen quality and predict conception rates.',
    `quantity_on_hand` STRING COMMENT 'Current count of semen straws or embryos available in inventory for this lot. Decremented upon each use in an AI or ET breeding event. Used for inventory planning and reorder decisions.',
    `record_type` STRING COMMENT 'Discriminator field that separates the two concerns managed by this data product: breeding_activity for actual mating/insemination events, and semen_inventory for semen or embryo inventory management records.. Valid values are `breeding_activity|semen_inventory`',
    `sire_breed` STRING COMMENT 'Breed designation of the sire (e.g., Angus, Hereford, Holstein, Simmental). Used for crossbreeding program management, breed composition tracking, and genetic diversity analysis.',
    `sire_name` STRING COMMENT 'Registered name of the sire used in the breeding event or associated with the semen/embryo inventory record. Used for genetic reporting, catalog references, and breeder communications.',
    `storage_location` STRING COMMENT 'Precise physical location within the storage tank, expressed as canister, goblet, and cane identifiers (e.g., C2-G3-CN4). Enables rapid physical retrieval of specific semen straws or embryos during AI procedures.',
    `synchronization_protocol` STRING COMMENT 'Hormonal synchronization protocol used to coordinate estrus and ovulation timing prior to the AI or ET event. Common protocols include CIDR (Controlled Internal Drug Release), OvSynch, CoSynch, Select-Synch, and MGA (melengestrol acetate). none indicates natural estrus detection was used. [ENUM-REF-CANDIDATE: CIDR|OvSynch|CoSynch|Select_Synch|MGA|none|TAI|FTAI — promote to reference product]. Valid values are `CIDR|OvSynch|CoSynch|Select_Synch|MGA|none`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this breeding event or inventory record was most recently modified. Formatted as yyyy-MM-ddTHH:mm:ss.SSSXXX. Used for change tracking, data synchronization, and audit compliance.',
    CONSTRAINT pk_breeding_event PRIMARY KEY(`breeding_event_id`)
) COMMENT 'Master and transactional record for the breeding program — encompassing both breeding activities and semen/embryo inventory management. For breeding activities: captures breeding date, female animal ID, sire ID or semen lot reference, breeding method (natural service, AI, embryo transfer), technician, conception check date, conception result, expected parturition date, and breeding program reference. For semen/embryo inventory: captures sire ID, sire name, breed, genetic registration number, EPD values (calving ease, birth weight, weaning weight, yearling weight, milk, marbling, REA), genomic-enhanced EPD flag, semen supplier, collection date, lot number, quantity on hand (straws/embryos), storage tank ID, storage location (canister/goblet/cane), conception rate history, cost per unit, and quality grade (post-thaw motility). Record type discriminator (breeding_activity vs semen_inventory) separates the two concerns. Supports genetic improvement tracking, EPD analysis, reproductive performance KPIs, AI program planning, and breeding cost accounting.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`livestock`.`parturition_record` (
    `parturition_record_id` BIGINT COMMENT 'Unique system-generated identifier for each parturition (birth/calving/farrowing/lambing/kidding) event record. Serves as the primary key for this transactional entity.',
    `asset_id` BIGINT COMMENT 'Foreign key linking to equipment.asset. Business justification: Parturition events use specific equipment assets (calving pen monitoring systems, obstetrical equipment, calf pullers). Linking to asset enables maintenance scheduling based on birthing event frequenc',
    `breeding_event_id` BIGINT COMMENT 'Foreign key linking to livestock.breeding_event. Business justification: A parturition_record (birth/calving event) is the direct outcome of a breeding_event. Linking parturition_record.breeding_event_id → livestock.breeding_event.breeding_event_id closes the reproductive ',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Parturition events with veterinary intervention (dystocia, C-section) incur direct costs requiring cost center allocation for livestock enterprise P&L. Calving/farrowing cost tracking by cost center i',
    `crew_id` BIGINT COMMENT 'Foreign key linking to workforce.crew. Business justification: Calving/farrowing crews handle parturition events in large livestock operations. Crew-level tracking supports H2A labor compliance, piece-rate payroll for calving assistance, and labor cost allocation',
    `facility_id` BIGINT COMMENT 'Reference to the farm facility, barn, or pen where the parturition event occurred. Supports location-based performance analysis and biosecurity management.',
    `herd_id` BIGINT COMMENT 'Reference to the herd or flock to which the dam belongs at the time of parturition. Used for herd-level performance reporting and APHIS traceability.',
    `lab_sample_id` BIGINT COMMENT 'Foreign key linking to quality.lab_sample. Business justification: Colostrum quality testing, neonatal blood sampling for pathogen screening (BVD, Johnes), and placental pathology samples are collected at parturition. A domain expert expects parturition_record to re',
    `pen_location_id` BIGINT COMMENT 'Foreign key linking to livestock.pen_location. Business justification: Parturition (birth/calving/farrowing) events occur in a specific physical pen or maternity area. Linking parturition_record to pen_location enables traceability of where births occurred, supports bios',
    `animal_id` BIGINT COMMENT 'Reference to the female parent (dam) animal record that gave birth. Links to the animal master record for the dam, enabling lineage tracing and dam performance analytics.',
    `employee_id` BIGINT COMMENT 'Reference to the farm worker or veterinary staff member who attended and recorded the parturition event. Used for workforce accountability and SOP compliance tracking.',
    `birth_date` DATE COMMENT 'Calendar date on which the parturition event occurred. Used as the primary date dimension for herd performance reporting, age calculation, and regulatory records.',
    `birth_time` TIMESTAMP COMMENT 'Precise date and time when the first offspring was born during the parturition event. Enables time-of-day analysis for staffing optimization and dystocia risk assessment.',
    `birth_type` STRING COMMENT 'Classification of the parturition by number of offspring born in the event (e.g., single, twin, triplet). Impacts dam recovery protocols, colostrum management, and offspring survival rates.. Valid values are `SINGLE|TWIN|TRIPLET|QUADRUPLET|QUINTUPLET_PLUS`',
    `birth_weight_kg` DECIMAL(18,2) COMMENT 'Average birth weight in kilograms across all live offspring born in this parturition event. For individual offspring weights, see the offspring detail records. Used for growth performance benchmarking and genetic evaluation (EPD).',
    `breeding_method` STRING COMMENT 'Method by which the dam was bred that resulted in this parturition: natural service, artificial insemination (AI), or embryo transfer (ET). Used for genetic program performance analysis and sire utilization reporting.. Valid values are `NATURAL_SERVICE|ARTIFICIAL_INSEMINATION|EMBRYO_TRANSFER|UNKNOWN`',
    `colostrum_administered` BOOLEAN COMMENT 'Indicates whether colostrum was administered to the newborn offspring following birth. Critical for passive immunity transfer and neonatal survival; required for animal welfare compliance documentation.',
    `colostrum_source` STRING COMMENT 'Source of colostrum provided to the newborn offspring: from the dam directly, pooled from other animals, commercial colostrum supplement, or frozen colostrum bank. Relevant for biosecurity and disease transmission risk management.. Valid values are `DAM|POOLED|COMMERCIAL_SUPPLEMENT|FROZEN_BANK|NOT_ADMINISTERED`',
    `colostrum_volume_ml` DECIMAL(18,2) COMMENT 'Volume of colostrum administered to the newborn offspring in millilitres. Used to verify adequate passive immunity transfer per species-specific protocols and animal welfare standards.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this parturition record was first created in the system. Used for audit trail, data lineage, and Silver layer ingestion tracking.',
    `dam_body_condition_score` DECIMAL(18,2) COMMENT 'Body Condition Score (BCS) of the dam at the time of parturition, assessed on a standardized scale (e.g., 1–5 for cattle/sheep, 1–9 for swine). Indicates dam nutritional status and predicts post-partum reproductive performance.',
    `dam_parity` STRING COMMENT 'The parity number (number of times the dam has given birth, including this event) at the time of parturition. First-parity animals carry higher dystocia risk; used for reproductive lifecycle analytics.',
    `dam_post_partum_status` STRING COMMENT 'Health status of the dam immediately following the parturition event. Drives post-partum care protocols, veterinary treatment scheduling, and culling decisions.. Valid values are `NORMAL|REQUIRES_MONITORING|TREATED|CULLED|DECEASED`',
    `dystocia_flag` BOOLEAN COMMENT 'Indicates whether the parturition involved dystocia (difficult birth requiring intervention). Drives veterinary follow-up workflows and is used in sire EPD (Expected Progeny Difference) calculations.',
    `ease_of_birth_score` STRING COMMENT 'Standardized numeric score (typically 1–5 scale) indicating the difficulty of the parturition: 1=No assistance, 2=Easy pull, 3=Hard pull, 4=Mechanical assistance, 5=Caesarean/Veterinary. Used for dystocia tracking, sire selection, and animal welfare compliance. [ENUM-REF-CANDIDATE: 1|2|3|4|5 — promote to reference product]',
    `event_number` STRING COMMENT 'Externally-known business identifier for the parturition event, used for cross-referencing with farm management systems (e.g., Granular, SAP) and regulatory reporting. Format: PART-YYYY-NNNNNN.. Valid values are `^PART-[0-9]{4}-[0-9]{6}$`',
    `gestation_length_days` STRING COMMENT 'Number of days from confirmed conception or breeding date to the birth date. Compared against species-standard gestation norms to flag premature or overdue births and assess breeding program accuracy.',
    `intervention_type` STRING COMMENT 'Type of veterinary or assisted intervention performed during the parturition event. Used for dystocia severity classification, cost allocation, and sire/dam selection analytics.. Valid values are `MANUAL_CORRECTION|MECHANICAL_EXTRACTION|CAESAREAN|EPIDURAL|NONE`',
    `notes` STRING COMMENT 'Free-text field for attending staff or veterinarian to record additional observations about the parturition event not captured in structured fields (e.g., unusual presentations, environmental conditions, dam behavior).',
    `offspring_born_alive` STRING COMMENT 'Count of offspring born alive during this parturition event. Key metric for reproductive efficiency reporting and herd performance benchmarking.',
    `offspring_stillborn` STRING COMMENT 'Count of offspring born dead (stillborn) during this parturition event. Used for mortality analysis, genetic program evaluation, and animal welfare compliance reporting.',
    `placenta_expelled` BOOLEAN COMMENT 'Indicates whether the placenta (afterbirth) was fully expelled following parturition. Retained placenta is a significant post-partum health risk requiring veterinary intervention; tracked for dam health monitoring.',
    `placenta_expulsion_hours` DECIMAL(18,2) COMMENT 'Number of hours after birth until the placenta was fully expelled. Values exceeding species-specific thresholds (e.g., >12 hours in cattle) trigger retained placenta alerts and veterinary follow-up workflows.',
    `presentation_type` STRING COMMENT 'Describes the position of the fetus at the time of delivery (anterior/normal, posterior/backward, transverse/sideways). Relevant for dystocia risk assessment and veterinary intervention records.. Valid values are `ANTERIOR|POSTERIOR|TRANSVERSE|UNKNOWN`',
    `record_status` STRING COMMENT 'Lifecycle status of the parturition record within the farm management system. DRAFT indicates pending verification; CONFIRMED indicates validated entry; AMENDED indicates a corrected record; VOIDED indicates a data entry error.. Valid values are `DRAFT|CONFIRMED|AMENDED|VOIDED`',
    `season_code` STRING COMMENT 'Agricultural season in which the parturition event occurred. Used for seasonal performance benchmarking, feed planning, and herd management scheduling.. Valid values are `SPRING|SUMMER|FALL|WINTER`',
    `source_system` STRING COMMENT 'Operational system of record from which this parturition record originated (e.g., Granular Farm Management, SAP S/4HANA, John Deere Operations Center, or manual entry). Used for data lineage and reconciliation in the Databricks Silver layer.. Valid values are `GRANULAR|SAP_S4HANA|JOHN_DEERE|MANUAL|OTHER`',
    `species_code` STRING COMMENT 'Livestock species involved in the parturition event. Determines the applicable regulatory framework (FSIS, APHIS) and terminology (calving, farrowing, lambing, kidding, foaling).. Valid values are `BOVINE|PORCINE|OVINE|CAPRINE|EQUINE|POULTRY`',
    `total_offspring_born` STRING COMMENT 'Total count of offspring born during this parturition event, including stillborn. Used for litter size analytics and dam reproductive performance KPIs.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this parturition record was most recently modified. Used for change detection in incremental Silver layer loads and audit compliance.',
    `veterinary_intervention` BOOLEAN COMMENT 'Indicates whether a licensed veterinarian was required to intervene during the parturition event (e.g., caesarean section, manual correction of malpresentation). Drives post-event health monitoring and cost tracking.',
    CONSTRAINT pk_parturition_record PRIMARY KEY(`parturition_record_id`)
) COMMENT 'Transactional record capturing each birth or calving/farrowing/lambing/kidding event. Records dam ID, sire ID, birth date, birth time, number of offspring, individual offspring IDs, birth weight per offspring, birth type (single, twin, triplet), ease of birth score, colostrum administration, dam body condition score at birth, and attending staff. Initiates the animal master record for newborns and feeds into herd performance reporting.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`livestock`.`health_treatment` (
    `health_treatment_id` BIGINT COMMENT 'Unique surrogate identifier for each health treatment record or protocol template in the livestock health management system. Primary key for the health_treatment data product.',
    `animal_id` BIGINT COMMENT 'Reference to the individual animal record in the livestock master data product. Populated for individual animal treatments; may be null for group-level treatments where group_id is used instead. Supports APHIS individual animal traceability requirements.',
    `asset_id` BIGINT COMMENT 'Foreign key linking to equipment.asset. Business justification: Treatment equipment (squeeze chutes, hydraulic restraint systems, dosing guns) are tracked assets. Linking health_treatment to asset enables maintenance scheduling based on treatment frequency, equipm',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Veterinary treatment costs are the second-largest variable cost in livestock operations. Cost center assignment on health_treatment enables health cost per head reporting, antibiotic program cost trac',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Health treatments must be linked to the performing employee for antibiotic stewardship compliance, VFD regulatory audits, and labor cost tracking. treated_by_name is a denormalized string that viola',
    `facility_id` BIGINT COMMENT 'Reference to the farm, barn, pen, or facility location where the treatment was administered. Supports GIS-based disease mapping in Esri ArcGIS and pen-level health analytics for APHIS disease surveillance.',
    `health_protocol_id` BIGINT COMMENT 'Self-referencing foreign key to the parent protocol_template record in this same health_treatment product. Populated when this treatment_instance was executed following a standardized health management protocol. Null for ad-hoc treatments or for protocol_template records themselves.',
    `herd_id` BIGINT COMMENT 'Foreign key linking to livestock.herd. Business justification: health_treatment records veterinary interventions that occur within a herd context. The herd_id is essential for herd-level morbidity/mortality reporting, APHIS regulatory compliance, and antibiotic u',
    `input_catalog_id` BIGINT COMMENT 'Foreign key linking to procurement.input_catalog. Business justification: Veterinary drugs and biologicals are managed in the procurement input catalog with PHI days, withdrawal periods, and EPA/APHIS registration data. Linking health_treatment to input_catalog enforces app',
    `lab_sample_id` BIGINT COMMENT 'Foreign key linking to quality.lab_sample. Business justification: Culture and sensitivity testing, diagnostic blood panels, and pathogen identification samples are collected to confirm diagnosis before or during treatment. A domain expert expects health_treatment to',
    `lot_trace_id` BIGINT COMMENT 'Foreign key linking to supply.lot_trace. Business justification: FDA/USDA drug and vaccine lot traceability is mandatory for withdrawal period compliance and product recall management. health_treatment.vaccine_lot_number is a denormalized lot reference; FK to lot_t',
    `material_master_id` BIGINT COMMENT 'Foreign key linking to inventory.material_master. Business justification: Drug inventory management and withdrawal-period compliance reporting require linking each treatment to the inventory material master. Enables MRP-driven drug stock replenishment, cost-per-treatment ac',
    `mrl_threshold_id` BIGINT COMMENT 'Foreign key linking to product.mrl_threshold. Business justification: Health treatments involve drugs with regulatory MRL thresholds governing withdrawal periods and earliest harvest dates. Linking health_treatment to product.mrl_threshold enables automated withdrawal p',
    `nonconformance_id` BIGINT COMMENT 'Foreign key linking to quality.nonconformance. Business justification: Drug residue exceedances, antibiotic withdrawal violations, and treatment protocol failures generate nonconformance records. USDA FSIS and FSMA require traceability from treatment event to quality non',
    `pen_location_id` BIGINT COMMENT 'Foreign key linking to livestock.pen_location. Business justification: Health treatments are administered to animals in specific pens or treatment areas. Linking health_treatment to pen_location enables pen-level disease tracking, biosecurity zone analysis, and morbidity',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Animal health treatment costs are significant livestock expenses requiring profit center attribution for enterprise P&L. Veterinary and drug costs by profit center are standard reporting requirements ',
    `purchase_order_id` BIGINT COMMENT 'Foreign key linking to procurement.purchase_order. Business justification: Medications used in treatments are procured via PO. Linking health_treatment to purchase_order enables drug lot traceability from procurement through treatment application, supports withdrawal period ',
    `vendor_contract_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor_contract. Business justification: Pharmaceutical and veterinary product suppliers operate under vendor contracts. Linking health_treatment to vendor_contract enables contract-based drug spend tracking, formulary compliance auditing, a',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor. Business justification: Drug/vaccine supplier traceability per treatment record is required for product recall response, FDA/USDA regulatory audits, and withdrawal period compliance tied to specific supplier lots. Livestock ',
    `veterinary_prescription_id` BIGINT COMMENT 'Foreign key linking to livestock.veterinary_prescription. Business justification: health_treatment.prescription_reference is currently a STRING field storing the prescription reference number. veterinary_prescription is the master record for VFDs and prescriptions. Normalizing by a',
    `booster_due_date` DATE COMMENT 'The date on which a follow-up booster vaccination is due for the treated animal, based on the vaccine manufacturers protocol. Applicable only for vaccination treatment types requiring multi-dose schedules. Drives vaccination schedule alerts in the FMIS.',
    `clinical_signs` STRING COMMENT 'Free-text description of the observable clinical signs or symptoms presented by the animal or group at the time of treatment, as recorded by the attending veterinarian or farm staff. Supports HACCP documentation and veterinary case history.',
    `created_timestamp` TIMESTAMP COMMENT 'System-generated timestamp recording when this health treatment record was first created in the FMIS or SAP QM system. Used for audit trail, data lineage, and regulatory record-keeping compliance.',
    `diagnosis_code` STRING COMMENT 'Standardized veterinary diagnosis code identifying the disease or condition being treated, aligned with USDA APHIS disease reporting codes or ICD-10-CM veterinary adaptations. Used for APHIS disease surveillance reporting and herd health analytics.',
    `dosage_amount` DECIMAL(18,2) COMMENT 'Numeric quantity of the drug or vaccine product administered per animal or per unit of body weight, as prescribed. Used in conjunction with dosage_unit for complete dosage documentation required by FDA VFD and FSIS withdrawal compliance.',
    `dosage_unit` STRING COMMENT 'Unit of measure for the administered dosage amount (e.g., mL, mg, mg/kg body weight). Required for accurate withdrawal period calculation and FDA VFD documentation.. Valid values are `mL|mg|mg/kg|mL/kg|IU|g`',
    `ear_tag_number` STRING COMMENT 'Physical ear tag identifier of the treated animal, denormalized from the animal master for rapid field lookup and cross-referencing with paper-based treatment logs. Supports USDA NAIS (National Animal Identification System) traceability.',
    `earliest_harvest_date` DATE COMMENT 'Calculated date on which the animal first becomes eligible for harvest or product collection after completing the mandatory withdrawal period. Derived from treatment_date plus withdrawal_days; stored as a business-critical compliance field to prevent premature slaughter and FSIS violations.',
    `notes` STRING COMMENT 'Free-text field for additional observations, special instructions, or contextual information recorded by the veterinarian or farm staff at the time of treatment. Supports HACCP documentation and veterinary case history completeness.',
    `number_of_animals_treated` STRING COMMENT 'Count of individual animals included in this treatment event. Value is 1 for individual animal treatments; greater than 1 for group-level treatments such as metaphylaxis or arrival processing. Used for drug inventory reconciliation and treatment cost allocation.',
    `product_used_unit` STRING COMMENT 'Unit of measure for the total_product_used quantity (e.g., mL, mg, doses). Required for drug inventory reconciliation and cost reporting.. Valid values are `mL|mg|g|IU|doses`',
    `record_type` STRING COMMENT 'Discriminator indicating whether this record represents an actual treatment event applied to an animal or group (treatment_instance) or a standardized health management protocol template used as a reference for future treatments (protocol_template). Drives downstream processing logic and reporting.. Valid values are `treatment_instance|protocol_template`',
    `retreatment_flag` BOOLEAN COMMENT 'Indicates whether this treatment record represents a re-treatment of an animal that did not respond adequately to a prior treatment for the same condition. True when this is a follow-up treatment; False for initial treatments. Supports antibiotic stewardship and treatment efficacy analytics.',
    `rfid_tag` STRING COMMENT 'Electronic RFID tag identifier associated with the treated animal, used for automated identification in chute-side treatment systems and integration with John Deere Operations Center livestock modules. Supports ISO 11784/11785 RFID standards.',
    `route_of_administration` STRING COMMENT 'The method by which the drug or vaccine was delivered to the animal (e.g., subcutaneous injection, intramuscular injection, oral drench, topical pour-on, intranasal spray). Affects withdrawal period applicability and FSIS residue compliance.. Valid values are `subcutaneous|intramuscular|intravenous|oral|topical|intranasal`',
    `total_product_used` DECIMAL(18,2) COMMENT 'Total quantity of the drug or vaccine product consumed for this treatment event, calculated as dosage_amount multiplied by number_of_animals_treated. Stored for drug inventory depletion recording in SAP MM and cost-of-treatment reporting.',
    `treatment_cost` DECIMAL(18,2) COMMENT 'Total cost of the treatment event in the farms operating currency, including drug product cost and veterinary service fees where applicable. Used for herd health cost-of-production analysis, OPEX reporting, and Granular Farm Management financial planning integration.',
    `treatment_date` DATE COMMENT 'The calendar date on which the veterinary treatment, vaccination, or health intervention was administered to the animal or group. This is the principal real-world event date used for withdrawal period calculations, FSIS compliance, and HACCP records.',
    `treatment_number` STRING COMMENT 'Externally-known business identifier for the treatment event or protocol template, used for cross-referencing with veterinary records, VFD documentation, and SAP QM notifications. Format typically follows farm-assigned numbering conventions (e.g., TRT-2024-00123).',
    `treatment_outcome` STRING COMMENT 'Clinical outcome of the treatment as assessed at the end of the treatment course or at follow-up evaluation. Used for herd health analytics, treatment efficacy reporting, and antibiotic stewardship program monitoring.. Valid values are `recovered|improved|no_change|deteriorated|died|retreated`',
    `treatment_status` STRING COMMENT 'Current lifecycle state of the treatment record. draft indicates a record in preparation; active indicates an ongoing treatment; completed indicates the treatment course is finished; cancelled indicates the treatment was voided; pending_approval indicates awaiting veterinarian sign-off for VFD-regulated products.. Valid values are `draft|active|completed|cancelled|pending_approval`',
    `treatment_timestamp` TIMESTAMP COMMENT 'Precise date and time at which the treatment was administered, captured for IoT-integrated barn management systems and time-sensitive drug administration protocols requiring exact timing records.',
    `treatment_type` STRING COMMENT 'Classification of the treatment purpose. therapeutic treats an existing disease; prophylactic prevents disease in healthy animals; vaccination administers a biological vaccine; metaphylaxis treats an entire group when a portion shows disease; arrival_processing covers standard processing at receiving; parasite_control targets internal or external parasites.. Valid values are `therapeutic|prophylactic|vaccination|metaphylaxis|arrival_processing|parasite_control`',
    `trigger_criteria` STRING COMMENT 'For protocol_template records, describes the specific conditions that trigger execution of this protocol (e.g., rectal temperature > 104°F, morbidity rate > 10% in pen within 7 days, BRD pull rate exceeds threshold). Null for treatment_instance records.',
    `updated_timestamp` TIMESTAMP COMMENT 'System-generated timestamp recording the most recent modification to this health treatment record. Supports audit trail requirements and change tracking for regulatory compliance.',
    `veterinarian_approval_date` DATE COMMENT 'The date on which the supervising veterinarian reviewed and approved this treatment record or protocol template. Required for VFD-regulated antibiotic treatments and GLOBALG.A.P. animal health certification audits.',
    `veterinarian_license_number` STRING COMMENT 'State-issued veterinary license number of the attending or supervising veterinarian responsible for the treatment authorization. Required for VFD documentation and VCPR compliance. Null when treatment is administered by non-veterinary farm staff under a standing order.',
    `vfd_reference_number` STRING COMMENT 'The official Veterinary Feed Directive (VFD) document reference number issued by the licensed veterinarian authorizing the use of a VFD antibiotic in animal feed. Mandatory for medically important antimicrobials used in feed per FDA VFD regulations. Null for non-VFD treatments.',
    `withdrawal_days` STRING COMMENT 'The mandatory number of days that must elapse after the last treatment before the animal or its products (meat, milk, eggs) may enter the food supply, as specified on the drug label. Also referred to as Pre-Harvest Interval (PHI) for meat animals. Critical for FSIS residue avoidance compliance.',
    `withdrawal_status` STRING COMMENT 'Current compliance status of the animal with respect to drug withdrawal period. in_withdrawal indicates the animal cannot yet be harvested; cleared indicates the withdrawal period has elapsed; not_applicable applies to non-withdrawal products or protocol templates.. Valid values are `in_withdrawal|cleared|not_applicable`',
    CONSTRAINT pk_health_treatment PRIMARY KEY(`health_treatment_id`)
) COMMENT 'Transactional record of every veterinary treatment, medical intervention, vaccination, and health protocol template for individual animals or groups. Captures treatment date, animal ID, record type (treatment_instance or protocol_template), treatment type (therapeutic, prophylactic, vaccination, metaphylaxis, arrival processing, parasite control), diagnosis code, clinical signs, drug/product name, active ingredient (AI), dosage, route of administration, withdrawal period (PHI/REI), booster due date (for vaccinations), vaccine manufacturer lot number, treated-by (veterinarian or farm staff), prescription/VFD reference, protocol reference (self-referencing FK for treatments following a protocol template), trigger criteria (temperature threshold, morbidity rate for protocol templates), treatment outcome, re-treatment flag, withdrawal status, earliest eligible harvest date, and veterinarian approval date. Serves as the consolidated SSOT for all animal health interventions and standardized health management procedures. Critical for FSIS antibiotic withdrawal period compliance, FDA VFD documentation, HACCP records, USDA residue avoidance programs, APHIS disease surveillance, GLOBALG.A.P. animal health certification, and herd health protocol management.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`livestock`.`vaccination_record` (
    `vaccination_record_id` BIGINT COMMENT 'Unique system-generated identifier for each vaccination record. Primary key for the vaccination_record data product in the livestock domain.',
    `animal_id` BIGINT COMMENT 'Reference to the individual animal receiving the vaccination. Links to the animal master record in the livestock domain. Null when vaccination is administered at group/herd level.',
    `asset_id` BIGINT COMMENT 'Foreign key linking to equipment.asset. Business justification: Vaccination events use tracked equipment assets (squeeze chutes, automatic syringes, restraint systems). Linking to asset supports maintenance scheduling (sterilization cycles), regulatory audit trail',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Vaccination programs are budgeted line items in livestock enterprise health cost budgets. Cost center assignment on vaccination_record enables vaccine program cost tracking, budget vs. actual variance',
    `crew_id` BIGINT COMMENT 'Foreign key linking to workforce.crew. Business justification: Vaccination processing days are crew events in livestock operations. Crew-level vaccination tracking supports labor cost allocation and crew productivity reporting (head vaccinated per crew per day), ',
    `employee_id` BIGINT COMMENT 'Reference to the workforce record of the person who administered the vaccination (veterinarian, veterinary technician, or trained farm employee).',
    `facility_id` BIGINT COMMENT 'Official USDA National Premises Identification Number (PIN) for the location where vaccination occurred. Required for APHIS Animal Disease Traceability reporting and national disease surveillance programs.',
    `health_protocol_id` BIGINT COMMENT 'Foreign key linking to livestock.health_protocol. Business justification: Vaccination records should reference the standardized health protocol that governs the vaccination program. health_protocol is the master record defining vaccination schedules, dosage, withdrawal peri',
    `herd_id` BIGINT COMMENT 'Foreign key linking to livestock.herd. Business justification: Vaccinations are frequently administered at the herd or group level (mass vaccination events), not just to individual animals. Linking vaccination_record to herd enables herd-level vaccination complia',
    `input_catalog_id` BIGINT COMMENT 'Foreign key linking to procurement.input_catalog. Business justification: Vaccines are managed in the procurement input catalog with PHI days, withdrawal periods, and regulatory registration data. Linking vaccination_record to input_catalog enforces approved vaccine formula',
    `lab_sample_id` BIGINT COMMENT 'Foreign key linking to quality.lab_sample. Business justification: Post-vaccination serology and titer testing verify vaccine efficacy (e.g., BVDV, IBR titers). USDA-accredited herd health programs require documented titer results linked to vaccination events. A doma',
    `lot_trace_id` BIGINT COMMENT 'Foreign key linking to supply.lot_trace. Business justification: USDA APHIS and FDA require vaccine lot traceability for adverse event reporting and recall compliance. vaccination_record.manufacturer_lot_number is a denormalized lot reference; FK to lot_trace enabl',
    `material_master_id` BIGINT COMMENT 'Foreign key linking to inventory.material_master. Business justification: Vaccine inventory management and lot traceability require linking each vaccination event to the specific material_master record for the vaccine used. Enables withdrawal period compliance, cold-chain v',
    `pen_location_id` BIGINT COMMENT 'Foreign key linking to livestock.pen_location. Business justification: Vaccination events occur in specific pens or processing areas. Linking vaccination_record to pen_location enables location-based vaccination coverage analysis, biosecurity zone compliance tracking, an',
    `purchase_order_id` BIGINT COMMENT 'Foreign key linking to procurement.purchase_order. Business justification: Vaccines are procured via purchase orders with lot and expiry tracking. Linking vaccination_record to purchase_order enables vaccine lot traceability from PO receipt through animal administration, sup',
    `master_id` BIGINT COMMENT 'Foreign key linking to product.master. Business justification: Vaccine products belong in the product catalog (product.master) for lifecycle management, cost tracking, and regulatory compliance. vaccine_name is a denormalized product reference. Linking enables va',
    `vendor_contract_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor_contract. Business justification: Vaccine suppliers operate under vendor contracts with volume commitments and cold-chain requirements. Linking vaccination_record to vendor_contract enables contract spend tracking, cold-chain complian',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor. Business justification: Vaccine manufacturer/supplier traceability per vaccination record is required for lot recall response, cold chain compliance audits, and USDA/APHIS regulatory reporting. vaccination_record.manufacture',
    `veterinary_prescription_id` BIGINT COMMENT 'Reference to the veterinary prescription or Veterinary Feed Directive (VFD) authorizing use of the vaccine, particularly for prescription-only biologics. Null for over-the-counter vaccines.',
    `administration_date` DATE COMMENT 'The calendar date on which the vaccine was administered to the animal or group. Principal business event date for regulatory reporting, withdrawal period calculation, and booster scheduling.',
    `administration_location` STRING COMMENT 'Name or identifier of the farm, barn, pen, or facility location where the vaccination was administered. Supports geographic disease surveillance, APHIS premises identification, and GLOBALG.A.P. site-level audit trails.',
    `administration_route` STRING COMMENT 'The anatomical route by which the vaccine was administered (e.g., subcutaneous, intramuscular, intranasal). Must match the label-approved route of administration per APHIS biologics regulations.. Valid values are `subcutaneous|intramuscular|intranasal|oral|intravenous|topical`',
    `administration_timestamp` TIMESTAMP COMMENT 'Precise date and time the vaccine was administered, captured from the farm management system or mobile device. Supports time-sensitive withdrawal period calculations and audit trail integrity.',
    `adverse_reaction_description` STRING COMMENT 'Free-text description of any adverse reaction observed following vaccination (e.g., anaphylaxis, injection site swelling, fever). Populated only when adverse_reaction_observed is True. Supports APHIS CVB adverse event reporting.',
    `adverse_reaction_observed` BOOLEAN COMMENT 'Indicates whether an adverse reaction was observed in the animal(s) following vaccination. A value of True triggers creation of an adverse event report to USDA APHIS Center for Veterinary Biologics (CVB) and initiates veterinary follow-up.',
    `animal_count` STRING COMMENT 'Count of animals vaccinated in a group/herd-level vaccination event. Populated when herd_group_id is set and individual animal records are not created. Used for herd immunity coverage calculations.',
    `booster_due_date` DATE COMMENT 'Calculated or label-specified date by which the next booster dose must be administered to maintain protective immunity. Drives automated alerts in the herd vaccination schedule and GLOBALG.A.P. compliance monitoring.',
    `certificate_of_analysis_number` STRING COMMENT 'Reference number of the Certificate of Analysis (COA) issued by the vaccine manufacturer for the specific lot, confirming potency, purity, and safety testing results. Corresponds to COA in common agricultural jargon.',
    `cold_chain_maintained` BOOLEAN COMMENT 'Indicates whether the required cold chain storage conditions were maintained for the vaccine from receipt through administration. A value of False triggers a non-compliance flag and may invalidate the vaccination record for regulatory purposes.',
    `compliance_status` STRING COMMENT 'Current compliance state of this vaccination record against the herd vaccination schedule and regulatory requirements. Drives APHIS disease surveillance alerts and GLOBALG.A.P. certification audits. [ENUM-REF-CANDIDATE: compliant|non_compliant|pending|overdue|waived|under_review — promote to reference product]. Valid values are `compliant|non_compliant|pending|overdue|waived|under_review`',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp when this vaccination record was first created in the data platform. Used for audit trail, data lineage, and Silver layer ingestion tracking.',
    `disease_target` STRING COMMENT 'The disease, pathogen, or condition the vaccine is intended to prevent or control (e.g., Bovine Respiratory Disease, Porcine Reproductive and Respiratory Syndrome, Newcastle Disease). Supports disease surveillance analytics and APHIS reportable disease tracking.',
    `dosage_ml` DECIMAL(18,2) COMMENT 'Volume of vaccine administered in milliliters (mL) per animal or per dose. Must conform to label-approved dosage. Deviations from label dosage require veterinary authorization and are flagged for compliance review.',
    `dose_number` STRING COMMENT 'Sequential dose number within a multi-dose vaccination series (e.g., 1 = primary, 2 = booster). Enables tracking of vaccination series completion and booster compliance.',
    `ear_tag_number` STRING COMMENT 'Official ear tag or visual identification number of the individual animal at time of vaccination. Denormalized for rapid lookup and regulatory reporting without joining to the animal master. Supports APHIS Animal Disease Traceability (ADT) requirements.',
    `earliest_harvest_date` DATE COMMENT 'The earliest date on which the animal may be harvested for human consumption, calculated as administration_date plus withdrawal_period_days. Critical for FSIS pre-harvest food safety compliance and scheduling harvest operations.',
    `injection_site` STRING COMMENT 'Specific anatomical location on the animal where the vaccine was injected (e.g., neck, behind ear, rump). Supports Beef Quality Assurance (BQA) compliance and carcass quality tracking to avoid injection site lesions.',
    `notes` STRING COMMENT 'Free-text field for additional observations, deviations from standard protocol, animal behavior notes, or other contextual information recorded by the administering technician or supervising veterinarian.',
    `record_number` STRING COMMENT 'Externally-known, human-readable business identifier for this vaccination event, used in veterinary documentation, APHIS reporting, and GLOBALG.A.P. audit trails. Format: VAC-{YYYY}-{NNNNNN}.. Valid values are `^VAC-[0-9]{4}-[0-9]{6}$`',
    `rfid_tag_number` STRING COMMENT 'RFID electronic identification number of the animal at time of vaccination, conforming to ISO 11784/11785 standards. Enables automated identification during chute-side vaccination and integrates with John Deere Operations Center livestock tracking.',
    `serial_number` STRING COMMENT 'USDA-assigned serial number for the specific biologics product lot, distinct from the manufacturer lot number. Required for APHIS Center for Veterinary Biologics (CVB) compliance and product release verification.',
    `species` STRING COMMENT 'Species of the animal(s) vaccinated. Determines applicable regulatory framework (APHIS, FSIS), withdrawal period tables, and label compliance requirements. [ENUM-REF-CANDIDATE: bovine|porcine|poultry|ovine|caprine|equine|aquaculture|other — promote to reference product]',
    `storage_temperature_c` DECIMAL(18,2) COMMENT 'Temperature in degrees Celsius at which the vaccine was stored prior to administration. Verified against label-required cold chain specifications (typically 2–8°C for refrigerated biologics). Out-of-range values trigger cold chain breach alerts.',
    `updated_timestamp` TIMESTAMP COMMENT 'System timestamp of the most recent modification to this vaccination record. Supports change detection, data quality monitoring, and regulatory audit requirements.',
    `vaccine_expiry_date` DATE COMMENT 'Expiration date printed on the vaccine vial or packaging. Used to verify that the vaccine was not expired at time of administration and to flag non-compliant records for regulatory review.',
    `vaccine_type` STRING COMMENT 'Biological classification of the vaccine formulation. Determines handling requirements, storage conditions, and regulatory classification under APHIS biologics licensing.. Valid values are `modified_live|killed|toxoid|recombinant|subunit|autogenous`',
    `withdrawal_period_days` STRING COMMENT 'Number of days that must elapse after vaccination before the animal or its products (meat, milk, eggs) may enter the food supply. Derived from the vaccine label and used to calculate the earliest eligible harvest date for FSIS pre-harvest food safety compliance.',
    CONSTRAINT pk_vaccination_record PRIMARY KEY(`vaccination_record_id`)
) COMMENT 'Transactional record of each vaccination administered to an individual animal or group. Captures vaccination date, animal or group ID, vaccine product name, manufacturer lot number, dosage, route, booster due date, administering technician, veterinary prescription reference, and compliance status against the herd vaccination schedule. Supports APHIS disease surveillance, FSIS pre-harvest food safety, and GLOBALG.A.P. animal health certification.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`livestock`.`weight_measurement` (
    `weight_measurement_id` BIGINT COMMENT 'Unique system-generated identifier for each individual weight measurement record. Serves as the primary key for the weight_measurement data product in the livestock domain Silver Layer.',
    `animal_id` BIGINT COMMENT 'Reference to the individual animal record being weighed. Populated for individual-scale measurements; null for group/pen-level measurements. Links to the animal master record in the livestock domain.',
    `asset_id` BIGINT COMMENT 'Reference to the weighing equipment (scale, load cell, or weigh tape device) used to capture the measurement. Links to the equipment asset master for calibration traceability.',
    `crew_id` BIGINT COMMENT 'Foreign key linking to workforce.crew. Business justification: Feedlot weigh events are performed by processing crews for piece-rate payroll and H2A labor compliance reporting. Crew-level tracking enables cost-of-gain calculations per crew and supports labor comp',
    `employee_id` BIGINT COMMENT 'Reference to the workforce employee or contractor who performed and recorded the weight measurement. Required for audit trail and operator performance tracking.',
    `facility_id` BIGINT COMMENT 'Reference to the farm, feedlot, barn, or production facility where the weight measurement was taken. Supports geographic and facility-level performance analytics.',
    `herd_id` BIGINT COMMENT 'Foreign key linking to livestock.herd. Business justification: weight_measurement records individual and group weights at production checkpoints. The herd context is essential for herd-level average daily gain (ADG) reporting, performance benchmarking, and market',
    `pen_location_id` BIGINT COMMENT 'Foreign key linking to livestock.pen_location. Business justification: weight_measurement records are taken at specific pen/scale locations within the livestock facility. Adding pen_location_id → livestock.pen_location.pen_location_id enables location-based weight perfor',
    `adg_kg` DECIMAL(18,2) COMMENT 'Average Daily Gain (ADG) in kilograms per day, calculated as the difference between current and previous body weight divided by the number of days elapsed. A key Key Performance Indicator (KPI) for growth performance tracking and feed conversion ratio (FCR) analysis. Stored as a captured/confirmed value from the source system, not recomputed.',
    `adjusted_weight_kg` DECIMAL(18,2) COMMENT 'Body weight after applying shrink percentage adjustment, representing the net pay weight used for sale, transfer, or harvest transactions. Calculated as body_weight_kg × (1 - shrink_pct/100) and stored for traceability.',
    `age_days` STRING COMMENT 'Age of the animal in days at the time of measurement, calculated from the recorded birth date. Used to compute age-adjusted weight benchmarks, frame scores, and to assess growth performance relative to breed and production stage expectations.',
    `body_condition_score` DECIMAL(18,2) COMMENT 'Body Condition Score (BCS) assigned to the animal at the time of weighing, typically on a 1–9 scale for beef cattle or 1–5 scale for dairy/sheep. Assesses fat cover and muscle mass relative to skeletal frame. Critical for animal welfare compliance, breeding readiness, and nutritional management decisions.',
    `body_weight_kg` DECIMAL(18,2) COMMENT 'The measured live body weight of the individual animal or average body weight per head for a group measurement, expressed in kilograms. This is the principal quantitative outcome of the measurement event. Used in ADG calculations, FCR analysis, and harvest readiness assessment.',
    `body_weight_lbs` DECIMAL(18,2) COMMENT 'The measured live body weight expressed in pounds (lbs), the primary unit of measure used in US domestic livestock markets, USDA reporting, and sale/harvest transactions. Maintained alongside kg for dual-unit reporting compliance.',
    `breed_code` STRING COMMENT 'Standardized breed code for the animal being weighed (e.g., ANGUS, HEREFORD, DUROC, HOLSTEIN). Used to apply breed-specific growth curves, expected weight benchmarks, and frame score standards in performance analytics.',
    `created_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when this weight measurement record was first created in the system of record. Distinct from measurement_timestamp which captures the real-world event time. Required for data lineage and Silver Layer audit trail.',
    `days_on_feed` STRING COMMENT 'Number of days the animal or group has been on the current feed ration since feedlot entry or last production stage transition. Used in conjunction with ADG to assess feed conversion efficiency and project harvest readiness date.',
    `ear_tag_number` STRING COMMENT 'Visual ear tag identifier recorded at the time of weighing for cross-verification with RFID and as a backup identification method. Used in manual weighing operations and visual lot reconciliation.',
    `frame_score` DECIMAL(18,2) COMMENT 'Numerical frame score (typically 1–9 for beef cattle) based on hip height measurement at a standard age, used to predict mature body size and optimal harvest weight. Supports breed selection, feeding program design, and market endpoint targeting.',
    `harvest_ready_flag` BOOLEAN COMMENT 'Boolean indicator set to True when the animals current body weight, BCS, and days on feed meet the defined harvest readiness criteria for the production program. Triggers harvest scheduling workflow and FSIS pre-harvest notification processes.',
    `head_count` STRING COMMENT 'Number of animals included in the measurement event. For individual measurements this is 1. For group/pen measurements this is the total number of animals weighed, used to calculate average body weight per head and total pen weight.',
    `hip_height_cm` DECIMAL(18,2) COMMENT 'Measured hip height of the animal in centimeters at the time of weighing, used to calculate frame score and assess skeletal development relative to body weight. Supports growth curve modeling and breed standard compliance.',
    `lot_number` STRING COMMENT 'Lot Number (LOT) identifying the production batch or consignment group to which the animal belongs at the time of measurement. Enables batch-level traceability from farm through harvest, supporting FSMA and FSIS compliance requirements.',
    `measurement_date` DATE COMMENT 'Calendar date on which the weight measurement was taken, stored as a DATE type for day-level partitioning, reporting, and production checkpoint scheduling. Derived from measurement_timestamp but retained for query performance.',
    `measurement_method` STRING COMMENT 'The technique or equipment type used to obtain the body weight. Affects measurement precision and confidence. Individual scale and load cell are most accurate; weigh tape and estimated methods carry higher variance and are flagged accordingly in analytics.. Valid values are `individual_scale|load_cell|weigh_tape|walk_over_scale|estimated`',
    `measurement_notes` STRING COMMENT 'Free-text field for operator observations recorded at the time of weighing, such as animal behavior, equipment anomalies, environmental conditions, or reasons for weight variance. Supports audit trail and veterinary follow-up.',
    `measurement_number` STRING COMMENT 'Externally-known business identifier for the weight measurement event, used for cross-referencing with farm management systems, scale printouts, and audit trails. Format: WM-{YYYY}-{NNNNNN}.. Valid values are `^WM-[0-9]{4}-[0-9]{6}$`',
    `measurement_status` STRING COMMENT 'Current workflow state of the weight measurement record. recorded = initial capture; verified = validated by supervisor or QA; rejected = failed validation rules; voided = cancelled after entry error.. Valid values are `recorded|verified|rejected|voided`',
    `measurement_timestamp` TIMESTAMP COMMENT 'The exact date and time when the weight measurement was physically taken. This is the principal real-world event timestamp, distinct from record audit timestamps. Critical for Average Daily Gain (ADG) calculations and production checkpoint tracking.',
    `previous_measurement_date` DATE COMMENT 'The date of the immediately preceding weight measurement for the same animal or group. Used to calculate the interval in days for ADG computation and to validate measurement frequency compliance.',
    `previous_weight_kg` DECIMAL(18,2) COMMENT 'The body weight recorded at the immediately preceding measurement event for the same animal or group, in kilograms. Stored on this record to support ADG validation and trend analysis without requiring a self-join.',
    `production_stage` STRING COMMENT 'Defined production checkpoint at which the weight measurement was taken, representing the animals lifecycle stage. Drives growth performance benchmarking, feed conversion ratio (FCR) calculations, and harvest readiness assessment. [ENUM-REF-CANDIDATE: birth|weaning|backgrounding|feedlot_entry|mid_feed|pre_harvest|harvest — promote to reference product]',
    `rfid_tag_number` STRING COMMENT 'The Radio Frequency Identification (RFID) electronic tag number read from the animal at the time of weighing, used to confirm animal identity and enable automated data capture from walk-over scales and electronic identification systems. Supports USDA APHIS traceability requirements.',
    `sex_code` STRING COMMENT 'Sex classification of the animal: M=Male (intact bull/boar/ram), F=Female (heifer/cow/gilt/ewe), C=Castrated male (steer/barrow/wether), S=Spayed female. Affects expected growth rates, weight benchmarks, and market endpoint targets.. Valid values are `M|F|C|S`',
    `shrink_pct` DECIMAL(18,2) COMMENT 'Estimated or measured percentage of body weight lost due to gut fill, stress, or transit prior to weighing (pencil shrink or actual shrink). Applied in sale weight calculations and market price negotiations. Standard industry practice in US livestock markets.',
    `source_system_code` STRING COMMENT 'Identifies the operational system of record from which this weight measurement record was ingested into the Silver Layer (e.g., Granular Farm Management, Climate FieldView, SAP S/4HANA PP, John Deere Operations Center, or manual entry). Supports data lineage and reconciliation.. Valid values are `GRANULAR|CLIMATE_FIELDVIEW|SAP_PP|JOHN_DEERE|MANUAL`',
    `species_code` STRING COMMENT 'Standardized code identifying the livestock species being weighed. Determines applicable weight benchmarks, BCS scales, frame score standards, and regulatory reporting requirements. [ENUM-REF-CANDIDATE: BEEF|DAIRY|SWINE|SHEEP|GOAT|POULTRY|EQUINE — promote to reference product]',
    `total_group_weight_kg` DECIMAL(18,2) COMMENT 'Total combined live weight of all animals in a group measurement event, expressed in kilograms. Null for individual animal measurements. Used for pen-level inventory valuation and feed planning.',
    `unit_of_measure` STRING COMMENT 'The primary unit of measure in which the weight was recorded at the point of capture (kg or lbs). Determines which weight field is the source-of-truth value; the alternate unit field is a conversion.. Valid values are `kg|lbs`',
    `updated_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when this weight measurement record was last modified, including status changes, corrections, or verification actions. Supports change data capture (CDC) in the Databricks Lakehouse Silver Layer pipeline.',
    `weigh_condition` STRING COMMENT 'Describes the gut-fill or fasting condition of the animal at the time of weighing, which directly affects the accuracy and comparability of weight measurements. Used to apply appropriate shrink adjustments and flag outlier weights.. Valid values are `full_fill|partial_fill|off_feed|fasted|post_transit`',
    `weight_variance_flag` BOOLEAN COMMENT 'Boolean indicator set to True when the measured body weight deviates from the expected weight by more than the configured tolerance threshold (e.g., ±15% from breed/age/stage benchmark). Triggers data quality review and potential animal health investigation.',
    CONSTRAINT pk_weight_measurement PRIMARY KEY(`weight_measurement_id`)
) COMMENT 'Transactional record of individual or group weight measurements taken at defined production checkpoints (weaning, backgrounding, feedlot entry, pre-harvest). Captures measurement date, animal ID or group ID, scale ID, body weight (lbs/kg), average daily gain (ADG) since last measurement, body condition score (BCS), frame score, measurement method (individual scale, load cell, weigh tape), and operator. Feeds into growth performance tracking, feed conversion ratio (FCR) calculations, and harvest readiness assessment.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`livestock`.`feed_ration` (
    `feed_ration_id` BIGINT COMMENT 'Unique surrogate identifier for each feed ration record (formulation or delivery event). Primary key for the feed_ration data product in the livestock domain.',
    `asset_id` BIGINT COMMENT 'Foreign key linking to equipment.asset. Business justification: Feed rations are mixed using specific TMR mixer assets. Linking feed_ration to the mixing asset supports calibration tracking (accurate ingredient inclusion rates), maintenance scheduling based on mix',
    `facility_id` BIGINT COMMENT 'Foreign key linking to supply.facility. Business justification: Feed rations are approved and managed at the facility level for FDA VFD medicated feed compliance and organic certification scope. A facility_id FK enables facility-specific ration approval workflows ',
    `haccp_plan_id` BIGINT COMMENT 'Foreign key linking to quality.haccp_plan. Business justification: Medicated and antibiotic-containing feed rations (antibiotic_flag, withdrawal_period_days) fall under HACCP/FSMA Preventive Controls for Animal Food. Linking feed_ration to its governing haccp_plan do',
    `herd_id` BIGINT COMMENT 'Foreign key linking to livestock.herd. Business justification: Feed rations are formulated for specific herds or production classes within a herd. Linking feed_ration to herd enables herd-level nutritional management, cost-per-head analysis by herd, and supports ',
    `mrl_threshold_id` BIGINT COMMENT 'Foreign key linking to product.mrl_threshold. Business justification: Medicated feed rations (antibiotic_flag=true) are subject to FDA VFD requirements and MRL thresholds for drug residues in food animals. Linking feed_ration to product.mrl_threshold enables automated w',
    `pen_location_id` BIGINT COMMENT 'Identifier of the pen or animal group to which this ration is assigned (formulation) or to which feed was delivered (delivery event). Links ration records to specific animal housing units for FCR tracking and feed cost allocation per animal group.',
    `employee_id` BIGINT COMMENT 'Reference to the licensed animal nutritionist or feed specialist responsible for formulating or approving this ration. Supports accountability, NRC compliance documentation, and audit trail for regulatory inspections.',
    `antibiotic_flag` BOOLEAN COMMENT 'Indicates whether this ration contains any antibiotic or medicated feed additive subject to VFD (Veterinary Feed Directive) or withdrawal period requirements. True = medicated; False = non-medicated. Critical for FSIS antibiotic residue compliance and withdrawal period tracking.',
    `approval_status` STRING COMMENT 'Current workflow status of the ration formulation in the approval lifecycle: draft (in preparation), pending_review (submitted to nutritionist), approved (cleared for use), rejected (not approved), superseded (replaced by newer version). Applicable to formulation records.. Valid values are `draft|pending_review|approved|rejected|superseded`',
    `bunk_score` STRING COMMENT 'Standardized numeric score (typically 0–4) assessing the feed bunk condition at the time of delivery: 0=empty/slick, 1=light cover, 2=normal, 3=heavy cover, 4=full refusal. Applicable to delivery records. Guides feeding rate adjustments and animal health monitoring.',
    `calcium_pct` DECIMAL(18,2) COMMENT 'Calculated calcium (Ca) content of the ration as a percentage of dry matter. Critical macro-mineral for bone development, milk production, and metabolic health. NRC compliance metric for all species.',
    `cost_per_head_per_day` DECIMAL(18,2) COMMENT 'Calculated feed cost in USD per animal per day based on ingredient prices and inclusion rates in the formulation. Applicable to formulation records. Key input for COGS (Cost of Goods Sold) allocation, OPEX tracking, and ROI analysis per production class.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this feed ration record was first created in the system. Supports audit trail, data lineage, and FSMA traceability requirements.',
    `crude_protein_pct` DECIMAL(18,2) COMMENT 'Calculated crude protein content of the ration as a percentage of dry matter. Key NRC nutritional compliance metric for protein adequacy across species and production classes. Applicable to formulation records.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for the cost_per_head_per_day field (e.g., USD). Supports multi-currency operations for international agriculture enterprises.. Valid values are `^[A-Z]{3}$`',
    `delivery_method` STRING COMMENT 'Method used to deliver feed to the animal group: TMR (Total Mixed Ration) mixer wagon, bunk feeder, automated feeding system, hand feed, or conveyor. Applicable to delivery records. Impacts feed uniformity and labor cost allocation.. Valid values are `tmr_mixer|bunk_feeder|automated_system|hand_feed|conveyor`',
    `delivery_timestamp` TIMESTAMP COMMENT 'Date and time at which feed was physically delivered to the pen or bunk. Principal business event timestamp for delivery records. Supports feeding schedule compliance, FCR (Feed Conversion Ratio) tracking, and daily intake analysis.',
    `dry_matter_pct` DECIMAL(18,2) COMMENT 'Dry matter content of the ration expressed as a percentage of as-fed weight. Used to convert as-fed quantities to DM basis for NRC nutrient requirement compliance and ration balancing.',
    `effective_date` DATE COMMENT 'Date from which this ration formulation becomes active and approved for use in feed delivery operations. Supports ration plan management and ensures animals receive the correct approved formulation.',
    `expiry_date` DATE COMMENT 'Date after which this ration formulation is no longer valid for use. Triggers review or replacement of the formulation. Applicable to formulation records.',
    `formulation_date` DATE COMMENT 'Date on which the ration formulation was created or last revised by the nutritionist. Applicable to formulation records. Used for version control and audit trail of recipe changes.',
    `gmo_flag` BOOLEAN COMMENT 'Indicates whether the ration formulation contains any GMO (Genetically Modified Organism) ingredients. True = contains GMO ingredients; False = non-GMO. Supports USDA National Organic Program (NOP) compliance, COOL labeling, and customer transparency requirements.',
    `mixing_instructions` STRING COMMENT 'Operational instructions for preparing the TMR or batch mix, including ingredient loading sequence, mixer run time, and any special handling notes. Applicable to formulation records. Supports SOP compliance and feed uniformity.',
    `neg_mcal_per_cwt` DECIMAL(18,2) COMMENT 'Net Energy for Gain (NEg) value of the ration expressed in megacalories per hundredweight (CWT) of dry matter. Used for NRC-compliant growth performance prediction and ration optimization in beef cattle finishing programs.',
    `nem_mcal_per_cwt` DECIMAL(18,2) COMMENT 'Net Energy for Maintenance (NEm) value of the ration expressed in megacalories per hundredweight (CWT) of dry matter. Used for NRC-compliant energy adequacy assessment in beef and dairy cattle rations.',
    `notes` STRING COMMENT 'Free-text field for additional nutritionist comments, special handling instructions, or operational observations related to the ration formulation or delivery event. Supports audit trail and knowledge transfer.',
    `nrc_compliance_flag` BOOLEAN COMMENT 'Indicates whether the ration formulation meets all NRC (National Research Council) nutrient requirement thresholds for the target species and production class. True = compliant; False = one or more NRC thresholds not met. Applicable to formulation records.',
    `phosphorus_pct` DECIMAL(18,2) COMMENT 'Calculated phosphorus (P) content of the ration as a percentage of dry matter. Key macro-mineral for energy metabolism and bone structure. NRC compliance metric; also tracked for environmental nutrient management under EPA guidelines.',
    `production_class` STRING COMMENT 'Specific production class or physiological stage of the target animal group (e.g., Finishing Steers, Lactating Dairy Cows, Nursery Pigs, Broiler Grower). Used for NRC-compliant nutrient requirement matching and ration cost allocation. [ENUM-REF-CANDIDATE: promote to reference product]',
    `quantity_delivered_dm_lbs` DECIMAL(18,2) COMMENT 'Total weight of feed delivered expressed on a dry matter (DM) basis in pounds. Calculated from as-fed quantity and dry matter percentage. Used for NRC-compliant nutrient intake calculations and ration balancing.',
    `quantity_delivered_lbs` DECIMAL(18,2) COMMENT 'Total weight of feed delivered to the pen on an as-fed basis, measured in pounds (lbs). Applicable to delivery records. Used for feed cost allocation per animal, FCR tracking, and daily intake monitoring.',
    `ration_name` STRING COMMENT 'Human-readable name assigned to the feed ration formulation (e.g., Grower Phase 2 TMR, Lactating Cow High-Energy). Used for identification in feed management systems and nutritionist communications.',
    `ration_number` STRING COMMENT 'Externally-known business identifier for the ration formulation or delivery event, used for cross-system reference and traceability (e.g., RAT-2024-00123). Sourced from Granular Farm Management or SAP PP.. Valid values are `^RAT-[0-9]{4}-[0-9]{5}$`',
    `record_type` STRING COMMENT 'Discriminator field separating the two concerns captured in this product: formulation for master ration recipes and delivery for transactional feed delivery events. Drives downstream processing logic and reporting segmentation.. Valid values are `formulation|delivery`',
    `refusal_amount_lbs` DECIMAL(18,2) COMMENT 'Weight of feed remaining uneaten in the bunk at the time of the next feeding, measured in pounds. Applicable to delivery records. Used to calculate actual intake, adjust ration quantities, and monitor animal health and appetite.',
    `target_daily_intake_lbs` DECIMAL(18,2) COMMENT 'Planned daily feed intake per head per day on an as-fed basis, in pounds. Applicable to formulation records. Derived from NRC nutrient requirements for the target species and production class. Drives delivery quantity planning.',
    `target_species` STRING COMMENT 'Animal species for which this ration is formulated or delivered (e.g., cattle, swine, poultry). Drives NRC nutritional compliance checks and species-specific regulatory requirements under APHIS and FSIS. [ENUM-REF-CANDIDATE: cattle|swine|poultry|sheep|goat|equine|other — promote to reference product]',
    `tdn_pct` DECIMAL(18,2) COMMENT 'Total Digestible Nutrients (TDN) content of the ration as a percentage of dry matter. Primary energy metric for ruminant rations used in NRC compliance and ration balancing. Applicable to formulation records.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this feed ration record was most recently modified. Supports change tracking, audit trail, and data quality monitoring in the Databricks Silver Layer.',
    `version_number` STRING COMMENT 'Sequential version number of the ration formulation, incremented each time the recipe is revised. Enables tracking of formulation changes over time and ensures delivery events reference the correct recipe version.',
    `withdrawal_period_days` STRING COMMENT 'Number of days animals must not receive this medicated ration prior to slaughter to ensure antibiotic residue levels are within FDA/FSIS MRL (Maximum Residue Limit) tolerances. Applicable when antibiotic_flag is True. Critical for FSIS compliance and food safety.',
    CONSTRAINT pk_feed_ration PRIMARY KEY(`feed_ration_id`)
) COMMENT 'Master and transactional record for feed nutrition management — encompassing both ration formulations (master) and feed delivery events (transactional). For formulations: captures ration name, version number, target species and production class, formulation date, nutritionist reference, ingredient list with inclusion rates (percent as-fed and DM basis), calculated nutrient profile (crude protein, TDN, NEm, NEg, calcium, phosphorus, trace minerals, vitamins), dry matter basis, target daily intake (lbs/head/day), cost per head per day, mixing instructions, and approval status. For delivery events: captures delivery date and time, pen/group ID, ration reference, quantity delivered (lbs/kg as-fed and dry matter), delivery method (TMR mixer, bunk feeder, automated system), operator, refusal amount, and feed bunk score. Record type discriminator (formulation vs delivery) separates the two concerns. Serves as the SSOT for feed formulation and delivery, supporting NRC nutritional compliance, feed cost allocation per animal, FCR tracking, and ration plan management.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`livestock`.`feed_delivery` (
    `feed_delivery_id` BIGINT COMMENT 'Unique system-generated identifier for each feed delivery event. Primary key for the feed_delivery data product in the livestock domain.',
    `asset_id` BIGINT COMMENT 'Identifier of the TMR mixer wagon or automated feeding equipment used for this delivery. Supports equipment utilization tracking, maintenance scheduling, OEE (Overall Equipment Effectiveness) analysis, and feed delivery cost allocation.',
    `commodity_lot_id` BIGINT COMMENT 'Identifier of the feed inventory lot (LOT) consumed in this delivery. Enables batch-level traceability, feed cost allocation, and withdrawal period tracking for medicated feeds per APHIS and FDA requirements.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Feed is the largest cost in livestock operations (60-70% of total cost). Cost center assignment on feed_delivery enables feed cost per head per day reporting, ration cost variance analysis, and cost c',
    `crew_id` BIGINT COMMENT 'Foreign key linking to workforce.crew. Business justification: Feed delivery in large feedlots is performed by feed crews operating mixer wagons. Crew-level tracking enables labor cost allocation per delivery, piece-rate payroll for feed drivers, and H2A complian',
    `employee_id` BIGINT COMMENT 'Identifier of the farm operator or employee who performed or supervised the feed delivery. Supports workforce accountability, SOP (Standard Operating Procedure) compliance, and FSMA traceability requirements.',
    `facility_id` BIGINT COMMENT 'Identifier of the farm facility or barn where the feed delivery took place. Supports multi-site operations, feed cost allocation by facility, and regulatory site-level reporting.',
    `feed_ration_id` BIGINT COMMENT 'Identifier of the prescribed feed ration formulation delivered. Used to verify nutritional compliance against the prescribed ration, support GMP (Good Manufacturing Practices) audits, and enable deviation analysis.',
    `lab_sample_id` BIGINT COMMENT 'Foreign key linking to quality.lab_sample. Business justification: Feed ingredient testing for mycotoxins (aflatoxin, DON), pathogens (Salmonella), and nutritional analysis is performed at delivery receipt. FDA FSMA Preventive Controls require feed safety testing. A ',
    `lot_trace_id` BIGINT COMMENT 'Foreign key linking to supply.lot_trace. Business justification: Feed ingredient lot traceability is required for medicated feed VFD compliance, FSMA Preventive Controls, and withdrawal period management. Linking feed_delivery to lot_trace enables full chain-of-cus',
    `nonconformance_id` BIGINT COMMENT 'Foreign key linking to quality.nonconformance. Business justification: Contaminated, out-of-spec, or adulterated feed deliveries generate nonconformances requiring quarantine, rejection, or corrective action. FDA FSMA and HACCP programs mandate nonconformance tracking fo',
    `pen_location_id` BIGINT COMMENT 'Identifier of the pen or housing unit where the feed was delivered. Links to the pen/group master record for animal group association, capacity tracking, and feed cost allocation per pen.',
    `procurement_goods_receipt_id` BIGINT COMMENT 'Foreign key linking to procurement.procurement_goods_receipt. Business justification: Feed deliveries must be matched to procurement goods receipts for three-way match (PO/GR/invoice) and FSMA supply chain documentation. Linking feed_delivery to procurement_goods_receipt enables quanti',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Feed costs are the largest single expense in livestock operations (50-70% of total cost). Profit center attribution on feed_delivery records enables feed cost allocation to livestock enterprise P&L se',
    `purchase_order_id` BIGINT COMMENT 'Foreign key linking to procurement.purchase_order. Business justification: Feed deliveries must reconcile against the originating procurement PO for three-way match (PO→GRN→pen delivery), feed cost allocation per production group, and FSMA supply chain traceability. A livest',
    `shipment_id` BIGINT COMMENT 'Foreign key linking to supply.shipment. Business justification: Feed deliveries from external suppliers arrive as inbound supply chain shipments. Linking feed_delivery to shipment enables FSMA feed ingredient traceability, medicated feed VFD compliance verificatio',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_location. Business justification: Feed delivery operations require direct reference to the source silo/bin storage location for inventory depletion, feed dispatch routing, and FIFO/FEFO rotation compliance. Role prefix source_ disti',
    `transport_unit_id` BIGINT COMMENT 'Foreign key linking to supply.transport_unit. Business justification: The specific mixer wagon or feed truck used for each delivery is tracked for equipment maintenance scheduling, feed contamination investigations, and FSMA sanitary transport compliance. feed_delivery ',
    `vendor_contract_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor_contract. Business justification: Feed is delivered under vendor supply contracts with volume commitments and price agreements. Linking feed_delivery to vendor_contract enables contract fulfillment tracking, price verification against',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor. Business justification: Feed supplier identity per delivery is required for vendor performance scorecarding (on-time delivery, fill rate), FSMA preventive controls traceability, and feed recall response. Linking feed_deliver',
    `animal_count_fed` STRING COMMENT 'Number of animals present in the pen or group at the time of feed delivery. Used to calculate per-head feed intake, normalize FCR (Feed Conversion Ratio) metrics, and detect anomalies in feed allocation relative to group size.',
    `bunk_score` STRING COMMENT 'Standardized numeric score (typically 0–4 scale) assessing the amount of feed remaining in the bunk at the time of delivery or pre-delivery inspection. Score 0 = empty/slick bunk; Score 4 = heavy refusal. Used to calibrate next delivery quantity and monitor animal appetite and health status.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the feed delivery record was first captured in the system. Used for audit trail and data lineage tracking.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for the feed cost amounts recorded in this delivery (e.g., USD, EUR, BRL). Supports multi-currency operations for global agriculture enterprises.. Valid values are `^[A-Z]{3}$`',
    `delivery_method` STRING COMMENT 'Method used to deliver feed to the pen or group. Options include TMR (Total Mixed Ration) mixer wagon, bunk feeder, automated feeding system, hand delivery, or conveyor. Affects feed uniformity, labor cost allocation, and equipment utilization tracking.. Valid values are `tmr_mixer|bunk_feeder|automated_system|hand_delivery|conveyor`',
    `delivery_notes` STRING COMMENT 'Free-text field for operator observations, exceptions, or special conditions recorded at the time of feed delivery (e.g., equipment malfunction, animal behavior observations, ingredient substitutions). Supports SOP (Standard Operating Procedure) deviation documentation and veterinary review.',
    `delivery_number` STRING COMMENT 'Externally-known business identifier for the feed delivery event, used for cross-referencing with feed management systems, SAP production orders, and operator logs. Follows the format FD-YYYY-NNNNNN.. Valid values are `^FD-[0-9]{4}-[0-9]{6}$`',
    `delivery_sequence` STRING COMMENT 'Sequential order number of this delivery within the daily feeding schedule (e.g., 1st feeding, 2nd feeding). Supports multi-feeding-per-day operations, feeding frequency analysis, and nutritional timing compliance.',
    `delivery_status` STRING COMMENT 'Current lifecycle status of the feed delivery event, tracking progression from scheduled through completion or cancellation. Supports operational monitoring and FCR (Feed Conversion Ratio) completeness checks.. Valid values are `scheduled|in_progress|completed|cancelled|partial`',
    `delivery_timestamp` TIMESTAMP COMMENT 'The principal real-world date and time when the feed delivery event occurred at the pen or group location. Used for feed scheduling compliance, nutritional timing analysis, and FCR (Feed Conversion Ratio) tracking.',
    `delivery_variance_kg` DECIMAL(18,2) COMMENT 'Difference between the prescribed quantity and the actual quantity delivered on an as-fed basis, in kilograms (actual minus prescribed). Positive values indicate over-delivery; negative values indicate under-delivery. Used for nutritional compliance verification and ration adherence KPI (Key Performance Indicator) reporting.',
    `dry_matter_pct` DECIMAL(18,2) COMMENT 'Dry matter percentage of the delivered ration at the time of delivery, expressed as a percentage. Used to convert as-fed quantities to dry matter basis and to verify ration moisture content against the prescribed formulation.',
    `feed_cost_per_kg` DECIMAL(18,2) COMMENT 'Unit cost of the delivered feed ration per kilogram on an as-fed basis, sourced from the feed inventory lot or procurement record. Used for feed cost allocation per animal group, COGS (Cost of Goods Sold) calculation, and financial reporting in SAP S/4HANA CO module.',
    `feed_source_type` STRING COMMENT 'Classification of the feed source for this delivery. Indicates whether the ration was mixed on-farm (TMR), purchased as a complete feed, custom-mixed by a feed mill, or derived from co-products. Supports feed cost analysis, supply chain traceability, and GLOBALG.A.P. compliance.. Valid values are `on_farm_mixed|purchased_complete|custom_mixed|co_product`',
    `gmo_status` STRING COMMENT 'Indicates whether the feed ration delivered contains GMO (Genetically Modified Organism) ingredients, is certified non-GMO, or has unknown GMO status. Required for USDA National Organic Program (NOP) compliance, GLOBALG.A.P. certification, and customer supply chain transparency reporting.. Valid values are `gmo|non_gmo|unknown`',
    `is_medicated_feed` BOOLEAN COMMENT 'Indicates whether the delivered ration contains a medicated additive subject to FDA Veterinary Feed Directive (VFD) or APHIS withdrawal period requirements. When True, triggers mandatory withdrawal period tracking and regulatory documentation requirements.',
    `mixing_duration_min` STRING COMMENT 'Duration in minutes that the TMR (Total Mixed Ration) mixer was operated to prepare the ration batch prior to delivery. Mixing time affects ration uniformity and particle size distribution; tracked for GMP (Good Manufacturing Practices) compliance and equipment OEE (Overall Equipment Effectiveness) analysis.',
    `organic_certified` BOOLEAN COMMENT 'Indicates whether the delivered feed ration is certified organic under the USDA National Organic Program (NOP). When True, the feed must originate from certified organic sources and the delivery must be documented for NOP audit compliance.',
    `prescribed_quantity_asfed_kg` DECIMAL(18,2) COMMENT 'The ration-prescribed target quantity of feed to be delivered on an as-fed basis, in kilograms. Compared against actual quantity delivered to calculate delivery variance and assess nutritional compliance against the prescribed ration.',
    `quantity_delivered_asfed_kg` DECIMAL(18,2) COMMENT 'Total weight of feed delivered to the pen or group on an as-fed basis, measured in kilograms. As-fed weight includes moisture content and is the primary operational quantity recorded at delivery. Used for feed cost allocation and FCR (Feed Conversion Ratio) calculations.',
    `quantity_delivered_dm_kg` DECIMAL(18,2) COMMENT 'Total weight of feed delivered expressed on a dry matter (DM) basis, measured in kilograms. Dry matter quantity normalizes for moisture variation across ration ingredients and is the standard basis for nutritional compliance verification and FCR (Feed Conversion Ratio) analysis.',
    `ration_name` STRING COMMENT 'Human-readable name or description of the feed ration delivered (e.g., Grower Phase 2 TMR, Lactating Cow Ration). Provides operational context for operators and supports reporting without requiring a ration master lookup.',
    `refusal_quantity_kg` DECIMAL(18,2) COMMENT 'Weight of feed remaining uneaten in the bunk or feeder at the time of the next delivery or scheduled bunk reading, measured in kilograms. Refusal data is critical for adjusting ration delivery amounts, monitoring animal health, and calculating net intake for FCR (Feed Conversion Ratio) analysis.',
    `scheduled_delivery_timestamp` TIMESTAMP COMMENT 'The planned date and time for the feed delivery as defined in the feeding schedule. Compared against actual delivery_timestamp to calculate delivery timing variance and assess adherence to the nutritional management plan.',
    `source_system_code` STRING COMMENT 'Code identifying the operational system of record from which this feed delivery record originated (e.g., SAP S/4HANA PP, Granular Farm Management, Climate FieldView, Trimble Ag Software, or manual entry). Supports data lineage, Silver Layer reconciliation, and audit trail requirements.. Valid values are `SAP|GRANULAR|FIELDVIEW|TRIMBLE|MANUAL`',
    `total_feed_cost` DECIMAL(18,2) COMMENT 'Total cost of feed delivered in this event, calculated as quantity_delivered_asfed_kg multiplied by feed_cost_per_kg. Used for feed cost allocation per pen/group, COGS (Cost of Goods Sold) reporting, and EBITDA analysis. Stored as a transactional fact to preserve the cost at time of delivery.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when the feed delivery record was last modified. Supports audit trail, data quality monitoring, and change detection in the Silver Layer.',
    `vfd_number` STRING COMMENT 'The FDA Veterinary Feed Directive (VFD) authorization number associated with the medicated feed delivered. Required for regulatory compliance when is_medicated_feed is True. Supports APHIS and FSIS audit traceability.',
    `withdrawal_period_end_date` DATE COMMENT 'The date after which animals that received medicated feed are eligible for harvest, calculated from the delivery date plus the required withdrawal period for the active ingredient (AI). Critical for FSIS pre-harvest compliance and antibiotic residue avoidance.',
    CONSTRAINT pk_feed_delivery PRIMARY KEY(`feed_delivery_id`)
) COMMENT 'Transactional record of each feed delivery event to a pen or group. Captures delivery date and time, pen/group ID, ration ID, quantity delivered (lbs/kg as-fed and dry matter), delivery method (TMR mixer, bunk feeder, automated system), operator, refusal amount recorded, and feed bunk score. Enables feed cost allocation per animal, FCR tracking, and nutritional compliance verification against prescribed rations.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`livestock`.`animal_movement` (
    `animal_movement_id` BIGINT COMMENT 'Unique system-generated identifier for each animal or group movement transaction record. Primary key for the animal_movement data product.',
    `animal_id` BIGINT COMMENT 'Reference to the individual animal record being moved. Populated for individual animal movements; null for group/lot movements where group_id is used instead.',
    `asset_id` BIGINT COMMENT 'Reference to the transport vehicle or trailer used for this movement. Supports biosecurity cleaning and disinfection tracking, and fleet telematics integration with John Deere Operations Center.',
    `bill_of_lading_id` BIGINT COMMENT 'Foreign key linking to supply.bill_of_lading. Business justification: Interstate livestock movements require a legal Bill of Lading for USDA/APHIS compliance, brand inspection, and chain-of-custody. Replacing denormalized bol_number with bill_of_lading_id provides a pro',
    `carrier_id` BIGINT COMMENT 'Foreign key linking to supply.carrier. Business justification: Livestock transport uses approved carriers with FSMA Sanitary Transport certification. Linking animal_movement to carrier enables carrier performance tracking, sanitary transport compliance verificati',
    `contract_id` BIGINT COMMENT 'Foreign key linking to sales.contract. Business justification: Interstate and export animal movements are executed under specific sales contracts. Linking movement to contract supports contract fulfillment tracking, USDA/APHIS interstate movement compliance, and ',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Inter-facility animal movements incur transport costs and trigger inter-entity cost transfers requiring cost center assignment. Livestock operations track movement costs by cost center for freight exp',
    `crew_id` BIGINT COMMENT 'Foreign key linking to workforce.crew. Business justification: Sorting, loading, and shipping livestock are crew activities. animal_movement has driver_employee_id but no crew_id. Crew-level movement tracking supports labor cost allocation per movement event and ',
    `delivery_order_id` BIGINT COMMENT 'Foreign key linking to sales.delivery_order. Business justification: When sold livestock are transported to a buyers facility, the animal movement record corresponds to a sales delivery order. Linking these enables BOL reconciliation, proof-of-delivery confirmation, a',
    `delivery_location_id` BIGINT COMMENT 'Foreign key linking to customer.delivery_location. Business justification: FSMA traceability and chain-of-custody require linking animal transport records to the customers specific receiving delivery location (with FSMA registration number, dock details, receiving hours). A',
    `facility_id` BIGINT COMMENT 'Reference to the location (pen, pasture, barn, facility, or external premises) to which the animal or group was moved. Used for biosecurity zone tracking and APHIS traceability.',
    `destination_premises_facility_id` BIGINT COMMENT 'USDA-registered premises identification number (PIN) for the destination location. Required for inter-premises movements under APHIS Animal Disease Traceability rule. Format follows USDA National Premises Information Repository (NPIR) standard.',
    `employee_id` BIGINT COMMENT 'Reference to the employee or contractor who drove the transport vehicle for this movement. Used for workforce accountability and chain-of-custody documentation.',
    `field_crop_plan_id` BIGINT COMMENT 'Foreign key linking to crop.field_crop_plan. Business justification: When animals are moved onto crop fields for residue or cover crop grazing, operators must verify the field crop plan for active PHI/REI restrictions from recent pesticide applications. This is a named',
    `pen_location_id` BIGINT COMMENT 'Foreign key linking to livestock.pen_location. Business justification: Animal movements have an origin pen location (the pen animals are moved FROM within the facility). Linking animal_movement to pen_location via from_pen_location_id enables pen occupancy tracking, move',
    `herd_id` BIGINT COMMENT 'Foreign key linking to livestock.herd. Business justification: Animal movements are associated with a specific herd — animals being moved belong to a herd, and the movement event should reference that herd for traceability, regulatory reporting (APHIS premises-to',
    `inspection_id` BIGINT COMMENT 'Foreign key linking to quality.inspection. Business justification: Interstate animal movements require USDA/state veterinary health inspections and brand inspections. animal_movement has veterinary_health_cert_number, brand_inspection_number, interstate_movement. Lin',
    `lab_sample_id` BIGINT COMMENT 'Foreign key linking to quality.lab_sample. Business justification: Interstate animal movement requires official lab test results (TB test, Brucellosis serology, EIA Coggins test) as prerequisites for health certificates. USDA APHIS regulations mandate these tests. A ',
    `lot_trace_id` BIGINT COMMENT 'Foreign key linking to supply.lot_trace. Business justification: FSMA Traceability Rule and USDA animal traceability programs require linking animal movement events to lot trace records for forward/backward traceability in disease outbreak or food safety investigat',
    `primary_animal_facility_id` BIGINT COMMENT 'Reference to the location (pen, pasture, barn, facility, or external premises) from which the animal or group departed. Used for biosecurity zone tracking and APHIS traceability.',
    `order_id` BIGINT COMMENT 'Foreign key linking to sales.order. Business justification: Animal movements to packing plants or feedlots are triggered by sales orders. Linking movement to sales order supports order fulfillment tracking, logistics scheduling, and USDA/APHIS movement documen',
    `shipment_id` BIGINT COMMENT 'Foreign key linking to supply.shipment. Business justification: Commercial livestock movements (sale to packer, interstate transfer) are executed as supply chain shipments. Linking animal_movement to shipment enables FSMA traceability, COOL documentation, and carr',
    `transport_order_id` BIGINT COMMENT 'Foreign key linking to supply.transport_order. Business justification: Livestock transport requires carrier assignment, route planning, and equipment scheduling via transport orders. Linking animal_movement to transport_order enables FSMA Sanitary Transport compliance tr',
    `transport_unit_id` BIGINT COMMENT 'Foreign key linking to supply.transport_unit. Business justification: The specific trailer used for livestock transport is tracked for FSMA Sanitary Transportation compliance (cleaning/disinfection records between loads), animal welfare audits, and biosecurity investiga',
    `weight_ticket_id` BIGINT COMMENT 'Foreign key linking to invoice.weight_ticket. Business justification: Animal movements to sale barns, feedlots, or packing plants generate weight tickets at the destination documenting head count and weight for commercial settlement. Linking animal_movement to weight_ti',
    `average_weight_kg` DECIMAL(18,2) COMMENT 'Average live weight in kilograms of animals in this movement at time of loading. Used for transport payload calculations, sale weight documentation, and performance benchmarking against YPM (Yield Per Acre Metric) targets.',
    `biosecurity_zone_crossing` BOOLEAN COMMENT 'Indicates whether this movement crosses a defined biosecurity zone boundary. True triggers mandatory cleaning and disinfection (C&D) protocols for transport vehicles and equipment per APHIS biosecurity guidelines.',
    `brand_inspection_number` STRING COMMENT 'State brand inspection certificate number issued for livestock movements in brand-law states. Required for cattle and horse movements in western US states to verify ownership and prevent theft.',
    `cool_country_of_origin` STRING COMMENT 'ISO 3166-1 alpha-3 country code representing the country of origin for COOL (Country of Origin Labeling) compliance. Required for covered commodities sold at retail under USDA AMS COOL regulations.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this movement record was first created in the system. Used for audit trail, data lineage, and FSMA record-keeping compliance (records must be maintained for 2 years).',
    `destination_state_code` STRING COMMENT 'Two-letter US state code for the destination location of this movement. Required for APHIS interstate movement reporting and COOL compliance documentation.. Valid values are `^[A-Z]{2}$`',
    `head_count_arrived` STRING COMMENT 'Actual number of animals confirmed received at the destination location upon arrival. May differ from head_count_moved due to in-transit mortality or escapes. Used for shrink calculation and inventory reconciliation.',
    `head_count_moved` STRING COMMENT 'Number of individual animals included in this movement transaction. For individual animal movements this is 1; for group movements this reflects the total head count transferred. Critical for inventory reconciliation and APHIS traceability.',
    `health_cert_expiry_date` DATE COMMENT 'Expiration date of the veterinary health certificate accompanying this movement. Movements occurring after this date are non-compliant with APHIS interstate movement regulations.',
    `interstate_movement` BOOLEAN COMMENT 'Indicates whether this movement crosses state lines. True triggers mandatory APHIS official identification and Certificate of Veterinary Inspection (CVI) requirements under the Animal Disease Traceability rule.',
    `movement_date` DATE COMMENT 'The calendar date on which the animal or group movement physically occurred. Principal business event date used for APHIS traceability reporting, COOL compliance, and withdrawal period calculations.',
    `movement_notes` STRING COMMENT 'Free-text field for operational notes, special handling instructions, or observations recorded at time of movement. May include animal condition observations, loading difficulties, or regulatory exceptions noted by the handler.',
    `movement_reason` STRING COMMENT 'Business reason or purpose for the animal or group movement. Drives downstream processing workflows, APHIS reporting categories, and biosecurity zone management. [ENUM-REF-CANDIDATE: weaning|backgrounding|feedlot_placement|sale|harvest|death|breeding|health_treatment|pasture_rotation|quarantine — promote to reference product]',
    `movement_reference_number` STRING COMMENT 'Externally-known business identifier for this movement transaction, used for cross-referencing with transport documents, USDA premises records, and operational systems such as SAP S/4HANA livestock movement orders. Serves as the human-readable transaction code.',
    `movement_status` STRING COMMENT 'Current lifecycle state of the movement transaction. Tracks the workflow from planning through physical completion, supporting operational visibility and exception management.. Valid values are `planned|in_transit|completed|cancelled|pending_inspection`',
    `movement_timestamp` TIMESTAMP COMMENT 'Precise date and time when the animal or group movement was initiated or completed, captured from FMIS or IoT gate sensors. Provides sub-day precision for biosecurity event sequencing and audit trails.',
    `movement_type` STRING COMMENT 'Classification of the movement scope: internal (within same premises), inter-premises (between registered USDA premises), external sale (to buyer), or external purchase (from seller). Determines APHIS reporting obligations and COOL documentation requirements.. Valid values are `internal|inter_premises|external_sale|external_purchase`',
    `official_id_number` STRING COMMENT 'The official identification number (e.g., RFID tag number, ear tag number, brand registration number) recorded at time of movement. Required for APHIS interstate movement documentation and disease traceability investigations.',
    `official_id_type` STRING COMMENT 'Type of official animal identification applied or verified at time of movement. RFID (Radio Frequency Identification) ear tags are the USDA-approved official identification for interstate movements under ADT rule.. Valid values are `RFID|ear_tag|brand|tattoo|microchip|none`',
    `origin_state_code` STRING COMMENT 'Two-letter US state code for the origin location of this movement. Required for APHIS interstate movement reporting, COOL country/state of origin labeling, and state brand inspection compliance.. Valid values are `^[A-Z]{2}$`',
    `species_code` STRING COMMENT 'Standardized species classification of the animals being moved. Used for APHIS species-specific traceability requirements, FSIS inspection routing, and biosecurity protocol selection. [ENUM-REF-CANDIDATE: BOVINE|SWINE|OVINE|CAPRINE|EQUINE|POULTRY|OTHER — 7 candidates stripped; promote to reference product]',
    `total_weight_kg` DECIMAL(18,2) COMMENT 'Total live weight in kilograms of all animals in this movement at time of loading. Used for transport billing, sale contracts, and FSIS ante-mortem documentation.',
    `transport_distance_km` DECIMAL(18,2) COMMENT 'Total distance in kilometers traveled during this movement. Used for animal welfare compliance (EU transport regulations, USDA 28-Hour Law), transport cost allocation, and carbon footprint reporting.',
    `transport_duration_hours` DECIMAL(18,2) COMMENT 'Total hours animals were in transit during this movement. Critical for USDA 28-Hour Law compliance (animals must be unloaded for rest, water, and feed after 28 consecutive hours of transport) and animal welfare audits.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this movement record was last modified. Supports audit trail requirements, data quality monitoring, and change detection in the Databricks Silver Layer pipeline.',
    `vehicle_license_plate` STRING COMMENT 'License plate number of the transport vehicle or trailer used for this movement. Recorded for biosecurity traceability, DOT compliance, and chain-of-custody documentation when the vehicle is not registered in the fleet asset system.',
    `veterinary_health_cert_number` STRING COMMENT 'Certificate of Veterinary Inspection (CVI) or health certificate number issued by an accredited veterinarian for interstate or international movements. Required by APHIS for regulated species and disease-control movements.',
    `withdrawal_period_active` BOOLEAN COMMENT 'Indicates whether any animal in this movement is currently within an antibiotic or chemical withdrawal period (Pre-Harvest Interval - PHI). True prevents movement to harvest facilities and triggers FSIS compliance holds. Supports antibiotic stewardship and FSMA compliance.',
    CONSTRAINT pk_animal_movement PRIMARY KEY(`animal_movement_id`)
) COMMENT 'Transactional record of every animal or group movement between pens, pastures, facilities, or external premises. Captures movement date, animal or group ID, origin location, destination location, movement reason (weaning, backgrounding, feedlot placement, sale, harvest, death), head count moved, transport vehicle ID, driver, and USDA premises ID for inter-premises moves. Supports APHIS traceability, COOL compliance, and biosecurity zone management.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`livestock`.`animal_disposition` (
    `animal_disposition_id` BIGINT COMMENT 'Primary key for animal_disposition',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Animal disposition (harvest/slaughter) records must reference the packer/processor as a customer account for FSMA traceability, COOL compliance, and accounts receivable. Farm-to-processor traceability',
    `animal_id` BIGINT COMMENT 'Reference to the individual animal record in the livestock master. Links this disposition event to the animals full lifecycle history including breeding, health, and feed records.',
    `invoice_id` BIGINT COMMENT 'Foreign key linking to invoice.invoice. Business justification: Animal disposition events (harvest sales, salvage sales) generate AR invoices. The disposition record captures salvage_sale_value, requiring a link to the billing document for AR reconciliation and li',
    `asset_id` BIGINT COMMENT 'Foreign key linking to equipment.asset. Business justification: Animal disposition events (slaughter, loading for sale) use tracked equipment assets (loading chutes, scales, stunning equipment). USDA/FSIS regulations require equipment inspection records tied to di',
    `billing_account_id` BIGINT COMMENT 'Foreign key linking to invoice.billing_account. Business justification: The packer or buyer billing account must be linked to animal disposition for AR aging, credit limit enforcement, and receivables management. The existing ar_invoice_id covers the invoice but not the b',
    `broker_id` BIGINT COMMENT 'Foreign key linking to sales.broker. Business justification: Livestock dispositions (sales) are frequently facilitated by licensed livestock brokers. Linking disposition to broker supports commission calculation, broker performance reporting, and 1099 tax repor',
    `certificate_of_analysis_id` BIGINT COMMENT 'Foreign key linking to quality.certificate_of_analysis. Business justification: Slaughter disposition generates a COA documenting residue compliance, pathogen testing, and carcass quality for food safety release. Export markets require COAs linked to individual animal disposition',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: Slaughter disposition produces a specific commodity output (fed beef, market hogs). Linking to product.commodity enables USDA yield reporting, commodity-class pricing, HS tariff code assignment for ex',
    `commodity_lot_id` BIGINT COMMENT 'Foreign key linking to inventory.commodity_lot. Business justification: Farm-to-table traceability and USDA/FSIS compliance require linking each animal disposition (harvest) to the resulting commodity lot in inventory. Enables carcass yield reconciliation, antibiotic with',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: Animal dispositions (sales, deaths, culls) are legal-entity-level financial events requiring company code assignment for statutory financial reporting, intercompany elimination, and USDA/FSA program c',
    `contract_id` BIGINT COMMENT 'Foreign key linking to sales.contract. Business justification: Animal dispositions (slaughter, sale) are executed against specific sales contracts. Traceability from individual disposition to the governing contract is required for contract fulfillment reporting, ',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Mortality and condemnation events are significant cost items in livestock operations. Cost center assignment on animal_disposition supports mortality cost reporting by herd/facility, insurance claim d',
    `crew_id` BIGINT COMMENT 'Foreign key linking to workforce.crew. Business justification: Harvest and euthanasia events involve dedicated crews. animal_disposition has individual employee FKs but no crew_id. Crew-level disposition tracking supports labor cost allocation at harvest and anim',
    `delivery_location_id` BIGINT COMMENT 'Foreign key linking to customer.delivery_location. Business justification: Disposition records reference the specific processing establishment (USDA-inspected facility) where harvest occurs. Linking to customer.delivery_location (which carries usda_establishment_number and f',
    `delivery_order_id` BIGINT COMMENT 'Foreign key linking to sales.delivery_order. Business justification: When animals are disposed (sold/transferred to packer), a delivery order governs the physical handoff. Linking disposition to delivery_order enables end-to-end traceability from individual animal to d',
    `facility_id` BIGINT COMMENT 'Reference to the facility (farm, feedlot, slaughter plant, or processing facility) where the disposition event occurred. Required for FSIS establishment-level reporting.',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Animal dispositions (death loss, condemnation, harvest) require GL postings to inventory write-down, mortality loss, or COGS accounts. GAAP and USDA reporting require proper GL classification of dispo',
    `grading_standard_id` BIGINT COMMENT 'Foreign key linking to product.grading_standard. Business justification: USDA AMS grading compliance requires linking each carcass disposition record to the applicable grading_standard that defines USDA quality/yield grade criteria. Enables grade-based pricing, USDA shield',
    `herd_id` BIGINT COMMENT 'Reference to the herd or flock group from which the animal originated at the time of disposition. Supports traceability and group-level regulatory reporting.',
    `inspection_id` BIGINT COMMENT 'Foreign key linking to quality.inspection. Business justification: USDA ante-mortem and post-mortem inspections at harvest are formal inspection events. animal_disposition captures usda_quality_grade, usda_yield_grade, condemnation_reason_code — all outputs of the go',
    `lab_sample_id` BIGINT COMMENT 'Foreign key linking to quality.lab_sample. Business justification: USDA FSIS residue testing at slaughter (NRMP program) and carcass condemnation pathology samples are collected at disposition. A domain expert expects animal_disposition to reference the residue/patho',
    `lot_trace_id` BIGINT COMMENT 'Foreign key linking to supply.lot_trace. Business justification: Animal harvest creates a supply chain lot trace record for the resulting carcass/product lot. Linking animal_disposition to lot_trace enables farm-to-harvest traceability required by FSMA, COOL, and f',
    `nonconformance_id` BIGINT COMMENT 'Foreign key linking to quality.nonconformance. Business justification: Condemned carcasses, failed withdrawal compliance, and carcass condemnation_reason_code directly generate nonconformance records. USDA FSIS post-mortem inspection outcomes require formal nonconformanc',
    `price_agreement_id` BIGINT COMMENT 'Foreign key linking to sales.price_agreement. Business justification: Animal sale prices are governed by price agreements (formula pricing, grid pricing). Linking disposition to price_agreement enables accurate revenue calculation, price compliance auditing, and settlem',
    `price_basis_id` BIGINT COMMENT 'Foreign key linking to invoice.price_basis. Business justification: Animal disposition pricing (per-cwt live, dressed weight, yield-grade premiums) is governed by a price basis record. Linking disposition to price_basis enables accurate carcass valuation, grade-based ',
    `employee_id` BIGINT COMMENT 'Reference to the FSIS or USDA-accredited veterinary inspector who conducted ante-mortem and/or post-mortem inspection. Required for regulatory audit trail and inspection record integrity.',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Animal disposition events (cull sales, death losses, harvest) are the primary revenue and loss recognition events in livestock operations. Profit center attribution on dispositions is required for liv',
    `order_id` BIGINT COMMENT 'Foreign key linking to sales.order. Business justification: FSMA Subpart S traceability requires linking harvest/disposition records to sales orders for carcass lot tracking. When an animal is harvested and sold, the disposition record must reference the sales',
    `settlement_statement_id` BIGINT COMMENT 'Foreign key linking to invoice.settlement_statement. Business justification: Packer settlement statements reconcile animal dispositions — documenting carcass weights, quality grades, premiums/discounts, and net proceeds per head. Linking disposition directly to settlement_stat',
    `shipment_id` BIGINT COMMENT 'Foreign key linking to supply.shipment. Business justification: Harvest/disposition events where animals ship to a packer are executed as supply chain shipments. Linking animal_disposition to shipment enables carcass traceability, COOL documentation, packer settle',
    `weight_ticket_id` BIGINT COMMENT 'Foreign key linking to invoice.weight_ticket. Business justification: Animal disposition (slaughter/sale) generates a commercial weight ticket documenting hot carcass weight or live weight at point of sale. This weight ticket is the basis for packer/buyer settlement and',
    `age_days` STRING COMMENT 'Age of the animal in days at the time of disposition, calculated from birth date. Used for regulatory age-at-slaughter compliance (e.g., veal, bob veal), carcass quality grading, and performance benchmarking.',
    `antibiotic_withdrawal_compliant` BOOLEAN COMMENT 'Indicates whether all antibiotic and veterinary drug withdrawal periods were satisfied prior to harvest. Critical food safety compliance flag. False triggers mandatory hold and regulatory notification under FSIS residue testing protocols.',
    `aphis_report_number` STRING COMMENT 'Official USDA APHIS report number assigned when this disposition event triggers a mandatory regulatory notification (e.g., foreign animal disease suspicion, mass mortality event). Null if no APHIS report was required.',
    `breed_code` STRING COMMENT 'Standardized breed identifier for the animal. Relevant for carcass quality grading, yield prediction, and genetic performance analytics. Sourced from the animal master record at time of disposition.',
    `carcass_disposition_code` STRING COMMENT 'FSIS post-mortem inspection outcome for the carcass. Passed indicates approved for human consumption; condemned indicates rejected and must be destroyed or rendered; retained indicates held pending further inspection.. Valid values are `passed|condemned|retained|passed_with_trim|emergency_passed`',
    `cause_of_death_code` STRING COMMENT 'Standardized veterinary code identifying the primary cause of death for non-harvest disposition types (natural death, euthanasia, condemnation). Null for planned harvest events. [ENUM-REF-CANDIDATE: respiratory_disease|digestive_disorder|injury_trauma|metabolic_disorder|infectious_disease|unknown — promote to reference product]',
    `cause_of_death_description` STRING COMMENT 'Free-text veterinary narrative describing the cause of death or reason for condemnation. Supplements the standardized cause_of_death_code with clinical detail for mortality investigations and APHIS reporting.',
    `condemnation_reason_code` STRING COMMENT 'Standardized FSIS code identifying the regulatory reason for carcass condemnation. Null for passed carcasses. Required for FSIS annual condemnation reporting and food safety analytics. [ENUM-REF-CANDIDATE: septicemia|pneumonia|peritonitis|abscess|contamination|bruising|cancer|other — promote to reference product]',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this disposition record was first created in the system. Provides the audit trail entry point for data lineage, SOX compliance, and regulatory record retention requirements.',
    `disposition_date` DATE COMMENT 'Calendar date on which the terminal disposition event occurred. Used as the principal business event date for regulatory reporting, withdrawal period compliance, and financial period allocation.',
    `disposition_number` STRING COMMENT 'Externally-known business identifier for this disposition event, used in regulatory submissions, veterinary records, and supply chain documentation. Formatted as DISP-YYYY-NNNNNN.. Valid values are `^DISP-[0-9]{4}-[0-9]{6}$`',
    `disposition_status` STRING COMMENT 'Current workflow state of the disposition record. Tracks progression from initial capture through regulatory reporting completion. Pending indicates awaiting inspection; condemned indicates regulatory rejection of carcass.. Valid values are `pending|completed|condemned|under_review|reported`',
    `disposition_timestamp` TIMESTAMP COMMENT 'Precise date and time at which the terminal disposition event was executed. Required for Pre-Harvest Interval (PHI) and Restricted Entry Interval (REI) compliance calculations and ante-mortem inspection sequencing.',
    `disposition_type` STRING COMMENT 'Classification of the terminal lifecycle event. Determines downstream regulatory reporting obligations, carcass handling procedures, and financial treatment. [ENUM-REF-CANDIDATE: harvest|natural_death|euthanasia|condemnation|salvage_sale|emergency_slaughter — promote to reference product if additional types are needed]. Valid values are `harvest|natural_death|euthanasia|condemnation|salvage_sale|emergency_slaughter`',
    `dressing_yield_pct` DECIMAL(18,2) COMMENT 'Ratio of hot carcass weight to live weight expressed as a percentage. Key performance indicator for harvest efficiency and carcass value. Calculated as (hot_carcass_weight_kg / live_weight_kg) * 100.',
    `ear_tag_number` STRING COMMENT 'Visual ear tag identifier affixed to the animal. Used as the primary visual identification method at harvest facilities and for manual reconciliation against RFID records. May differ from RFID if tag was replaced.',
    `establishment_number` STRING COMMENT 'USDA FSIS-assigned official establishment number for the slaughter or processing facility. Required on all FSIS regulatory submissions, labels, and inspection records. Distinct from internal facility_id.. Valid values are `^[0-9]{3,6}[A-Z]?$`',
    `hot_carcass_weight_kg` DECIMAL(18,2) COMMENT 'Weight of the carcass immediately after slaughter and evisceration, before chilling, expressed in kilograms. Primary basis for yield calculations, grading, and producer payment in harvest events.',
    `last_treatment_date` DATE COMMENT 'Date of the most recent veterinary drug or antibiotic treatment administered to the animal prior to disposition. Used to verify withdrawal period compliance and calculate days-off-drug at time of harvest.',
    `last_treatment_drug` STRING COMMENT 'Name of the most recent veterinary drug or antibiotic administered to the animal. Used in conjunction with last_treatment_date to verify withdrawal period compliance against FDA-approved withdrawal intervals.',
    `live_weight_kg` DECIMAL(18,2) COMMENT 'Live body weight of the animal recorded at the time of ante-mortem inspection or mortality event, expressed in kilograms. Used for yield calculations, payment settlement, and performance analytics.',
    `necropsy_findings` STRING COMMENT 'Summary of pathological findings from the post-mortem examination. Documents lesions, disease conditions, and contributing factors identified during necropsy. Supports disease surveillance and herd health management.',
    `necropsy_performed` BOOLEAN COMMENT 'Indicates whether a post-mortem examination (necropsy) was conducted on the animal. Required for APHIS disease surveillance reporting and mortality investigation protocols.',
    `phi_days_required` STRING COMMENT 'Number of days required between last drug treatment and harvest as specified on the drug label or veterinary prescription. Used to calculate and verify withdrawal period compliance at time of disposition.',
    `regulatory_report_date` DATE COMMENT 'Date on which the disposition event was officially reported to the regulatory authority. Used to verify timely reporting compliance with FSIS and APHIS notification deadlines.',
    `regulatory_reported` BOOLEAN COMMENT 'Indicates whether this disposition event has been submitted to the applicable regulatory authority (FSIS, APHIS, or state agency). Supports compliance monitoring and audit readiness.',
    `rfid_tag_number` STRING COMMENT 'RFID electronic identifier read at the time of disposition. Provides automated, tamper-resistant animal identification at harvest or mortality processing points. Supports USDA 840 official identification requirements.',
    `salvage_sale_value` DECIMAL(18,2) COMMENT 'Monetary value received for the animal or carcass in a salvage sale disposition. Applicable only when disposition_type is salvage_sale. Used for financial loss recovery accounting and insurance claim support.',
    `sex_code` STRING COMMENT 'Sex classification of the animal at disposition: M=Male (intact), F=Female, C=Castrated male, S=Spayed female. Affects carcass grading, yield estimates, and USDA quality grade assignment.. Valid values are `M|F|C|S`',
    `species_code` STRING COMMENT 'Standardized species classification of the animal at disposition. Drives applicable regulatory framework (FSIS vs. APHIS), slaughter inspection requirements, and carcass grading standards.. Valid values are `BOVINE|SWINE|OVINE|CAPRINE|POULTRY|EQUINE`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this disposition record. Supports audit trail integrity, data lineage tracking, and change detection in the Databricks Silver Layer pipeline.',
    `usda_quality_grade` STRING COMMENT 'Official USDA quality grade assigned to the carcass based on marbling, maturity, and other palatability factors. Drives pricing, market channel selection, and producer premium payments. Applicable primarily to beef. [ENUM-REF-CANDIDATE: Prime|Choice|Select|Standard|Commercial|Utility|Cutter|Canner — 8 candidates stripped; promote to reference product]',
    `usda_yield_grade` DECIMAL(18,2) COMMENT 'Numerical USDA yield grade (1.0–5.9) indicating the estimated percentage of boneless, closely trimmed retail cuts from the round, loin, rib, and chuck. Lower values indicate higher cutability. Used for pricing and market channel decisions.',
    CONSTRAINT pk_animal_disposition PRIMARY KEY(`animal_disposition_id`)
) COMMENT 'Transactional record capturing every terminal animal lifecycle event — including harvest (slaughter), natural death, euthanasia, condemnation, and sale for salvage. Records disposition date, animal ID, disposition type, cause of death (for mortality events), necropsy results, carcass disposition, and regulatory reporting status.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`livestock`.`veterinary_prescription` (
    `veterinary_prescription_id` BIGINT COMMENT 'Unique system-generated identifier for each veterinary prescription or Veterinary Feed Directive (VFD) record. Serves as the primary key for the veterinary_prescription data product.',
    `animal_id` BIGINT COMMENT 'Reference to the specific animal or group of animals for which the prescription was issued. Links to the livestock animal master record.',
    `employee_id` BIGINT COMMENT 'Reference to the licensed veterinarian (DVM) who issued the prescription. Required for VCPR validation and FDA VFD compliance.',
    `facility_id` BIGINT COMMENT 'Foreign key linking to supply.facility. Business justification: FDA VFD regulations require veterinary prescriptions (especially VFDs) to be associated with a specific premises/facility and kept on file there. A facility_id FK enables regulatory compliance reporti',
    `health_protocol_id` BIGINT COMMENT 'Foreign key linking to livestock.health_protocol. Business justification: veterinary_prescription is issued in accordance with established health protocols. Linking veterinary_prescription.health_protocol_id → livestock.health_protocol.health_protocol_id enables protocol-le',
    `herd_id` BIGINT COMMENT 'Reference to the herd or flock for which the prescription applies when issued at the group level rather than individual animal level.',
    `input_catalog_id` BIGINT COMMENT 'Foreign key linking to procurement.input_catalog. Business justification: Prescribed drugs must be in the approved procurement input catalog with PHI, withdrawal, and EPA registration data. Linking veterinary_prescription to input_catalog enforces approved formulary prescri',
    `lab_sample_id` BIGINT COMMENT 'Foreign key linking to quality.lab_sample. Business justification: Culture and sensitivity lab results are required to justify extra-label drug use and antibiotic selection under VCPR requirements. FDA VFD regulations and antibiotic stewardship programs require diagn',
    `material_master_id` BIGINT COMMENT 'Foreign key linking to inventory.material_master. Business justification: VFD and prescription compliance requires linking each veterinary prescription to the specific drug material_master for dispensing verification, quantity_authorized vs quantity_dispensed reconciliation',
    `purchase_order_id` BIGINT COMMENT 'Foreign key linking to procurement.purchase_order. Business justification: Veterinary prescriptions, especially VFDs, drive specific purchase orders for medicated feed or drugs. Linking veterinary_prescription to purchase_order enables prescription-to-procurement traceabilit',
    `vendor_contract_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor_contract. Business justification: Veterinary prescriptions drive pharmaceutical procurement under vendor contracts. Linking veterinary_prescription to vendor_contract enables formulary contract compliance, ensures prescribed drugs are',
    `animal_weight_kg` DECIMAL(18,2) COMMENT 'The average or representative body weight in kilograms of the animals at the time of prescription. Used for weight-based dosage calculations and to verify appropriate dosing.',
    `approved_species` STRING COMMENT 'The animal species for which the drug is approved and prescribed (e.g., cattle, swine, poultry, sheep, goats). Must align with FDA label approval or AMDUCA extra-label use authorization. [ENUM-REF-CANDIDATE: cattle|swine|poultry|sheep|goats|equine|aquaculture — promote to reference product]',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this veterinary prescription record was first created in the system. Used for audit trail, data lineage, and FSIS record retention compliance (VFD records must be retained for 2 years).',
    `dosage_amount` DECIMAL(18,2) COMMENT 'The numeric quantity of drug to be administered per dose or per unit of feed (e.g., grams per ton of feed, mg per kg body weight). The principal quantitative fact for this prescription.',
    `dosage_frequency` STRING COMMENT 'The frequency or schedule at which the prescribed drug is to be administered (e.g., once daily, continuous feed, single dose). Required on the prescription label per FDA regulations.. Valid values are `once_daily|twice_daily|every_48h|continuous_feed|single_dose|as_directed`',
    `dosage_unit` STRING COMMENT 'The unit of measure for the prescribed dosage amount (e.g., g/ton for medicated feed, mg/kg for injectable drugs). Required for accurate compounding and dispensing. [ENUM-REF-CANDIDATE: g/ton|mg/kg|mg/lb|g/head/day|oz/ton|ppm|mL/head — 7 candidates stripped; promote to reference product]',
    `drug_class` STRING COMMENT 'Antimicrobial or pharmacological class of the prescribed drug (e.g., tetracycline, macrolide, ionophore, beta-lactam). Used for antibiotic stewardship analytics and WHO critically important antimicrobial (CIA) classification tracking.',
    `dvm_license_number` STRING COMMENT 'The state-issued veterinary license number of the prescribing veterinarian (DVM). Required on all VFD documents per FDA regulation and for FSIS antibiotic stewardship audit trails.',
    `dvm_state` STRING COMMENT 'The US state in which the prescribing veterinarian holds their active license. Required for cross-state regulatory compliance verification.. Valid values are `^[A-Z]{2}$`',
    `egg_withdrawal_days` STRING COMMENT 'The number of days eggs must be withheld from sale following drug administration in laying poultry. Applicable only for poultry operations; null for non-poultry species.',
    `expiration_date` DATE COMMENT 'The date after which the prescription is no longer valid and the authorized drug or medicated feed may not be dispensed or used. FDA VFD regulations require an expiration date not to exceed 6 months from issue date for most VFDs.',
    `extra_label_use` BOOLEAN COMMENT 'Indicates whether this prescription involves extra-label drug use (use of an FDA-approved drug in a manner not specified on the approved label). Extra-label use requires a valid VCPR and is regulated under AMDUCA (Animal Medicinal Drug Use Clarification Act).',
    `indication` STRING COMMENT 'The disease, condition, or clinical indication for which the drug is being prescribed (e.g., bovine respiratory disease, necrotic enteritis, mastitis prevention). Required for VCPR documentation and FSIS antibiotic use justification.',
    `issue_date` DATE COMMENT 'The calendar date on which the veterinarian issued the prescription or VFD. This is the principal real-world event date for the prescription transaction and is required on all VFD documents per FDA regulation.',
    `milk_withdrawal_days` STRING COMMENT 'The number of days milk must be withheld from sale following drug administration in dairy animals. Separate from meat withdrawal period as milk and meat withdrawal periods often differ for the same drug.',
    `number_of_animals` STRING COMMENT 'The total count of animals covered under this prescription or VFD. Required on VFD documents per FDA regulation and used for dosage calculation and antibiotic use density metrics.',
    `prescription_number` STRING COMMENT 'Externally-known alphanumeric identifier assigned to the prescription or VFD at issuance. Used for regulatory filing, pharmacy dispensing, and audit trail purposes.. Valid values are `^RX-[0-9]{4}-[0-9]{6}$`',
    `prescription_status` STRING COMMENT 'Current lifecycle state of the veterinary prescription. Active indicates the prescription is valid and may be dispensed; expired indicates the expiration date has passed; cancelled indicates the prescribing veterinarian voided the order; filled indicates the full authorized quantity has been dispensed.. Valid values are `active|expired|cancelled|filled|partially_filled|pending`',
    `prescription_type` STRING COMMENT 'Classification of the prescription by regulatory category. VFD (Veterinary Feed Directive) applies to medicated feed products; prescription_drug covers legend drugs requiring a valid VCPR; OTC_extra_label covers over-the-counter drugs used in an extra-label manner; compounded covers compounded preparations. [ENUM-REF-CANDIDATE: VFD|prescription_drug|OTC_extra_label|compounded — promote to reference product]. Valid values are `VFD|prescription_drug|OTC_extra_label|compounded`',
    `production_class` STRING COMMENT 'The production class or use category of the animals covered by the prescription (e.g., beef cattle, dairy cattle, broiler, layer). Determines applicable withdrawal periods and regulatory requirements. [ENUM-REF-CANDIDATE: beef_cattle|dairy_cattle|swine_market|swine_breeding|broiler|layer|turkey|sheep|goat|other — promote to reference product]',
    `quantity_authorized` DECIMAL(18,2) COMMENT 'The total quantity of drug or medicated feed product authorized under this prescription (e.g., total grams, total pounds of medicated feed, total vials). Controls dispensing limits and prevents over-use.',
    `quantity_dispensed` DECIMAL(18,2) COMMENT 'The cumulative quantity of drug or medicated feed product actually dispensed against this prescription to date. Used to track partial fills and ensure authorized quantity is not exceeded.',
    `quantity_unit` STRING COMMENT 'The unit of measure for the authorized quantity (e.g., lbs of medicated feed, mL of injectable solution, number of vials). Required for dispensing accuracy and inventory reconciliation. [ENUM-REF-CANDIDATE: lbs|kg|g|tons|mL|vials|tablets|oz — 8 candidates stripped; promote to reference product]',
    `route_of_administration` STRING COMMENT 'The method by which the drug is to be administered to the animal (e.g., oral via medicated feed, intramuscular injection, subcutaneous injection). Required for proper drug use and withdrawal period determination. [ENUM-REF-CANDIDATE: oral|injectable_IM|injectable_IV|injectable_SQ|topical|intramammary|intrauterine — 7 candidates stripped; promote to reference product]',
    `special_instructions` STRING COMMENT 'Free-text field for any additional veterinarian instructions, warnings, or conditions associated with the prescription (e.g., do not use in animals producing milk for human consumption, refrigerate after opening). Captures label-specific or VCPR-specific guidance.',
    `treatment_duration_days` STRING COMMENT 'The number of days the prescribed drug treatment is to be administered. Used to calculate total drug quantity needed, withdrawal period start date, and antibiotic use days for stewardship reporting.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this veterinary prescription record was last modified. Supports audit trail requirements and change tracking for regulatory compliance.',
    `vcpr_reference` STRING COMMENT 'The reference number or identifier for the established Veterinarian-Client-Patient Relationship (VCPR) under which this prescription was issued. A valid VCPR is a legal prerequisite for issuing any veterinary prescription or VFD under FDA regulations.',
    `vfd_distributor_name` STRING COMMENT 'The name of the licensed feed manufacturer or distributor authorized to produce and supply the medicated feed under this VFD. Required on VFD documents per FDA regulation for medicated feed traceability.',
    `withdrawal_end_date` DATE COMMENT 'The calculated calendar date on which the withdrawal period ends and the animal or animal products are cleared for harvest or sale. Derived from last treatment date plus withdrawal_period_days; stored for operational scheduling and FSIS compliance verification.',
    `withdrawal_period_days` STRING COMMENT 'The mandatory Pre-Harvest Interval (PHI) — the number of days that must elapse after the last drug administration before the animal or animal products (meat, milk, eggs) may enter the food supply. Critical for FSIS food safety compliance and MRL (Maximum Residue Limit) adherence.',
    CONSTRAINT pk_veterinary_prescription PRIMARY KEY(`veterinary_prescription_id`)
) COMMENT 'Master record for veterinary prescriptions and Veterinary Feed Directives (VFDs) issued by a licensed veterinarian for use on the operation. Captures prescription date, issuing veterinarian (DVM license number), drug or medicated feed product, approved species and indication, dosage instructions, withdrawal period, quantity authorized, expiration date, VCPR (Veterinarian-Client-Patient Relationship) reference, and regulatory filing status. Required for FDA VFD compliance and FSIS antibiotic stewardship documentation.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`livestock`.`animal_transaction` (
    `animal_transaction_id` BIGINT COMMENT 'Unique surrogate identifier for each livestock commercial transfer record (purchase or sale). Primary key for the animal_transaction data product in the Silver Layer lakehouse.',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Livestock sales/purchase transactions are commercial events with a customer counterparty (buyer or seller). Linking to customer.account enables accounts receivable, sales reporting, COOL compliance tr',
    `invoice_id` BIGINT COMMENT 'Foreign key linking to invoice.invoice. Business justification: Livestock sale transactions generate AR invoices to buyers. The livestock sale invoicing process requires linking each animal_transaction to its billing document. Agriculture domain experts expect eve',
    `billing_account_id` BIGINT COMMENT 'Foreign key linking to invoice.billing_account. Business justification: Each livestock sale transaction is billed to a buyers AR billing account for credit management and collections. animal_transaction.counterparty_name is denormalized; a proper FK to billing_account en',
    `broker_id` BIGINT COMMENT 'Foreign key linking to sales.broker. Business justification: Livestock auctions and direct packer sales routinely involve licensed livestock commission agents/brokers. USDA Packers and Stockyards Act requires tracking broker involvement in livestock transaction',
    `certification_record_id` BIGINT COMMENT 'Foreign key linking to customer.certification_record. Business justification: Organic and GAP-certified livestock sales require verifying the buyers active certification at point of transaction. Ag compliance auditors and organic program managers expect the sale record to refe',
    `contact_id` BIGINT COMMENT 'Foreign key linking to customer.contact. Business justification: Livestock sales transactions involve a specific buyer representative (procurement manager, buyer agent) who negotiates terms and signs off. CRM reporting, contract management, and post-sale follow-up ',
    `certificate_of_analysis_id` BIGINT COMMENT 'Foreign key linking to quality.certificate_of_analysis. Business justification: Animal sales for export and interstate commerce require COAs documenting residue-free status, disease testing, and health compliance. Buyers and regulatory agencies require COAs linked to purchase tra',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: Livestock buy/sell transactions are commodity trades (feeder cattle, market hogs, broilers) with exchange market pricing benchmarks, HS tariff codes for international transactions, and USDA commodity ',
    `price_basis_id` BIGINT COMMENT 'Foreign key linking to invoice.price_basis. Business justification: Livestock are priced on a per-cwt basis with futures-based pricing. Linking animal_transaction to price_basis enables basis tracking for livestock forward contracts and futures-based pricing — a real ',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: Animal purchase and sale transactions are legal-entity-level revenue/expense events requiring company code for statutory financial statements, intercompany reconciliation, and tax reporting. Multi-ent',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Animal purchase and sale transactions must be posted to cost centers for livestock inventory cost tracking and buy/sell margin reporting. Cost center assignment on animal_transaction supports direct c',
    `delivery_location_id` BIGINT COMMENT 'Foreign key linking to customer.delivery_location. Business justification: Livestock transactions require a specific customer receiving/delivery location for logistics coordination, appointment scheduling, COOL documentation, and biosecurity zone compliance. A livestock sale',
    `delivery_order_id` BIGINT COMMENT 'Foreign key linking to sales.delivery_order. Business justification: Animal buy/sell transactions result in delivery orders for physical transfer. Linking transaction to delivery_order enables end-to-end traceability from financial transaction to physical delivery, sup',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Livestock buy/sell transactions require an accountable employee (lot manager, buyer, or sales representative) for audit trails, commission tracking, and regulatory compliance (brand inspection, COOL d',
    `facility_id` BIGINT COMMENT 'USDA APHIS-assigned Premises Identification Number (PIN) of the counterparty: the vendor premises for purchase transactions or the buyer premises for sale transactions. Core traceability identifier required for APHIS animal movement reporting and COOL chain-of-custody documentation.',
    `finance_ap_invoice_id` BIGINT COMMENT 'Foreign key linking to finance.finance_ap_invoice. Business justification: Animal purchases generate AP invoices that must be matched to the operational animal_transaction record for three-way matching (PO, receipt, invoice). This link supports livestock procurement reconcil',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Animal buy/sell transactions require GL account mapping (livestock inventory, cost of sales, gain/loss on sale) for GAAP financial statement preparation. Livestock accountants need this link to automa',
    `herd_id` BIGINT COMMENT 'Foreign key linking to livestock.herd. Business justification: animal_transaction records livestock purchase and sale events. Every transaction involves animals from a specific herd — the herd context is essential for traceability, COOL documentation, and regulat',
    `lot_trace_id` BIGINT COMMENT 'Foreign key linking to supply.lot_trace. Business justification: USDA COOL (Country of Origin Labeling) and FSMA traceability require linking buy/sell transactions to lot trace records for origin verification and recall scope determination. animal_transaction has n',
    `pen_location_id` BIGINT COMMENT 'Identifier of the pen or lot assigned to receive and hold purchased animals upon arrival at the operations premises. Populated only for purchase transactions. Links to facility management records for biosecurity and animal welfare compliance.',
    `procurement_goods_receipt_id` BIGINT COMMENT 'Foreign key linking to procurement.procurement_goods_receipt. Business justification: Livestock purchase transactions require goods receipt matching for three-way match (PO/GR/invoice) and USDA/APHIS movement documentation. Linking animal_transaction to procurement_goods_receipt enable',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Animal buy/sell transactions are the primary revenue events in livestock trading operations. Profit center attribution on animal_transaction is required for livestock enterprise segment reporting, tra',
    `contract_id` BIGINT COMMENT 'Foreign key linking to sales.contract. Business justification: Feedlots sell cattle under forward contracts with packers months before closeout. Linking animal_transaction to the sales contract enables forward contract fulfillment tracking, basis settlement, and ',
    `order_id` BIGINT COMMENT 'Foreign key linking to sales.order. Business justification: Livestock sale transactions are executed against sales orders for revenue recognition, FSMA lot traceability, and accounts receivable. A livestock sales manager expects every animal_transaction to ref',
    `price_agreement_id` BIGINT COMMENT 'Foreign key linking to sales.price_agreement. Business justification: Livestock packer sales operate under negotiated price agreements (formula pricing, grid pricing, or cash market agreements). Linking animal_transaction to the governing price agreement enables price v',
    `settlement_statement_id` BIGINT COMMENT 'Foreign key linking to invoice.settlement_statement. Business justification: Livestock purchase/sale transactions are settled via producer or packer settlement statements. Linking animal_transaction to settlement_statement enables reconciliation of transaction proceeds against',
    `shipment_id` BIGINT COMMENT 'Foreign key linking to supply.shipment. Business justification: Animal purchase/sale transactions involve physical transport via supply chain shipments. Replacing denormalized bol_reference with shipment_id links the commercial transaction to logistics execution f',
    `vendor_contract_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor_contract. Business justification: Livestock purchase transactions are frequently executed under vendor supply contracts (e.g., feeder cattle supply agreements, custom feeding contracts). Linking animal_transaction to vendor_contract e',
    `weight_ticket_id` BIGINT COMMENT 'Foreign key linking to invoice.weight_ticket. Business justification: Livestock sale settlement is driven by scale weight tickets — price per cwt requires a certified weight ticket. animal_transaction.weight_ticket_number is a denormalized reference; a proper FK to invo',
    `antibiotic_withdrawal_clear_date` DATE COMMENT 'The date on or after which the animals are cleared from any antibiotic withdrawal period and are eligible for harvest or sale. Critical for FSIS food safety compliance and prevention of violative drug residues in meat products. Populated based on most recent treatment records.',
    `avg_weight_per_head_lbs` DECIMAL(18,2) COMMENT 'Average live weight per individual animal in pounds at the time of transfer. Derived operationally at point of transaction (scale ticket) and stored as a business fact. Supports performance benchmarking, feed efficiency analysis, and grading decisions.',
    `brand_inspection_cert_number` STRING COMMENT 'Certificate number issued by the state brand inspection authority verifying ownership of branded livestock at time of transfer. Required in brand law states (e.g., TX, CO, MT, WY) for cattle and horse transactions to establish legal title.',
    `breed` STRING COMMENT 'Breed designation of the animals in the transaction (e.g., Angus, Hereford, Duroc, Hampshire). Relevant for cost basis accounting, genetic program tracking, and premium pricing in sales contracts.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this animal transaction record was first created in the Silver Layer lakehouse. Supports audit trail, data lineage, and SLA monitoring for data ingestion pipelines from source systems (SAP S/4HANA, Granular Farm Management).',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for the transaction value (e.g., USD for US Dollar, CAD for Canadian Dollar, MXN for Mexican Peso). Supports multi-currency operations for cross-border livestock imports and exports.. Valid values are `^[A-Z]{3}$`',
    `grade_yield_basis` STRING COMMENT 'The pricing and grading basis applied to outbound sale transactions. Indicates whether the sale price is based on live weight, dressed weight, USDA yield grade, USDA quality grade, or a formula-based pricing arrangement. Populated only for sale transactions.. Valid values are `live|dressed|yield_grade|quality_grade|formula`',
    `head_count` STRING COMMENT 'Number of individual animals included in this transaction. Used for inventory reconciliation, cost-per-head calculations, and APHIS movement reporting. Combined with weight and price fields to derive per-unit economics.',
    `health_certificate_number` STRING COMMENT 'Official USDA APHIS Veterinary Services (VS) health certificate number issued by an accredited veterinarian certifying the health status of animals at time of movement. Required for interstate and international livestock shipments per 9 CFR Part 86.',
    `lot_number` STRING COMMENT 'Batch or lot tracking identifier assigned to the group of animals in this transaction for traceability purposes. Supports APHIS animal movement traceability, FSIS recall readiness, and COOL chain-of-custody documentation from farm to harvest.',
    `notes` STRING COMMENT 'Free-text field for additional operational notes, special conditions, or remarks associated with the livestock transaction. May include auction lot descriptions, special handling instructions, or negotiated contract terms not captured in structured fields.',
    `origin_country` STRING COMMENT 'Three-letter ISO 3166-1 alpha-3 country code of the country of origin for the animals. Required for COOL compliance, import permit processing, and APHIS international traceability. Populated for all transactions; defaults to USA for domestic transfers.. Valid values are `^[A-Z]{3}$`',
    `origin_state` STRING COMMENT 'Two-letter US state code of the origin premises from which the animals were shipped. Required for COOL (Country of Origin Labeling) chain-of-custody documentation and APHIS interstate movement reporting.. Valid values are `^[A-Z]{2}$`',
    `price_per_cwt` DECIMAL(18,2) COMMENT 'Purchase or sale price expressed per hundredweight (CWT = 100 lbs) in USD. Standard pricing basis for cattle and hog transactions in North American livestock markets. Populated when the transaction is priced on a weight basis.',
    `price_per_head` DECIMAL(18,2) COMMENT 'Purchase or sale price expressed on a per-head basis in USD. Populated when the transaction is priced per individual animal rather than per CWT. Mutually exclusive with price_per_cwt for a given transaction; one or both may be populated depending on transaction channel.',
    `purchase_order_number` STRING COMMENT 'SAP S/4HANA MM purchase order number associated with this livestock purchase transaction. Populated for inbound (purchase) transactions only. Enables three-way match (PO, goods receipt, invoice) in accounts payable processing.',
    `quarantine_period_days` STRING COMMENT 'Number of days the purchased animals must remain in quarantine isolation before integration into the main herd or flock. Populated only for purchase transactions where quarantine_required = True. Supports antibiotic withdrawal period tracking and biosecurity compliance.',
    `quarantine_required` BOOLEAN COMMENT 'Indicates whether the purchased animals are subject to a mandatory quarantine period upon arrival at the receiving premises. Applicable to purchase transactions only. Drives receiving pen assignment and health monitoring workflows.',
    `rfid_tag_range` STRING COMMENT 'Range or list of RFID electronic identification tag numbers (e.g., 840 USDA official ear tags) assigned to the animals in this transaction. Supports APHIS electronic animal identification traceability requirements and individual animal tracking.',
    `species` STRING COMMENT 'Biological species classification of the animals involved in the transaction (e.g., bovine for cattle, swine for hogs, ovine for sheep). Drives regulatory reporting requirements, withdrawal period tracking, and FSIS/APHIS compliance rules. [ENUM-REF-CANDIDATE: bovine|swine|ovine|caprine|equine|poultry|other — promote to reference product]',
    `total_transaction_value` DECIMAL(18,2) COMMENT 'Gross total monetary value of the livestock transfer in USD, representing the full purchase cost (for inbound) or gross sale revenue (for outbound). Used for cost basis accounting, revenue recognition, and enterprise profitability analysis in SAP S/4HANA FI/CO.',
    `total_weight_lbs` DECIMAL(18,2) COMMENT 'Aggregate live weight in pounds of all animals in the transaction at the time of transfer (purchase weight for inbound; sale weight for outbound). Used for CWT (hundredweight) pricing calculations, cost basis accounting, and yield analysis.',
    `transaction_channel` STRING COMMENT 'The commercial channel through which the livestock transfer was executed. Direct = farm-to-farm; Auction = physical livestock auction market; Video Auction = remote video-based auction (e.g., Superior Livestock); Formula = price tied to a market index or formula; Private Treaty = negotiated private sale.. Valid values are `direct|auction|video_auction|formula|private_treaty`',
    `transaction_date` DATE COMMENT 'The principal real-world business event date on which the livestock transfer (purchase or sale) was executed — i.e., the date of ownership transfer or market transaction. Distinct from transport or arrival dates.',
    `transaction_direction` STRING COMMENT 'Indicates whether this record represents an inbound livestock purchase (animals acquired from an external party) or an outbound livestock sale (animals transferred to an external buyer). Drives which conditional attributes are populated (e.g., quarantine period for purchases; grade/yield basis for sales).. Valid values are `purchase|sale`',
    `transaction_number` STRING COMMENT 'Externally-known business identifier for the livestock transfer event, typically sourced from SAP S/4HANA (purchase order number for inbound or sales order number for outbound) or the auction/market reference number. Used for cross-system reconciliation and counterparty communication.',
    `transaction_status` STRING COMMENT 'Current workflow state of the livestock transfer event. Tracks the lifecycle from initial draft through confirmation, transit, completion, or cancellation. Drives downstream accounting and traceability processes.. Valid values are `draft|confirmed|in_transit|completed|cancelled`',
    `transport_carrier_name` STRING COMMENT 'Name of the licensed livestock transport carrier responsible for moving the animals between premises. Required for APHIS traceability, FMCSA compliance, and freight cost allocation.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this animal transaction record in the Silver Layer lakehouse. Used for incremental data processing, change data capture (CDC), and audit trail compliance.',
    CONSTRAINT pk_animal_transaction PRIMARY KEY(`animal_transaction_id`)
) COMMENT 'Transactional record of all livestock transfer events — both purchases (inbound) and sales (outbound) — between the operation and external parties. Captures transaction date, transaction direction (purchase/sale), counterparty premises ID (vendor for purchases, buyer for sales), species, breed, head count, weight (purchase weight or sale weight), price per head or per CWT, total transaction value, transaction channel (direct, auction, video auction, formula), origin state/country, health certificate number, brand inspection certificate, import permit (if applicable for purchases), quarantine period required (for purchases), receiving pen assignment (for purchases), transport carrier, BOL reference, grade and yield basis (for sales), and COOL chain-of-custody documentation. Purchase-specific attributes (quarantine period, receiving pen, import permit) are populated only for purchase transactions. Sale-specific attributes (grade/yield basis, sale channel) are populated only for sale transactions. Serves as the consolidated SSOT for all livestock commercial transfers. Supports livestock cost basis accounting, revenue recognition, enterprise profitability analysis, COOL compliance, and APHIS traceability. Distinguished from procurement/sales domain records by being animal-specific with livestock traceability attributes (health certificates, brand inspections, premises IDs) that generic commercial transaction records do not carry.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`livestock`.`milk_production_record` (
    `milk_production_record_id` BIGINT COMMENT 'Unique surrogate identifier for each milk production record in the silver layer lakehouse. Primary key for this transactional entity. Entity role: TRANSACTION_HEADER — captures a discrete milking event or Dairy Herd Improvement Association (DHIA) test-day observation for an individual animal or group.',
    `animal_id` BIGINT COMMENT 'Reference to the individual dairy cow or animal record in the livestock animal master. Serves as the primary party reference linking milk yield to a specific animals lifecycle record. Supports DHIA enrollment and individual cow performance tracking.',
    `asset_id` BIGINT COMMENT 'Reference to the milking parlor, milking robot (automatic milking system), or milking unit where the event occurred. Supports parlor throughput analysis, equipment performance benchmarking (OEE), and robotic milking interval compliance tracking.',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: Milk is a traded commodity (fluid milk, cream, cheese milk) with USDA Federal Order pricing, MRL thresholds, and organic premium classifications. Linking milk_production_record to product.commodity en',
    `commodity_lot_id` BIGINT COMMENT 'Foreign key linking to inventory.commodity_lot. Business justification: Dairy quality management and FDA PMO compliance require linking each milk production record to the bulk tank commodity lot. Enables somatic cell count and antibiotic residue traceability per lot, supp',
    `contract_id` BIGINT COMMENT 'Foreign key linking to sales.contract. Business justification: Dairy operations sell milk under long-term supply contracts with processors or cooperatives. Linking milk production records to the governing sales contract enables contract volume tracking, milk chec',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Dairy enterprise P&L reporting requires milk production attributed to cost centers for milk revenue recognition and cost-per-hundredweight analysis. DHIA and farm management software universally link ',
    `crew_id` BIGINT COMMENT 'Foreign key linking to workforce.crew. Business justification: Milking parlor operations are crew-based. milk_production_record has no crew_id. The milking crew responsible for each session is tracked for labor cost allocation, food safety accountability (SCC iss',
    `delivery_order_id` BIGINT COMMENT 'Foreign key linking to sales.delivery_order. Business justification: Milk pickups by tanker trucks are executed as delivery orders. Linking milk production records to delivery orders enables traceability from production batch to delivery fulfillment, required for FSMA ',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Individual milker accountability is required in dairy operations for food safety traceability — somatic cell count anomalies and mastitis events are traced to specific milkers. No employee_id exists o',
    `herd_id` BIGINT COMMENT 'Reference to the herd or dairy enterprise group to which the animal belongs at the time of milking. Enables herd-level aggregation of milk production performance and supports enterprise benchmarking.',
    `lab_sample_id` BIGINT COMMENT 'Foreign key linking to quality.lab_sample. Business justification: DHIA test-day samples (dhia_test_day_flag) and bulk tank samples are formal lab samples. Linking milk_production_record to lab_sample supports milk quality traceability for PMO compliance, DHIA report',
    `lot_trace_id` BIGINT COMMENT 'Foreign key linking to supply.lot_trace. Business justification: Milk lot traceability from individual cow production records to bulk tank to processor shipment is required by PMO (Pasteurized Milk Ordinance) and FSMA. Linking milk_production_record to lot_trace en',
    `nonconformance_id` BIGINT COMMENT 'Foreign key linking to quality.nonconformance. Business justification: Abnormal milk (is_abnormal_milk), somatic cell count exceedances, and diverted milk (divert_reason) trigger nonconformance records under PMO Grade A milk regulations. Dairy quality managers require th',
    `pen_location_id` BIGINT COMMENT 'Foreign key linking to livestock.pen_location. Business justification: milk_production_record captures milking events at specific parlor/pen locations. The parlor_id field exists as a BIGINT but has no FK assignment. Adding pen_location_id → livestock.pen_location.pen_lo',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Dairy enterprise revenue recognition requires milk production attributed to profit centers for dairy P&L reporting. Milk revenue is the primary income stream in dairy operations; profit center attribu',
    `order_id` BIGINT COMMENT 'Foreign key linking to sales.order. Business justification: Milk production batches are sold via sales orders to processors or cooperatives. Linking production records to sales orders enables volume reconciliation, revenue attribution per milking session, and ',
    `settlement_statement_id` BIGINT COMMENT 'Foreign key linking to invoice.settlement_statement. Business justification: Dairy cooperatives and processors issue monthly milk settlement statements based on production records. Linking milk_production_record to settlement_statement enables producer payment reconciliation, ',
    `shift_id` BIGINT COMMENT 'Foreign key linking to workforce.shift. Business justification: Dairy milking operations run on defined shifts (AM/PM/overnight). Linking milk records to shift enables shift-level yield reporting, labor cost per hundredweight by shift, and quality traceability (SC',
    `shipment_id` BIGINT COMMENT 'Foreign key linking to supply.shipment. Business justification: Milk is collected and shipped via bulk tanker shipments to processors. Linking milk_production_record to shipment enables farm-to-processor traceability for Grade A milk program compliance, somatic ce',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_location. Business justification: Milk collection operations require direct reference to the bulk tank or storage location where milk is deposited. Supports DHIA test-day reporting, PMO regulatory compliance, milk quality management b',
    `transport_unit_id` BIGINT COMMENT 'Foreign key linking to supply.transport_unit. Business justification: The milk tanker truck used for each pickup is tracked for FDA Grade A Pasteurized Milk Ordinance (PMO) compliance — tanker cleaning records, temperature logs, and somatic cell count investigations req',
    `conductivity_ms_cm` DECIMAL(18,2) COMMENT 'Electrical conductivity (EC) of the milk sample measured in millisiemens per centimeter (mS/cm). Elevated EC is an early indicator of subclinical mastitis and udder inflammation. Captured by inline sensors in automatic milking systems and modern parlor equipment.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this milk production record was first created in the silver layer lakehouse. Audit trail field supporting FSMA record-keeping requirements, SOX data governance controls, and DHIA data submission audit logs. Formatted as yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `data_source_system` STRING COMMENT 'Identifies the operational system of record from which this milk production record was ingested. Supports data lineage, silver layer reconciliation, and source system audit trails. Values align with the enterprises operational systems: Climate FieldView, Granular Farm Management, DHIA testing service, parlor management system, SAP S/4HANA, or manual entry. [ENUM-REF-CANDIDATE: CLIMATE_FIELDVIEW|GRANULAR|DHIA_SERVICE|PARLOR_MGMT|MANUAL|SAP_S4HANA|OTHER — 7 candidates stripped; promote to reference product]',
    `days_in_milk` STRING COMMENT 'Number of days elapsed since the animals most recent calving event at the time of this milking record. DIM (Days in Milk) is the primary axis for lactation curve modeling, peak milk prediction, and dry-off scheduling. Calculated from calving date but stored as a business-critical operational field.',
    `dhia_test_day_flag` BOOLEAN COMMENT 'Indicates whether this record is an official DHIA (Dairy Herd Improvement Association) test-day observation conducted by a certified DHIA supervisor. True = official DHIA test-day; False = routine parlor or non-official record. Determines eligibility for DHIA genetic evaluation and official production records.',
    `divert_reason` STRING COMMENT 'Reason code for diverting milk from the bulk tank when is_abnormal_milk is True. COLOSTRUM: first-milking colostrum; ANTIBIOTIC_WITHDRAWAL: animal within withdrawal period (PHI — Pre-Harvest Interval); MASTITIS: clinical mastitis; BLOOD_TINGED: visible blood contamination; DRUG_TREATMENT: other veterinary drug treatment; NONE: not diverted. Supports antibiotic residue compliance and FSIS regulatory reporting.. Valid values are `COLOSTRUM|ANTIBIOTIC_WITHDRAWAL|MASTITIS|BLOOD_TINGED|DRUG_TREATMENT|NONE`',
    `fat_pct` DECIMAL(18,2) COMMENT 'Percentage of butterfat content in the milk sample, measured via DHIA test-day analysis or inline sensor. Used for component-based milk pricing (fat premium/deduction), breed performance benchmarking, and nutritional ration adjustment. Regulatory threshold compliance per FDA Grade A Pasteurized Milk Ordinance (PMO).',
    `fat_yield_kg` DECIMAL(18,2) COMMENT 'Absolute quantity of butterfat produced in this milking event, calculated as milk_yield_kg × fat_pct / 100. Stored as a business field for DHIA component reporting, Federal Milk Marketing Order (FMMO) component pricing, and dairy enterprise financial reconciliation.',
    `is_abnormal_milk` BOOLEAN COMMENT 'Indicates whether the milk from this event was classified as abnormal (e.g., colostrum, mastitic milk, antibiotic-treated milk, blood-tinged milk) and therefore diverted from the bulk tank. True = abnormal/diverted; False = normal saleable milk. Critical for milk quality compliance and antibiotic residue tracking under FSIS and FDA PMO.',
    `lactation_number` STRING COMMENT 'Sequential count of the animals completed and current lactations (parity). First-calf heifers are parity 1. Used for stratified performance benchmarking, culling decision support, and genetic evaluation. Aligns with parity_number in the animal master record.',
    `lactose_pct` DECIMAL(18,2) COMMENT 'Percentage of lactose in the milk sample. Elevated lactose deviation can indicate early-stage mastitis or metabolic disorders. Used in conjunction with SCC and MUN for udder health monitoring and milk quality compliance.',
    `linear_score` DECIMAL(18,2) COMMENT 'Logarithmic transformation of somatic cell count expressed on a 0–9 linear scale, as defined by DHIA. Provides a normalized, statistically stable measure of udder health for genetic evaluation, herd benchmarking, and DHIA enrollment reporting.',
    `milk_temperature_c` DECIMAL(18,2) COMMENT 'Temperature of the milk at the point of collection, expressed in degrees Celsius. Used for milk quality compliance (FDA PMO requires rapid cooling to ≤10°C within 4 hours of milking), cold chain monitoring, and detection of fever-related health events in the animal.',
    `milk_yield_kg` DECIMAL(18,2) COMMENT 'Volume of milk produced by the animal during this milking event, expressed in kilograms. Primary quantitative outcome of the milking transaction. Used for lactation curve modeling, DHIA test-day reporting, and dairy enterprise revenue estimation.',
    `milk_yield_lbs` DECIMAL(18,2) COMMENT 'Volume of milk produced during this milking event expressed in pounds (lbs). Retained alongside kg for compatibility with USDA NASS reporting, DHIA test-day records, and domestic dairy market pricing conventions (hundredweight/CWT basis).',
    `milking_date` DATE COMMENT 'Calendar date on which the milking event or DHIA test-day observation occurred. Principal business event date used for daily, monthly, and lactation-period reporting. Formatted as yyyy-MM-dd per model conventions.',
    `milking_duration_sec` STRING COMMENT 'Total elapsed time in seconds for the milking event from unit attachment to detachment. Used for parlor throughput optimization, teat condition monitoring, and robotic milking system performance analysis (OEE — Overall Equipment Effectiveness).',
    `milking_event_number` STRING COMMENT 'Externally-known business identifier for this milking event or test-day record, typically assigned by the parlor management system or DHIA testing service (e.g., DHIA test-day report number, parlor event ID). Used for cross-system reconciliation with source systems such as Climate FieldView or Granular Farm Management.',
    `milking_session` STRING COMMENT 'Identifies the milking session within the day: AM (morning), PM (evening), MID (midday for 3x programs), or labeled 3X variants for three-times-daily milking schedules. Critical for normalizing yield comparisons across different milking frequency programs. [ENUM-REF-CANDIDATE: AM|PM|MID|3X_AM|3X_PM|3X_MID — promote to reference product]. Valid values are `AM|PM|MID|3X_AM|3X_PM|3X_MID`',
    `milking_timestamp` TIMESTAMP COMMENT 'Precise date and time when the milking event was recorded, including timezone offset. Enables intra-day sequencing of milking sessions, parlor throughput analysis, and robotic milking interval tracking. Formatted as yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `mun_mg_dl` DECIMAL(18,2) COMMENT 'Concentration of urea nitrogen in milk expressed in milligrams per deciliter (mg/dL). MUN (Milk Urea Nitrogen) is an indicator of dietary protein-energy balance and rumen fermentation efficiency. Used for ration formulation adjustments and environmental nitrogen management compliance.',
    `peak_flow_rate_kg_min` DECIMAL(18,2) COMMENT 'Maximum milk flow rate recorded during the milking event, expressed in kilograms per minute. Indicator of teat canal health, milking unit vacuum performance, and potential mastitis risk. Captured by parlor management systems and robotic milking units.',
    `protein_pct` DECIMAL(18,2) COMMENT 'Percentage of true protein content in the milk sample. Used for component-based milk pricing (protein premium/deduction), cheese yield estimation, and feed ration optimization. Key performance indicator for dairy enterprise profitability.',
    `protein_yield_kg` DECIMAL(18,2) COMMENT 'Absolute quantity of true protein produced in this milking event, calculated as milk_yield_kg × protein_pct / 100. Stored for DHIA component reporting, FMMO protein pricing, and cheese yield estimation in downstream processing.',
    `record_status` STRING COMMENT 'Lifecycle status of this milk production record. ACTIVE: valid and in use; VOIDED: invalidated due to error or equipment malfunction; CORRECTED: superseded by a corrected record; PENDING_REVIEW: flagged for quality review; DHIA_SUBMITTED: officially submitted to DHIA testing service. Supports data governance and audit trail requirements.. Valid values are `ACTIVE|VOIDED|CORRECTED|PENDING_REVIEW|DHIA_SUBMITTED`',
    `record_type` STRING COMMENT 'Classification of the source and method of this milk production record. DHIA_TEST_DAY: official DHIA supervisor test; DAILY_PARLOR: routine parlor management system record; ROBOT_AMS: automatic milking system (robotic) record; MANUAL_ENTRY: hand-entered observation; ESTIMATED: interpolated or estimated value. Drives data quality weighting in analytics and DHIA enrollment eligibility.. Valid values are `DHIA_TEST_DAY|DAILY_PARLOR|ROBOT_AMS|MANUAL_ENTRY|ESTIMATED`',
    `somatic_cell_count` BIGINT COMMENT 'Number of somatic cells per milliliter of milk (cells/mL). Primary indicator of udder health and mastitis status. Regulatory threshold: FDA PMO Grade A standard ≤750,000 cells/mL; EU standard ≤400,000 cells/mL. Directly impacts milk quality premiums/penalties and bulk tank SCC compliance.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this milk production record was last modified in the silver layer lakehouse. Supports change data capture (CDC), correction audit trails, and data governance compliance. Formatted as yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `withdrawal_clear_date` DATE COMMENT 'Date on which the animals antibiotic or drug withdrawal period expires and milk is eligible to re-enter the bulk tank. Populated when divert_reason is ANTIBIOTIC_WITHDRAWAL or DRUG_TREATMENT. Critical for FSIS antibiotic residue compliance and FDA PMO Grade A milk eligibility. Aligns with withdrawal_clear_date in the animal master.',
    CONSTRAINT pk_milk_production_record PRIMARY KEY(`milk_production_record_id`)
) COMMENT 'Transactional record of milk yield measurements for individual dairy cows or groups, captured at each milking event or DHIA test-day. Captures milking date, animal ID, milking session (AM/PM/3x), milk yield (lbs/kg), milk fat percentage, milk protein percentage, somatic cell count (SCC), linear score, milk urea nitrogen (MUN), days in milk (DIM), lactation number, and milking parlor/robot ID. Supports DHIA enrollment, milk quality compliance, and dairy enterprise performance management.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`livestock`.`health_protocol` (
    `health_protocol_id` BIGINT COMMENT 'Unique system-generated identifier for the herd health protocol record. Primary key for the health_protocol data product.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Health protocols define treatment programs with standard costs (drug, labor) that are pre-budgeted to cost centers. Linking protocols to cost centers enables protocol-level budget planning and actual-',
    `employee_id` BIGINT COMMENT 'Reference to the licensed veterinarian who authored and approved this health protocol. Required for VCPR (Veterinarian-Client-Patient Relationship) compliance under FDA CVM and APHIS accreditation requirements.',
    `facility_id` BIGINT COMMENT 'Foreign key linking to supply.facility. Business justification: Health protocols are scoped to specific facilities for biosecurity zone compliance and USDA/FDA regulatory audits. health_protocol.facility_scope is a denormalized text reference; a proper FK to facil',
    `input_catalog_id` BIGINT COMMENT 'Foreign key linking to procurement.input_catalog. Business justification: Health protocols specify approved drugs and biologicals that must be in the procurement input catalog. Linking health_protocol to input_catalog enforces approved product list management, ensures proto',
    `material_master_id` BIGINT COMMENT 'Foreign key linking to inventory.material_master. Business justification: Health protocol formulary management requires linking each protocol to the specific drug/vaccine material_master. Enables withdrawal period calculation, VFD compliance verification, antibiotic steward',
    `administration_route` STRING COMMENT 'The prescribed route of drug administration as specified on the FDA-approved label (e.g., subcutaneous injection, intramuscular injection, oral drench, pour-on). Deviations from the approved route constitute extra-label drug use (ELDU) requiring a valid VCPR. [ENUM-REF-CANDIDATE: subcutaneous|intramuscular|intravenous|oral|intranasal|topical|pour_on — 7 candidates stripped; promote to reference product]',
    `antibiotic_class` STRING COMMENT 'Pharmacological class of the antibiotic used in this protocol (e.g., macrolide, tetracycline, beta-lactam). Required for antibiotic stewardship reporting, resistance monitoring, and FDA GFI #213 medically important antimicrobial tracking. Null or not_applicable for non-antibiotic protocols. [ENUM-REF-CANDIDATE: macrolide|tetracycline|beta_lactam|fluoroquinolone|sulfonamide|aminoglycoside|not_applicable — 7 candidates stripped; promote to reference product]',
    `approved_date` DATE COMMENT 'Date on which the protocol was formally approved and signed by the responsible veterinarian. Establishes the VCPR-compliant authorization date for regulatory audit purposes under APHIS, FSIS, and FSMA requirements.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this health protocol record was first created in the system. Supports data lineage, audit trail, and SOX/FSMA record-keeping compliance requirements.',
    `dosage_amount` DECIMAL(18,2) COMMENT 'The prescribed dose quantity of the drug product per unit of animal body weight or per head as specified in the protocol. Used in conjunction with dosage_uom to calculate total drug volume for treatment events.',
    `dosage_uom` STRING COMMENT 'Unit of measure for the prescribed dosage amount (e.g., ml per hundredweight (CWT), ml per head, mg per kg body weight). Ensures accurate dose calculation and label compliance per FDA NADA/ANADA approved labeling.. Valid values are `ml_per_cwt|ml_per_head|mg_per_kg|ml_per_kg|cc_per_head`',
    `effective_date` DATE COMMENT 'Date from which this health protocol becomes operationally effective and may be applied to animals. May differ from approved_date if a transition period is required. Drives protocol applicability checks in treatment and vaccination records.',
    `expiry_date` DATE COMMENT 'Date on which this health protocol expires and must be reviewed and re-approved by the veterinarian. Null for protocols with no defined expiry. Supports VCPR annual review requirements and GLOBALG.A.P. protocol currency compliance.',
    `injection_site` STRING COMMENT 'Anatomical location for injection administration as specified by BQA guidelines to minimize carcass damage and maximize meat quality. Neck injection is the BQA-preferred site for cattle. Not applicable for non-injectable routes.. Valid values are `neck|behind_shoulder|rump|not_applicable`',
    `is_antibiotic_protocol` BOOLEAN COMMENT 'Indicates whether this protocol involves the use of medically important antimicrobials (antibiotics). True triggers mandatory antibiotic stewardship tracking, VFD requirements where applicable, and antibiotic-free program compliance checks per FDA GFI #213 and GFI #209.',
    `is_extra_label_use` BOOLEAN COMMENT 'Indicates whether this protocol involves extra-label drug use (ELDU) — use of an FDA-approved drug in a manner not specified on the approved label (different species, dose, route, or indication). ELDU requires a valid VCPR and veterinarian authorization per 21 CFR Part 530.',
    `is_prescription_required` BOOLEAN COMMENT 'Indicates whether the drug product in this protocol requires a valid veterinary prescription (Rx) for procurement and use. Drives procurement compliance checks in SAP MM and vendor management workflows.',
    `is_vfd_required` BOOLEAN COMMENT 'Indicates whether a Veterinary Feed Directive (VFD) is required for the drug product used in this protocol. True for medically important antimicrobials administered via feed or water under 21 CFR Part 558. Drives VFD documentation workflow in SAP QM.',
    `max_treatments_allowed` STRING COMMENT 'Maximum number of times this protocol may be applied to a single animal within a production cycle before escalation to a veterinarian or chronic/realizer designation. Supports antibiotic stewardship and chronic animal management decisions.',
    `milk_withdrawal_days` STRING COMMENT 'Mandatory milk discard period in days following drug administration for dairy animals, as specified on the FDA-approved label. Applicable only to dairy production classes; null for beef/non-dairy protocols. Required for Grade A Pasteurized Milk Ordinance (PMO) compliance.',
    `phi_days` STRING COMMENT 'Pre-Harvest Interval (PHI) in days — the minimum time that must elapse between the last application of a pesticide or parasiticide and animal harvest. Distinct from drug withdrawal period; applies specifically to EPA-registered pesticide products used in parasite control protocols.',
    `production_class` STRING COMMENT 'The specific production class or stage within the species for which this protocol applies (e.g., feedlot cattle, cow-calf pairs, broiler flocks). Ensures protocol applicability is correctly scoped to avoid misapplication across production stages. [ENUM-REF-CANDIDATE: cow_calf|stocker|feedlot|dairy|breeding|farrow_to_finish|broiler|layer|pullet|gilt|sow|boar — promote to reference product]',
    `protocol_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying the health protocol, used for cross-referencing in treatment records, vaccination logs, and veterinary documentation. Serves as the business identifier referenced in FMIS and SAP QM.. Valid values are `^[A-Z0-9-]{3,20}$`',
    `protocol_name` STRING COMMENT 'Descriptive human-readable name of the health protocol (e.g., Arrival Processing BRD Metaphylaxis, Spring Vaccination Schedule - Cow-Calf). Used in reporting, treatment records, and veterinary documentation.',
    `protocol_notes` STRING COMMENT 'Free-text field for veterinarian or protocol administrator notes, special instructions, contraindications, or clinical observations relevant to protocol application. Supports clinical decision-making and audit documentation.',
    `protocol_status` STRING COMMENT 'Current lifecycle state of the health protocol. Draft indicates under development; active indicates approved and in use; suspended indicates temporarily halted pending review; retired indicates no longer in use; pending_review indicates awaiting veterinarian re-approval.. Valid values are `draft|active|suspended|retired|pending_review`',
    `protocol_type` STRING COMMENT 'Classification of the protocol by its operational purpose. Arrival processing covers new animal intake procedures; metaphylaxis covers mass antibiotic treatment at arrival; vaccination_schedule covers routine immunization programs; parasite_control covers deworming and ectoparasite management; treatment_guideline covers individual animal therapy; biosecurity covers disease prevention procedures.. Valid values are `arrival_processing|metaphylaxis|vaccination_schedule|parasite_control|treatment_guideline|biosecurity`',
    `rei_hours` STRING COMMENT 'Restricted Entry Interval (REI) in hours specifying the minimum time workers must wait before re-entering treated areas or handling treated animals, as required by EPA pesticide label regulations. Applicable primarily to parasite control and topical pesticide protocols.',
    `retreatment_interval_days` STRING COMMENT 'Minimum number of days that must elapse between successive applications of this protocol to the same animal. Prevents over-treatment, supports antibiotic stewardship, and ensures withdrawal period compliance between treatments.',
    `review_frequency_days` STRING COMMENT 'Scheduled review interval in days for this protocol (e.g., 365 for annual review). Drives automated review reminders and protocol currency compliance tracking. Supports VCPR maintenance requirements and GLOBALG.A.P. audit readiness.',
    `sop_reference` STRING COMMENT 'Reference code or document identifier for the Standard Operating Procedure (SOP) associated with this health protocol. Links to the detailed procedural documentation in the document management system for training and audit purposes.',
    `target_species` STRING COMMENT 'The animal species for which this health protocol is designed and approved. Drives species-specific drug dosage calculations, withdrawal period requirements, and APHIS/FSIS regulatory compliance checks. [ENUM-REF-CANDIDATE: bovine|swine|poultry|ovine|caprine|equine|mixed — 7 candidates stripped; promote to reference product]',
    `trigger_morbidity_rate_pct` DECIMAL(18,2) COMMENT 'Pen or herd morbidity rate percentage at or above which this metaphylaxis or mass treatment protocol is triggered (e.g., 10% pen pull rate triggers mass treatment). Null if trigger_type is not morbidity_rate. Supports evidence-based metaphylaxis decision-making.',
    `trigger_temperature_threshold_c` DECIMAL(18,2) COMMENT 'Rectal temperature threshold in degrees Celsius at or above which this protocol is triggered for an individual animal (e.g., 39.7°C for BRD treatment initiation). Null if trigger_type is not temperature_threshold. Used by pen riders and veterinary staff to standardize pull decisions.',
    `trigger_type` STRING COMMENT 'The type of trigger criterion that initiates application of this protocol. Temperature threshold triggers are based on rectal temperature readings; morbidity_rate triggers are based on pen pull rates; arrival_processing triggers apply automatically at animal intake; scheduled triggers follow a calendar-based vaccination schedule.. Valid values are `temperature_threshold|morbidity_rate|arrival_processing|scheduled|clinical_sign|pen_pull_rate`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this health protocol record was last modified. Supports change tracking, audit trail, and regulatory record-keeping requirements under FSMA and GLOBALG.A.P.',
    `withdrawal_period_days` STRING COMMENT 'The mandatory withdrawal period in days from last drug administration to slaughter or milk harvest, as specified on the FDA-approved label. Critical for FSIS residue compliance, MRL adherence, and antibiotic-free program certification. Drives the withdrawal_clear_date calculation on the animal record.',
    CONSTRAINT pk_health_protocol PRIMARY KEY(`health_protocol_id`)
) COMMENT 'Master record defining standardized herd health protocols and treatment guidelines established by the operations veterinarian. Captures protocol name, target species and production class, protocol type (arrival processing, metaphylaxis, vaccination schedule, parasite control), drug products authorized, dosages, administration routes, withdrawal periods, trigger criteria (temperature threshold, morbidity rate), and veterinarian approval date. Serves as the SSOT for standardized health management procedures referenced by treatment and vaccination records.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`livestock`.`ration_ingredient` (
    `ration_ingredient_id` BIGINT COMMENT 'Primary key for the ration_ingredient association',
    `feed_ration_id` BIGINT COMMENT 'Foreign key linking to the feed ration formulation that contains this ingredient',
    `input_catalog_id` BIGINT COMMENT 'Foreign key linking to procurement.input_catalog. Business justification: Feed ingredients must be in the approved procurement input catalog with GMO status, organic certification, and regulatory compliance data. Linking ration_ingredient to input_catalog enforces approved ',
    `lab_sample_id` BIGINT COMMENT 'Foreign key linking to quality.lab_sample. Business justification: Individual feed ingredients (corn, soybean meal, distillers grains) are sampled and tested for nutritional content, mycotoxins, and contaminants before inclusion in rations. FDA FSMA Preventive Contro',
    `material_master_id` BIGINT COMMENT 'Foreign key linking to the material master record representing the feed ingredient',
    `vendor_contract_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor_contract. Business justification: Each feed ration ingredient is sourced under a vendor supply contract with price and volume commitments. Linking ration_ingredient to vendor_contract enables contract-based ration cost modeling, suppl',
    `cost_per_unit` DECIMAL(18,2) COMMENT 'The cost of this ingredient per unit of measure at the time this ration formulation was created or last revised. Captured at the ration-ingredient level to support feed cost allocation and historical cost tracking independent of current material_master standard_price.',
    `dry_matter_basis_flag` BOOLEAN COMMENT 'Indicates whether the inclusion_rate_pct for this ingredient in this ration is expressed on a dry matter (DM) basis (true) or as-fed basis (false). The same ingredient may be expressed differently across rations depending on nutritionist preference.',
    `inclusion_rate_pct` DECIMAL(18,2) COMMENT 'The percentage of this ingredient in the ration, expressed as a proportion of the total ration weight. Belongs to the ration-ingredient combination — the same ingredient may have different inclusion rates across different rations.',
    `ingredient_list` STRING COMMENT 'Structured text or JSON-serialized list of feed ingredients included in the ration formulation, with inclusion rates on both as-fed and dry matter basis (e.g., corn silage 45%, distillers grains 15%, hay 20%). Applicable to formulation records. Supports feed cost analysis and ingredient traceability. [Moved from feed_ration: The ingredient_list STRING/JSON blob on feed_ration is a denormalized encoding of the ration-ingredient M:N relationship. Once the ration_ingredient association product is in place, this attribute becomes redundant and should be deprecated. The structured ration_ingredient records replace it with properly typed, queryable, and auditable individual ingredient rows.]',
    `ingredient_sequence` STRING COMMENT 'The order in which this ingredient is added to the TMR mixer or batch during ration preparation. Critical for mixing quality and nutritional homogeneity. Belongs to the ration-ingredient combination, not to the ingredient or ration alone.',
    `quantity_per_batch_kg` DECIMAL(18,2) COMMENT 'The physical weight in kilograms of this ingredient required per batch mix of the ration. Derived from inclusion rate and batch size but stored explicitly for feed mill operations. Belongs to the ration-ingredient combination.',
    `substitution_allowed` BOOLEAN COMMENT 'Indicates whether this ingredient in this specific ration may be substituted with an alternative ingredient when the primary ingredient is unavailable. A ration-ingredient-level flag — the same ingredient may be substitutable in one ration but not in another.',
    CONSTRAINT pk_ration_ingredient PRIMARY KEY(`ration_ingredient_id`)
) COMMENT 'This association product represents the Ration Ingredient role between feed_ration and material_master. It captures the bill-of-materials composition of each feed ration formulation — specifically, which ingredients (material_master records) are included in a given ration, at what inclusion rate, in what quantity per batch, and at what cost. Each record links one feed_ration formulation to one material_master ingredient with attributes that exist only in the context of that specific ration-ingredient combination. Serves as the SSOT for ration composition, supporting NRC nutritional compliance calculations, feed cost allocation, and feed mill mixing operations.. Existence Justification: A feed ration formulation is composed of multiple feed ingredients (material_master records such as corn silage, soybean meal, mineral premix), and each ingredient appears across many different ration formulations. Nutritionists and feed mill operators actively manage this composition daily — creating, adjusting, and versioning ingredient inclusions with specific rates, quantities, and costs per ration-ingredient combination. This is a classic bill-of-materials / recipe composition relationship that the livestock feed industry universally recognizes as ration ingredients or feed formulation lines.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`livestock`.`breed` (
    `breed_id` BIGINT COMMENT 'Primary key for breed',
    `parent_breed_id` BIGINT COMMENT 'Self-referencing FK on breed (parent_breed_id)',
    `average_birth_weight_kg` DECIMAL(18,2) COMMENT 'Typical birth weight in kilograms for offspring of this breed, used for calving/farrowing management and health monitoring.',
    `average_daily_gain_kg` DECIMAL(18,2) COMMENT 'Expected daily weight gain in kilograms during the growth phase, used for performance benchmarking and feed efficiency calculations.',
    `average_litter_size` DECIMAL(18,2) COMMENT 'Expected number of offspring per birth event for the breed, used for production planning and facility capacity management.',
    `average_mature_weight_kg` DECIMAL(18,2) COMMENT 'Typical adult body weight in kilograms for the breed at maturity, used for feed planning and facility design.',
    `breed_category` STRING COMMENT 'Primary production purpose classification of the breed, indicating its intended agricultural use and economic function.',
    `breed_code` STRING COMMENT 'Standardized alphanumeric code uniquely identifying the breed across systems and external registries. Used for regulatory reporting and industry data exchange.',
    `breed_name` STRING COMMENT 'Official common name of the breed as recognized by breed associations and industry standards.',
    `breed_status` STRING COMMENT 'Current lifecycle status of the breed indicating its availability and conservation state within breeding programs.',
    `breeding_season` STRING COMMENT 'Natural or managed breeding cycle pattern for the breed, indicating optimal reproductive timing for breeding program management.',
    `carcass_yield_percentage` DECIMAL(18,2) COMMENT 'Expected dressed carcass weight as a percentage of live weight for meat breeds, used for harvest planning and economic valuation.',
    `climate_adaptability` STRING COMMENT 'Environmental climate conditions to which the breed is best suited, used for facility design and geographic placement decisions.',
    `coat_color_pattern` STRING COMMENT 'Characteristic coat color and pattern description for the breed, used for visual identification and breed verification.',
    `conservation_priority` STRING COMMENT 'Conservation status classification indicating the urgency of genetic preservation efforts for the breed.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this breed record was first created in the system, used for audit trail and data lineage tracking.',
    `crossbreeding_compatibility` STRING COMMENT 'Notes on breeds commonly crossed with this breed and expected hybrid vigor outcomes, used for breeding program design.',
    `disease_resistance_profile` STRING COMMENT 'Summary of known genetic resistance or susceptibility to common diseases, used for health management and breeding selection.',
    `effective_date` DATE COMMENT 'Date from which this breed record became active and available for use in breeding programs and animal registration.',
    `egg_production_potential_per_year` STRING COMMENT 'Average annual egg production count for poultry layer breeds, used for production forecasting and flock management. Null for non-poultry breeds.',
    `end_date` DATE COMMENT 'Date on which this breed record was retired or became inactive. Null for currently active breeds.',
    `feed_conversion_ratio` DECIMAL(18,2) COMMENT 'Average feed conversion efficiency expressed as kilograms of feed required per kilogram of weight gain, used for economic analysis and ration planning.',
    `genetic_marker_profile` STRING COMMENT 'Summary of key genetic markers or DNA characteristics used for breed verification and parentage validation in breeding programs.',
    `gestation_period_days` STRING COMMENT 'Average length of pregnancy in days for the breed, used for breeding program scheduling and calving/farrowing date estimation.',
    `is_certified_organic_eligible` BOOLEAN COMMENT 'Indicates whether the breed meets eligibility criteria for certified organic production programs.',
    `is_heritage_breed` BOOLEAN COMMENT 'Indicates whether the breed is classified as a heritage or traditional breed eligible for conservation programs and specialty marketing.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Date and time when this breed record was most recently updated, used for audit trail and change tracking.',
    `market_age_target_days` STRING COMMENT 'Typical age in days at which animals of this breed reach market readiness, used for production cycle planning and facility turnover scheduling.',
    `market_weight_target_kg` DECIMAL(18,2) COMMENT 'Optimal live weight in kilograms at which animals of this breed are typically marketed or harvested, used for production scheduling and economic planning.',
    `milk_production_potential_kg_per_year` DECIMAL(18,2) COMMENT 'Average annual milk yield in kilograms for dairy breeds, used for production forecasting and economic analysis. Null for non-dairy breeds.',
    `notes` STRING COMMENT 'Additional free-text notes or comments about the breed, including historical context, special considerations, or operational guidance.',
    `origin_country_code` STRING COMMENT 'Three-letter ISO country code representing the geographic origin or development location of the breed.',
    `physical_characteristics` STRING COMMENT 'Detailed description of distinguishing physical traits and conformation standards for the breed, used for breed verification and selection.',
    `registry_association_name` STRING COMMENT 'Name of the official breed registry or association that maintains pedigree records and breed standards for this breed.',
    `regulatory_restrictions` STRING COMMENT 'Any import/export restrictions, quarantine requirements, or regulatory limitations applicable to this breed, used for compliance and trade planning.',
    `scientific_name` STRING COMMENT 'Taxonomic scientific name of the breed, including genus and species classification.',
    `special_handling_requirements` STRING COMMENT 'Any unique care, housing, or management requirements specific to this breed, used for facility design and staff training.',
    `species_type` STRING COMMENT 'Primary species classification of the breed, categorizing the animal type for operational and regulatory purposes.',
    `temperament` STRING COMMENT 'Typical behavioral disposition of the breed, used for handler safety planning and animal welfare management.',
    CONSTRAINT pk_breed PRIMARY KEY(`breed_id`)
) COMMENT 'Master reference table for breed. Referenced by breed_id.';

